fn doctor(options: &CliOptions) -> ExitCode {
    let doctor_options = match DoctorOptions::parse(&options.args) {
        Ok(options) => options,
        Err(message) => {
            eprintln!("{message}");
            return ExitCode::from(2);
        }
    };
    let store_status = match open_store(&options.store_path) {
        Ok(store) => match store.schema_version() {
            Ok(version) => json!({
                "ok": true,
                "path": options.store_path.display().to_string(),
                "schema_version": version,
            }),
            Err(error) => json!({
                "ok": false,
                "path": options.store_path.display().to_string(),
                "error": store_error(error),
            }),
        },
        Err(message) => json!({
            "ok": false,
            "path": options.store_path.display().to_string(),
            "error": message,
        }),
    };
    let tools = doctor_tool_checks();
    let provider_capabilities = builtin_provider_capabilities();
    let provider_configs = doctor_provider_config_checks(
        &doctor_options.provider_config_paths,
        &provider_capabilities,
    );
    let provider_health_checks = if doctor_options.providers {
        doctor_provider_health_checks(&provider_capabilities, &tools)
    } else {
        Vec::new()
    };
    let provider_validation_evidence_recorded = if let Some(instance_id) = doctor_options
        .record_provider_evidence_instance_id
        .as_deref()
    {
        let store = match open_store_or_exit(options) {
            Ok(store) => store,
            Err(code) => return code,
        };
        match record_doctor_provider_validation_evidence(
            &store,
            instance_id,
            &provider_configs,
            &provider_capabilities,
        ) {
            Ok(count) => count,
            Err(error) => {
                return report_store_error("failed to record provider validation evidence", error)
            }
        }
    } else {
        0
    };
    if options.json {
        emit_json(json!({
            "stage": whipplescript_kernel::kernel_stage(),
            "store": store_status,
            "tools": tools.iter().map(tool_check_to_json).collect::<Vec<_>>(),
            "provider_capabilities": provider_capabilities
                .iter()
                .map(|capability| capability.to_json())
                .collect::<Vec<_>>(),
            "provider_config_checks": provider_configs
                .iter()
                .map(provider_config_check_to_json)
                .collect::<Vec<_>>(),
            "provider_health_checks": provider_health_checks
                .iter()
                .map(provider_health_check_to_json)
                .collect::<Vec<_>>(),
            "provider_validation_evidence_recorded": provider_validation_evidence_recorded,
        }))
    } else {
        println!("whip doctor: {}", whipplescript_kernel::kernel_stage());
        println!("store: {}", options.store_path.display());
        if store_status.get("ok").and_then(Value::as_bool) == Some(true) {
            if let Some(version) = store_status.get("schema_version").and_then(Value::as_i64) {
                println!("sqlite schema: {version}");
            }
        } else if let Some(error) = store_status.get("error").and_then(Value::as_str) {
            eprintln!("sqlite store check failed: {error}");
        }
        println!("tools:");
        for tool in tools {
            let status = if tool.available { "ok" } else { "missing" };
            let required = if tool.required {
                "required"
            } else {
                "optional"
            };
            println!(
                "  {:<16} {:<7} {} ({})",
                tool.id,
                status,
                tool.path.as_deref().unwrap_or(tool.command),
                required
            );
            if !tool.available {
                println!("    {}", tool.note);
            }
        }
        println!("provider capabilities:");
        for capability in provider_capabilities {
            println!(
                "  {:<8} {:<20} cancellation={}",
                capability.provider_kind.as_str(),
                capability.surface.as_str(),
                capability
                    .cancellation_depths
                    .iter()
                    .map(|depth| depth.as_str())
                    .collect::<Vec<_>>()
                    .join(",")
            );
        }
        if !provider_configs.is_empty() {
            println!("provider config checks:");
            for config in provider_configs {
                println!("  {}", config.path.display());
                for result in config.results {
                    println!(
                        "    {:<5} {:<32} {}",
                        result.status.as_str(),
                        result.code,
                        result.message
                    );
                }
            }
        }
        if !provider_health_checks.is_empty() {
            println!("provider health checks:");
            for check in provider_health_checks {
                println!(
                    "  {:<8} {:<20} {:<8} {}",
                    check.provider,
                    check.check,
                    check.status.as_str(),
                    check.message
                );
            }
        }
        if provider_validation_evidence_recorded > 0 {
            println!(
                "provider validation evidence recorded: {provider_validation_evidence_recorded}"
            );
        }
        ExitCode::SUCCESS
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct DoctorOptions {
    provider_config_paths: Vec<PathBuf>,
    record_provider_evidence_instance_id: Option<String>,
    providers: bool,
}

impl DoctorOptions {
    fn parse(args: &[String]) -> Result<Self, String> {
        let mut provider_config_paths = Vec::new();
        let mut record_provider_evidence_instance_id = None;
        let mut providers = false;
        let mut iter = args.iter();
        while let Some(arg) = iter.next() {
            match arg.as_str() {
                "--providers" => providers = true,
                "--provider-config" => {
                    let Some(path) = iter.next() else {
                        return Err("expected path after `--provider-config`".to_owned());
                    };
                    provider_config_paths.push(PathBuf::from(path));
                }
                "--record-provider-evidence" => {
                    let Some(instance_id) = iter.next() else {
                        return Err(
                            "expected instance id after `--record-provider-evidence`".to_owned()
                        );
                    };
                    record_provider_evidence_instance_id = Some(instance_id.clone());
                }
                other => {
                    return Err(format!(
                        "unknown doctor option `{other}`; expected --providers, --provider-config, or --record-provider-evidence"
                    ));
                }
            }
        }
        Ok(Self {
            provider_config_paths,
            record_provider_evidence_instance_id,
            providers,
        })
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct DoctorProviderConfigCheck {
    path: PathBuf,
    results: Vec<ProviderValidationResult>,
    bindings: Vec<DoctorProviderBindingCheck>,
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct DoctorProviderBindingCheck {
    config: ProviderBindingConfig,
    results: Vec<ProviderValidationResult>,
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct DoctorProviderHealthCheck {
    provider: String,
    surface: String,
    check: String,
    status: ProviderValidationStatus,
    message: String,
}

fn doctor_provider_health_checks(
    capabilities: &[ProviderCapability],
    tools: &[ToolCheck],
) -> Vec<DoctorProviderHealthCheck> {
    capabilities
        .iter()
        .filter(|capability| matches!(capability.provider_kind.as_str(), "codex" | "claude"))
        .flat_map(|capability| {
            let mut checks = Vec::new();
            let provider = capability.provider_kind.as_str().to_owned();
            let surface = capability.surface.as_str().to_owned();
            checks.push(command_health_check(capability, tools));
            for requirement in &capability.auth_requirements {
                checks.push(auth_health_check(&provider, &surface, requirement));
            }
            for health_check in &capability.health_checks {
                if !matches!(
                    health_check.as_str(),
                    "codex_cli" | "claude_sdk" | "pi_cli" | "api_key"
                ) {
                    checks.push(DoctorProviderHealthCheck {
                        provider: provider.clone(),
                        surface: surface.clone(),
                        check: health_check.clone(),
                        status: ProviderValidationStatus::Skip,
                        message: "live provider check requires explicit real-provider validation"
                            .to_owned(),
                    });
                }
            }
            checks
        })
        .collect()
}

fn command_health_check(
    capability: &ProviderCapability,
    tools: &[ToolCheck],
) -> DoctorProviderHealthCheck {
    let provider = capability.provider_kind.as_str();
    let tool = tools.iter().find(|tool| tool.id == provider);
    let available = tool.is_some_and(|tool| tool.available);
    DoctorProviderHealthCheck {
        provider: provider.to_owned(),
        surface: capability.surface.as_str().to_owned(),
        check: format!("{provider}_cli"),
        status: if available {
            ProviderValidationStatus::Pass
        } else {
            ProviderValidationStatus::Fail
        },
        message: if available {
            format!("{provider} CLI is available")
        } else {
            format!("{provider} CLI is not on PATH")
        },
    }
}

fn auth_health_check(
    provider: &str,
    surface: &str,
    requirement: &str,
) -> DoctorProviderHealthCheck {
    let env_name = match provider {
        "codex" => Some("OPENAI_API_KEY"),
        "claude" => Some("ANTHROPIC_API_KEY"),
        _ => None,
    };
    let env_set = env_name.is_some_and(|name| env::var_os(name).is_some());
    DoctorProviderHealthCheck {
        provider: provider.to_owned(),
        surface: surface.to_owned(),
        check: requirement.to_owned(),
        status: if env_set {
            ProviderValidationStatus::Pass
        } else {
            ProviderValidationStatus::Skip
        },
        message: if let Some(env_name) = env_name {
            if env_set {
                format!("{env_name} is set; value redacted")
            } else {
                format!("{env_name} is unset; credential reference may come from provider config")
            }
        } else {
            "credential reference posture unavailable".to_owned()
        },
    }
}

fn doctor_provider_config_checks(
    paths: &[PathBuf],
    capabilities: &[ProviderCapability],
) -> Vec<DoctorProviderConfigCheck> {
    paths
        .iter()
        .map(|path| {
            let (results, bindings) = match fs::read_to_string(path) {
                Ok(config_json) => {
                    validate_doctor_provider_config_json_with_bindings(&config_json, capabilities)
                }
                Err(error) => (
                    vec![ProviderValidationResult::fail(
                        "",
                        "",
                        "provider.config.unreadable",
                        "read_error",
                        format!("could not read provider config: {error}"),
                    )],
                    Vec::new(),
                ),
            };
            DoctorProviderConfigCheck {
                path: path.clone(),
                results,
                bindings,
            }
        })
        .collect()
}

#[cfg(test)]
fn validate_doctor_provider_config_json(config_json: &str) -> Vec<ProviderValidationResult> {
    validate_doctor_provider_config_json_with_bindings(
        config_json,
        &builtin_provider_capabilities(),
    )
    .0
}

fn validate_doctor_provider_config_json_with_bindings(
    config_json: &str,
    capabilities: &[ProviderCapability],
) -> (
    Vec<ProviderValidationResult>,
    Vec<DoctorProviderBindingCheck>,
) {
    let value = match serde_json::from_str::<Value>(config_json) {
        Ok(value) => value,
        Err(_) => return (validate_provider_binding_json(config_json), Vec::new()),
    };
    let provider_values = if let Some(providers) = value.get("providers").and_then(Value::as_array)
    {
        providers.iter().collect::<Vec<_>>()
    } else if let Some(providers) = value.as_array() {
        providers.iter().collect::<Vec<_>>()
    } else {
        vec![&value]
    };

    let mut all_results = Vec::new();
    let mut bindings = Vec::new();
    for provider in provider_values {
        match ProviderBindingConfig::from_value(provider) {
            Ok(config) => {
                let mut results = validate_provider_binding(&config, capabilities);
                results.extend(validate_provider_runtime_config(&config));
                all_results.extend(results.iter().cloned());
                bindings.push(DoctorProviderBindingCheck { config, results });
            }
            Err(results) => all_results.extend(results),
        }
    }
    (all_results, bindings)
}

fn validate_provider_runtime_config(
    config: &ProviderBindingConfig,
) -> Vec<ProviderValidationResult> {
    if config.provider_kind != ProviderKind::Command || config.surface != AdapterSurface::Command {
        return Vec::new();
    }
    match command_launch_plan_from_config(config) {
        Ok(_) => vec![ProviderValidationResult::pass(
            config.provider_id.clone(),
            config.surface.as_str(),
            "provider.command.valid",
            "command_config_valid",
            "command provider config is launchable",
        )],
        Err(StoreError::Conflict(message)) => vec![ProviderValidationResult::fail(
            config.provider_id.clone(),
            config.surface.as_str(),
            "provider.command.invalid",
            "invalid_command_config",
            message,
        )],
        Err(error) => vec![ProviderValidationResult::fail(
            config.provider_id.clone(),
            config.surface.as_str(),
            "provider.command.invalid",
            "invalid_command_config",
            format!("{error:?}"),
        )],
    }
}

fn record_doctor_provider_validation_evidence(
    store: &SqliteStore,
    instance_id: &str,
    provider_configs: &[DoctorProviderConfigCheck],
    capabilities: &[ProviderCapability],
) -> Result<usize, StoreError> {
    let mut count = 0usize;
    for config_check in provider_configs {
        for binding in &config_check.bindings {
            let status = if binding
                .results
                .iter()
                .any(|result| result.status == ProviderValidationStatus::Fail)
            {
                "fail"
            } else {
                "pass"
            };
            let capability = capabilities
                .iter()
                .find(|capability| {
                    capability.provider_kind == binding.config.provider_kind
                        && capability.surface == binding.config.surface
                })
                .map(ProviderCapability::to_json)
                .unwrap_or_else(|| {
                    json!({
                        "provider_kind": binding.config.provider_kind.as_str(),
                        "surface": binding.config.surface.as_str(),
                        "registered": false,
                    })
                });
            let config_json = binding.config.to_json_redacted().to_string();
            let capability_json = capability.to_string();
            let validation_results_json = Value::Array(
                binding
                    .results
                    .iter()
                    .map(ProviderValidationResult::to_json)
                    .collect::<Vec<_>>(),
            )
            .to_string();
            let correlation_id = format!(
                "provider-validation:{}:{}",
                binding.config.provider_id,
                binding.config.surface.as_str()
            );
            let source_path = config_check.path.display().to_string();
            store.record_provider_validation_evidence(ProviderValidationEvidence {
                instance_id,
                provider_id: &binding.config.provider_id,
                provider_kind: binding.config.provider_kind.as_str(),
                surface: binding.config.surface.as_str(),
                status,
                config_json: &config_json,
                capability_json: &capability_json,
                validation_results_json: &validation_results_json,
                source_path: Some(&source_path),
                correlation_id: Some(&correlation_id),
            })?;
            count += 1;
        }
    }
    Ok(count)
}

fn provider_config_check_to_json(check: &DoctorProviderConfigCheck) -> Value {
    json!({
        "path": check.path.display().to_string(),
        "results": check
            .results
            .iter()
            .map(ProviderValidationResult::to_json)
            .collect::<Vec<_>>(),
    })
}

fn provider_health_check_to_json(check: &DoctorProviderHealthCheck) -> Value {
    json!({
        "provider": check.provider,
        "surface": check.surface,
        "check": check.check,
        "status": check.status.as_str(),
        "message": check.message,
    })
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct ToolCheck {
    id: &'static str,
    category: &'static str,
    command: &'static str,
    required: bool,
    available: bool,
    path: Option<String>,
    note: &'static str,
}

fn doctor_tool_checks() -> Vec<ToolCheck> {
    let path = path_value();
    let mut checks = [
        (
            "maude",
            "formal",
            &["maude"][..],
            false,
            "needed for formal model checks and generated Maude searches",
        ),
        (
            "python",
            "formal",
            &["python3", "python"][..],
            false,
            "needed for generated construct graph and lowered IR Maude bridge checks",
        ),
        (
            "java",
            "formal",
            &["java"][..],
            false,
            "needed for Apalache/TLA+ checks",
        ),
        (
            "apalache",
            "formal",
            &["apalache-mc", "apalache"][..],
            false,
            "needed for TLA+ lifecycle checks",
        ),
        (
            "coerce",
            "integration",
            &["coerce-cli", "coerce"][..],
            false,
            "needed for no-mock coerce integration tests",
        ),
        (
            "codex",
            "provider",
            &["codex"][..],
            false,
            "needed for Codex agent harness provider runs",
        ),
        (
            "claude",
            "provider",
            &["claude"][..],
            false,
            "needed for Claude Code agent harness provider runs",
        ),
    ]
    .into_iter()
    .map(|(id, category, candidates, required, note)| {
        let path = find_executable_in_path(candidates, &path);
        ToolCheck {
            id,
            category,
            command: candidates[0],
            required,
            available: path.is_some(),
            path,
            note,
        }
    })
    .collect::<Vec<_>>();

    let python_path = checks
        .iter()
        .find(|tool| tool.id == "python")
        .and_then(|tool| tool.path.clone());
    let jsonschema_available = python_path
        .as_deref()
        .is_some_and(|python| python_module_available(python, "jsonschema"));
    checks.push(ToolCheck {
        id: "python-jsonschema",
        category: "formal",
        command: "python3 -c 'import jsonschema'",
        required: false,
        available: jsonschema_available,
        path: python_path,
        note: "needed by generated construct graph and lowered IR Maude bridge checks",
    });
    checks
}

fn path_value() -> String {
    env::var_os("PATH")
        .map(|value| value.to_string_lossy().into_owned())
        .unwrap_or_default()
}

fn find_executable_in_path(candidates: &[&str], path_value: &str) -> Option<String> {
    for directory in env::split_paths(path_value) {
        for candidate in candidates {
            let path = directory.join(candidate);
            if path.is_file() {
                return Some(path.display().to_string());
            }
        }
    }
    None
}

fn python_module_available(python: &str, module: &str) -> bool {
    Command::new(python)
        .arg("-c")
        .arg(format!("import {module}"))
        .output()
        .map(|output| output.status.success())
        .unwrap_or(false)
}

/// One `whip lint` finding: a quality observation beyond the correctness errors
/// `whip check` reports. Carries a stable code + severity plus the declared entity
/// `name` it concerns; `span` is resolved from that name against the source so the
/// finding can point at a location (CLI line/col and LSP diagnostics).
#[derive(Debug)]
struct LintFinding {
    code: &'static str,
    severity: Severity,
    message: String,
    /// The top-level declaration this finding is about. Every lint finding concerns
    /// a uniquely-named top-level decl, so the name resolves unambiguously to a span.
    name: Option<String>,
    span: Option<SourceSpan>,
}

/// A lint rule's configured *action* (spec/editor-tooling.md) — a separate axis from
/// the finding's intrinsic `severity`. Set on the CLI (`--allow`/`--deny`) or in a
/// project `whip.lint.json`; CLI overrides config overrides the `warn` default.
#[derive(Clone, Copy, PartialEq, Eq)]
enum LintAction {
    /// Suppressed: the finding is not emitted.
    Allow,
    /// Emitted at its default severity; does not fail the run.
    Warn,
    /// Emitted and the CLI exits nonzero.
    Deny,
}

impl LintAction {
    fn as_str(self) -> &'static str {
        match self {
            Self::Allow => "allow",
            Self::Warn => "warn",
            Self::Deny => "deny",
        }
    }

    fn from_wire(value: &str) -> Option<Self> {
        match value {
            "allow" => Some(Self::Allow),
            "warn" => Some(Self::Warn),
            "deny" => Some(Self::Deny),
            _ => None,
        }
    }
}

/// Resolve a project `whip.lint.json` (`whipplescript.lint_config.v0`) next to the
/// linted program into a code→action map. Returns an error string for invalid
/// configuration (a `lint.internal` infrastructure error per spec). `Ok(None)` means
/// no config file is present.
fn load_lint_config(
    program_path: &str,
) -> Result<Option<std::collections::BTreeMap<String, LintAction>>, String> {
    let config_path = Path::new(program_path)
        .parent()
        .unwrap_or_else(|| Path::new("."))
        .join("whip.lint.json");
    let contents = match fs::read_to_string(&config_path) {
        Ok(contents) => contents,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(error) => return Err(format!("cannot read {}: {error}", config_path.display())),
    };
    let parsed: Value = serde_json::from_str(&contents)
        .map_err(|error| format!("invalid lint config {}: {error}", config_path.display()))?;
    if parsed.get("schema").and_then(Value::as_str) != Some("whipplescript.lint_config.v0") {
        return Err(format!(
            "{}: expected schema `whipplescript.lint_config.v0`",
            config_path.display()
        ));
    }
    let mut actions = std::collections::BTreeMap::new();
    if let Some(rules) = parsed.get("rules") {
        let rules = rules
            .as_object()
            .ok_or_else(|| format!("{}: `rules` must be an object", config_path.display()))?;
        for (code, action) in rules {
            let action = action
                .as_str()
                .and_then(LintAction::from_wire)
                .ok_or_else(|| {
                    format!(
                        "{}: rule `{code}` has an invalid action (use allow/warn/deny)",
                        config_path.display()
                    )
                })?;
            actions.insert(code.clone(), action);
        }
    }
    Ok(Some(actions))
}

/// Coerce functions declared but never called. A `coerce` is only callable from
/// within the program (no external invocation), so an uncalled one is unambiguously
/// dead — zero false-positive risk. The call scan is conservative: a name that
/// appears in a `coerce <name>(` position anywhere (even inside a prompt) counts as
/// used, so the analysis can only ever under-report, never wrongly flag.
fn lint_unused_coerces(ir: &IrProgram) -> Vec<LintFinding> {
    let mut called: std::collections::HashSet<String> = std::collections::HashSet::new();
    for rule in &ir.rules {
        for line in rule.body.lines() {
            if let Some(rest) = line.trim().strip_prefix("coerce ") {
                if let Some((name, _)) = rest.split_once('(') {
                    called.insert(name.trim().to_owned());
                }
            }
        }
    }
    ir.coerces
        .iter()
        .filter(|coerce| !called.contains(&coerce.name))
        .map(|coerce| LintFinding {
            code: "lint.unused_coerce",
            severity: Severity::Warning,
            message: format!("coerce `{}` is declared but never called", coerce.name),
            name: Some(coerce.name.clone()),
            span: None,
        })
        .collect()
}

/// Whole-token occurrence count of `name` in `text` (an identifier run is a maximal
/// `[A-Za-z0-9_]+`), so `r` does not match inside `recall` or `r.field`'s neighbours.
fn whole_token_count(text: &str, name: &str) -> usize {
    let mut count = 0;
    let mut current = String::new();
    let flush = |current: &mut String, count: &mut usize| {
        if current == name {
            *count += 1;
        }
        current.clear();
    };
    for ch in text.chars() {
        if ch.is_alphanumeric() || ch == '_' {
            current.push(ch);
        } else {
            flush(&mut current, &mut count);
        }
    }
    flush(&mut current, &mut count);
    count
}

/// A `coerce <fn>(...) as <binding>` call whose result `<binding>` is never used —
/// the coercion runs (validation/transform) but its result is discarded, which is
/// either dead work or a forgotten `after <binding> succeeds/fails` handler. Detection
/// mirrors the unused-type analysis: the binding is rule-local, so we count its
/// whole-token occurrences in the rule body and flag only when it appears EXACTLY
/// once — at its own binding site. A name reused elsewhere (even in a prompt string)
/// inflates the count, so the analysis only ever under-reports — zero false positives.
fn lint_unused_coerce_results(ir: &IrProgram) -> Vec<LintFinding> {
    let mut findings = Vec::new();
    for rule in &ir.rules {
        for line in rule.body.lines() {
            let Some(rest) = line.trim().strip_prefix("coerce ") else {
                continue;
            };
            // `<fn>(<args>) as <binding>` — the binding is the identifier after `as`.
            let Some((_, after_paren)) = rest.split_once('(') else {
                continue;
            };
            let Some((_, after_as)) = after_paren.split_once(" as ") else {
                continue;
            };
            let binding: String = after_as
                .trim_start()
                .chars()
                .take_while(|ch| ch.is_alphanumeric() || *ch == '_')
                .collect();
            if binding.is_empty() {
                continue;
            }
            if whole_token_count(&rule.body, &binding) == 1 {
                findings.push(LintFinding {
                    code: "lint.coerce_result_unused",
                    severity: Severity::Warning,
                    message: format!(
                        "coerce result `{binding}` in rule `{}` is never used — drop the coercion or handle its result",
                        rule.name
                    ),
                    // A rule-local binding is not a top-level declaration, so it has
                    // no `document_symbols` span; leaving `name` unset avoids a
                    // spurious match against a same-named top-level decl.
                    name: None,
                    span: None,
                });
            }
        }
    }
    findings
}

/// The set of identifier tokens appearing in any rule's `when` clauses or body. An
/// in-program-only declaration (coordination resource / queue / file store) is
/// referenced only by a rule operation that names it — in a body (`acquire`,
/// `append … to`, `consume`, `file … into`, `import … from`, `export … to`) or a
/// `when` clause (`when <queue> has ready issue`). A name absent from this set is
/// therefore unreferenced. Whole-token (not substring) matching avoids spurious
/// matches; treating any appearance as a use keeps the analysis conservative (it
/// can only under-report, never wrongly flag).
fn rule_identifiers(ir: &IrProgram) -> std::collections::HashSet<String> {
    let mut tokens = std::collections::HashSet::new();
    let absorb = |text: &str, tokens: &mut std::collections::HashSet<String>| {
        let mut current = String::new();
        for ch in text.chars() {
            if ch.is_alphanumeric() || ch == '_' {
                current.push(ch);
            } else if !current.is_empty() {
                tokens.insert(std::mem::take(&mut current));
            }
        }
        if !current.is_empty() {
            tokens.insert(current);
        }
    };
    for rule in &ir.rules {
        absorb(&rule.body, &mut tokens);
        for when in &rule.whens {
            absorb(&when.pattern, &mut tokens);
        }
    }
    tokens
}

/// In-program-only declarations (`lease`/`ledger`/`counter`/`queue`/`file store`)
/// declared but never referenced. Like `coerce`, these are only usable from within
/// the program, so an unreferenced one is dead — zero false-positive risk.
fn lint_unused_resources(ir: &IrProgram) -> Vec<LintFinding> {
    let tokens = rule_identifiers(ir);
    let mut findings = Vec::new();
    for lease in &ir.leases {
        if !tokens.contains(lease.name.as_str()) {
            findings.push(LintFinding {
                code: "lint.unused_lease",
                severity: Severity::Warning,
                message: format!("lease `{}` is declared but never acquired", lease.name),
                name: Some(lease.name.clone()),
                span: None,
            });
        }
    }
    for ledger in &ir.ledgers {
        if !tokens.contains(ledger.name.as_str()) {
            findings.push(LintFinding {
                code: "lint.unused_ledger",
                severity: Severity::Warning,
                message: format!("ledger `{}` is declared but never appended to", ledger.name),
                name: Some(ledger.name.clone()),
                span: None,
            });
        }
    }
    for counter in &ir.counters {
        if !tokens.contains(counter.name.as_str()) {
            findings.push(LintFinding {
                code: "lint.unused_counter",
                severity: Severity::Warning,
                message: format!("counter `{}` is declared but never consumed", counter.name),
                name: Some(counter.name.clone()),
                span: None,
            });
        }
    }
    for tracker in &ir.trackers {
        if !tokens.contains(tracker.name.as_str()) {
            findings.push(LintFinding {
                code: "lint.unused_tracker",
                severity: Severity::Warning,
                message: format!(
                    "tracker `{}` is declared but never filed into or claimed",
                    tracker.name
                ),
                name: Some(tracker.name.clone()),
                span: None,
            });
        }
    }
    for file_store in &ir.file_stores {
        if !tokens.contains(file_store.name.as_str()) {
            findings.push(LintFinding {
                code: "lint.unused_file_store",
                severity: Severity::Warning,
                message: format!(
                    "file store `{}` is declared but never read or written",
                    file_store.name
                ),
                name: Some(file_store.name.clone()),
                span: None,
            });
        }
    }
    findings
}

/// Rules with an effectively-empty body (only whitespace and comments). Such a
/// rule matches and commits nothing — a forgotten or half-written body, always a
/// mistake. Detecting an empty body (rather than inspecting metadata) is reliable:
/// every rule-body statement produces something, and a top-level `complete`/`fail`
/// is carried by the lowering rather than the IR metadata, so a body-text check is
/// the trustworthy signal and never false-positives on a rule that does work.
fn lint_noop_rules(ir: &IrProgram) -> Vec<LintFinding> {
    ir.rules
        .iter()
        .filter(|rule| {
            rule.body.lines().all(|line| {
                let trimmed = line.trim();
                trimmed.is_empty() || trimmed.starts_with('#') || trimmed.starts_with("//")
            })
        })
        .map(|rule| LintFinding {
            code: "lint.noop_rule",
            severity: Severity::Warning,
            message: format!(
                "rule `{}` has an empty body — it fires but does nothing",
                rule.name
            ),
            name: Some(rule.name.clone()),
            span: None,
        })
        .collect()
}

/// Whole-token frequency over the (bundled) source. A type name that appears
/// exactly once appears only at its own declaration — it is referenced nowhere.
/// Counting over the full bundled source means cross-`include` references count;
/// names appearing in comments/strings only ever inflate the count, keeping the
/// derived "unused" judgement conservative (it can only under-report).
fn source_token_frequency(source: &str) -> std::collections::HashMap<String, usize> {
    let mut freq = std::collections::HashMap::new();
    let mut current = String::new();
    for ch in source.chars() {
        if ch.is_alphanumeric() || ch == '_' {
            current.push(ch);
        } else if !current.is_empty() {
            *freq.entry(std::mem::take(&mut current)).or_insert(0) += 1;
        }
    }
    if !current.is_empty() {
        *freq.entry(current).or_insert(0) += 1;
    }
    freq
}

/// Declared `class`/`enum` types never referenced anywhere. Types are
/// program-internal (there is no external reference to a type by name), so a
/// user-declared name occurring exactly once — only at its own declaration — is
/// dead. The count must be EXACTLY one: a synthetic type generated during lowering
/// (e.g. a flow's `FlowAwait_*` state class) never appears in the source at all
/// (count 0), so requiring the one declaration occurrence excludes it. Zero
/// false-positive risk.
fn lint_unused_types(source: &str, ir: &IrProgram) -> Vec<LintFinding> {
    let freq = source_token_frequency(source);
    ir.schemas
        .iter()
        .filter_map(|schema| {
            let (name, kind, code) = match schema {
                IrSchema::Class(class) => (&class.name, "class", "lint.unused_class"),
                IrSchema::Enum(enum_type) => (&enum_type.name, "enum", "lint.unused_enum"),
            };
            (freq.get(name.as_str()).copied().unwrap_or(0) == 1).then(|| LintFinding {
                code,
                severity: Severity::Warning,
                message: format!("{kind} `{name}` is declared but never referenced"),
                name: Some(name.clone()),
                span: None,
            })
        })
        .collect()
}

/// A `file store` grant whose read/write glob matches everything under the root
/// (`**` or `**/*`) is broader than any concrete call needs — operational-risk
/// hygiene (spec/editor-tooling.md "Capability And Grant Hygiene"). Only an EXPLICIT
/// match-everything glob is flagged (a scoped glob like `docs/**` and the no-glob
/// default are left alone), so the analysis never false-flags a narrowed grant.
fn lint_broad_file_grants(ir: &IrProgram) -> Vec<LintFinding> {
    let is_match_all = |glob: &str| matches!(glob.trim(), "**" | "**/*");
    let mut findings = Vec::new();
    for store in &ir.file_stores {
        for (kind, globs) in [("read", &store.read_globs), ("write", &store.write_globs)] {
            if globs.iter().any(|glob| is_match_all(glob)) {
                findings.push(LintFinding {
                    code: "lint.broad_file_grant",
                    severity: Severity::Warning,
                    message: format!(
                        "file store `{}` grants `{kind}` to everything under its root (`**`) — narrow the glob to the paths actually used",
                        store.name
                    ),
                    name: Some(store.name.clone()),
                    span: None,
                });
            }
        }
    }
    findings
}

/// Rules whose `after` blocks nest deeply (≥ `DEEP_AFTER_THRESHOLD` levels). A long
/// `after`-chain is exactly what a `flow` exists to express more clearly, so this is a
/// maintainability hint (severity `info`), not a correctness issue. The depth is
/// computed from the body AST (`metadata.max_after_depth`), so it never miscounts on
/// braces inside prompt strings — zero false positives.
fn lint_deep_after_nesting(ir: &IrProgram) -> Vec<LintFinding> {
    const DEEP_AFTER_THRESHOLD: usize = 4;
    ir.rules
        .iter()
        .filter(|rule| rule.metadata.max_after_depth >= DEEP_AFTER_THRESHOLD)
        .map(|rule| LintFinding {
            code: "lint.deep_after_nesting",
            severity: Severity::Info,
            message: format!(
                "rule `{}` nests `after` blocks {} levels deep — consider a `flow` for the sequence",
                rule.name, rule.metadata.max_after_depth
            ),
            name: Some(rule.name.clone()),
            span: None,
        })
        .collect()
}

/// A `tools [...]` grant (DR-0025) only takes effect in the owned harness: the
/// grant is resolved and offered to the model exclusively when the agent runs
/// `provider owned` (or a harness whose kind is `owned`). A grant on a
/// codex/claude/fixture agent is dead — it can never be invoked — so flag it.
/// Resolving the harness kind keeps this zero-false-positive on `using` agents.
fn lint_tool_grant_requires_owned_harness(ir: &IrProgram) -> Vec<LintFinding> {
    let harness_is_owned = |name: &str| {
        ir.harnesses
            .iter()
            .find(|harness| harness.name == name)
            .map(|harness| harness.kind == "owned")
            .unwrap_or(false)
    };
    ir.agents
        .iter()
        .filter(|agent| !agent.tools.is_empty())
        .filter(|agent| {
            let direct_owned = agent.provider.as_deref() == Some("owned");
            let harness_owned = agent.harness.as_deref().is_some_and(harness_is_owned);
            !direct_owned && !harness_owned
        })
        .map(|agent| LintFinding {
            code: "lint.tool_grant_requires_owned_harness",
            severity: Severity::Warning,
            message: format!(
                "agent `{}` grants tools [{}] but does not use the owned harness; `tools` grants only take effect with `provider owned`",
                agent.name,
                agent.tools.join(", "),
            ),
            name: Some(agent.name.clone()),
            span: None,
        })
        .collect()
}

fn lint_program(source: &str, ir: &IrProgram) -> Vec<LintFinding> {
    let mut findings = lint_unused_coerces(ir);
    findings.extend(lint_unused_coerce_results(ir));
    findings.extend(lint_unused_resources(ir));
    findings.extend(lint_noop_rules(ir));
    findings.extend(lint_unused_types(source, ir));
    findings.extend(lint_broad_file_grants(ir));
    findings.extend(lint_deep_after_nesting(ir));
    findings.extend(lint_tool_grant_requires_owned_harness(ir));
    // Resolve each finding's declaration name to its source span. Top-level names are
    // program-unique, so a single `document_symbols` match is the declaration site.
    let symbols = whipplescript_parser::document_symbols(source);
    for finding in &mut findings {
        if let Some(name) = &finding.name {
            finding.span = symbols
                .iter()
                .find(|symbol| symbol.name == *name)
                .map(|symbol| symbol.span);
        }
    }
    findings
}

/// Lint one source file: load its project `whip.lint.json`, compile, run the
/// analyses, resolve each finding's action, and either print findings (text mode) or
/// push a `{path, findings}` report into `json_reports` (JSON mode). Returns the
/// `(denied, emitted)` counts, or `Err(FAILURE)` if it has already reported a config
/// or compile error (fail-fast, matching the single-file behavior).
#[allow(clippy::too_many_arguments)]
fn lint_source(
    path: &str,
    root: Option<&str>,
    selected_rules: &std::collections::BTreeSet<String>,
    cli_actions: &std::collections::BTreeMap<String, LintAction>,
    json: bool,
    json_reports: &mut Vec<Value>,
) -> Result<(usize, usize), ExitCode> {
    // A project `whip.lint.json` next to the file; invalid config is `lint.internal`.
    let config_actions = match load_lint_config(path) {
        Ok(config) => config.unwrap_or_default(),
        Err(error) => {
            if json {
                let _ = emit_json(json!({
                    "schema": "whipplescript.lint.v0",
                    "path": path,
                    "findings": [{
                        "code": "lint.internal",
                        "severity": "error",
                        "default_severity": "error",
                        "configured_action": "deny",
                        "message": error,
                    }],
                }));
            } else {
                eprintln!("error: [lint.internal] {error}");
            }
            return Err(ExitCode::FAILURE);
        }
    };
    let (source, ir) = match compile_source_path_with_root(path, root) {
        Ok(compiled) => compiled,
        Err(error) => {
            if json {
                let _ = emit_json(compile_failure_json_report(path, error));
            } else {
                let _ = report_compile_failure(path, error);
            }
            return Err(ExitCode::FAILURE);
        }
    };
    // Resolve each finding's action: CLI over config over the `warn` default.
    let action_of = |code: &str| -> LintAction {
        cli_actions
            .get(code)
            .or_else(|| config_actions.get(code))
            .copied()
            .unwrap_or(LintAction::Warn)
    };
    // `--rule` (when given) restricts to the named rules; `allow` suppresses entirely.
    let findings = lint_program(&source, &ir);
    let resolved: Vec<(&LintFinding, LintAction)> = findings
        .iter()
        .filter(|finding| selected_rules.is_empty() || selected_rules.contains(finding.code))
        .map(|finding| (finding, action_of(finding.code)))
        .filter(|(_, action)| *action != LintAction::Allow)
        .collect();
    let denied = resolved
        .iter()
        .filter(|(_, action)| *action == LintAction::Deny)
        .count();
    if json {
        json_reports.push(json!({
            "path": path,
            "findings": resolved
                .iter()
                .map(|(finding, action)| {
                    json!({
                        "code": finding.code,
                        "severity": finding.severity.as_str(),
                        // default_severity is the analysis's intrinsic severity;
                        // configured_action is the resolved policy axis (a separate
                        // concern from severity — spec/editor-tooling.md).
                        "default_severity": finding.severity.as_str(),
                        "configured_action": action.as_str(),
                        "message": finding.message,
                        // Location of the offending declaration (0-based line +
                        // UTF-16 character, matching LSP), when it resolves.
                        "range": finding.span.map(|span| {
                            let (start_line, start_char) = lsp_byte_to_position(&source, span.start);
                            let (end_line, end_char) = lsp_byte_to_position(&source, span.end);
                            json!({
                                "start": { "line": start_line, "character": start_char },
                                "end": { "line": end_line, "character": end_char },
                            })
                        }),
                    })
                })
                .collect::<Vec<_>>(),
        }));
    } else {
        for (finding, action) in &resolved {
            // Prefix with `line:col` (1-based) when the declaration span resolves.
            let location = finding
                .span
                .map(|span| {
                    let (line, character) = lsp_byte_to_position(&source, span.start);
                    format!(":{}:{}", line + 1, character + 1)
                })
                .unwrap_or_default();
            println!(
                "{path}{location}: {} [{}] {} ({})",
                finding.severity.as_str(),
                finding.code,
                finding.message,
                action.as_str(),
            );
        }
    }
    Ok((denied, resolved.len()))
}

/// `whip [--json] lint [--root <workflow>] [--rule <id>] [--allow <id>] [--deny <id>]
/// <source-or-dir>...`: static-analysis findings over programs that already compile. A
/// positional may be a file or a directory (discovered recursively for `.whip` files).
/// Compile errors are reported (lint is a superset of `check` for errors) with a
/// non-zero exit. Each finding's *action* is resolved from `--allow`/`--deny` (over a
/// project `whip.lint.json`, over the `warn` default): `allow` suppresses it, `warn`
/// reports it, `deny` reports it and exits nonzero (spec/editor-tooling.md). With one
/// source the JSON report is `{schema, path, findings}`; with several it is `{schema,
/// reports: [{path, findings}, …]}`.
/// `whip agents <workflow.whip>` — the std.agent introspection surface (DR-0015
/// truthful capability report, declared tier): list each declared `agent` with
/// its provider/harness/profile/capacity and its declared skills, capabilities,
/// and workflow tools. Reads the compiled IR; no provider probing (that is the
/// separate probed tier).
fn agents(options: &CliOptions) -> ExitCode {
    let usage = "usage: whip [--json] agents [--root <workflow>] <workflow.whip>";
    let mut source: Option<String> = None;
    let mut root: Option<String> = None;
    let mut index = 0;
    while index < options.args.len() {
        match options.args[index].as_str() {
            "--root" => {
                index += 1;
                root = options.args.get(index).cloned();
            }
            // Accept + ignore so the same arg set works across check/lint/agents.
            "--package-lock" => {
                index += 1;
            }
            arg if !arg.starts_with('-') => source = Some(arg.to_owned()),
            other => {
                eprintln!("unknown agents option `{other}`");
                eprintln!("{usage}");
                return ExitCode::from(2);
            }
        }
        index += 1;
    }
    let Some(source_path) = source else {
        eprintln!("{usage}");
        return ExitCode::from(2);
    };
    let (_source, ir) = match compile_source_path_with_root(&source_path, root.as_deref()) {
        Ok(pair) => pair,
        Err(error) => return report_compile_failure(&source_path, error),
    };

    if options.json {
        let agents_json: Vec<Value> = ir
            .agents
            .iter()
            .map(|agent| {
                json!({
                    "name": agent.name,
                    "provider": agent.provider,
                    "harness": agent.harness,
                    "profile": agent.profile,
                    "capacity": agent.capacity,
                    "skills": agent.skills,
                    "capabilities": agent.capabilities,
                    "tools": agent.tools,
                })
            })
            .collect();
        return emit_json(json!({ "agents": agents_json }));
    }

    if ir.agents.is_empty() {
        println!("no agents declared");
        return ExitCode::SUCCESS;
    }
    for agent in &ir.agents {
        println!("agent {}", agent.name);
        if let Some(provider) = &agent.provider {
            println!("  provider {provider}");
        }
        if let Some(harness) = &agent.harness {
            println!("  harness {harness}");
        }
        if let Some(profile) = &agent.profile {
            println!("  profile {profile}");
        }
        if let Some(capacity) = agent.capacity {
            println!("  capacity {capacity}");
        }
        if !agent.capabilities.is_empty() {
            println!("  capabilities {}", agent.capabilities.join(", "));
        }
        if !agent.tools.is_empty() {
            println!("  tools {}", agent.tools.join(", "));
        }
        if !agent.skills.is_empty() {
            println!("  skills {}", agent.skills.join(", "));
        }
    }
    ExitCode::SUCCESS
}

/// `whip providers <workflow.whip>` — the operator view of every provider a
/// program needs: aggregates the `provider` of each declared agent, channel, and
/// source into a distinct list, with what references each. Reads the compiled IR.
fn providers(options: &CliOptions) -> ExitCode {
    let usage = "usage: whip [--json] providers [--root <workflow>] <workflow.whip>";
    let mut source: Option<String> = None;
    let mut root: Option<String> = None;
    let mut index = 0;
    while index < options.args.len() {
        match options.args[index].as_str() {
            "--root" => {
                index += 1;
                root = options.args.get(index).cloned();
            }
            "--package-lock" => {
                index += 1;
            }
            arg if !arg.starts_with('-') => source = Some(arg.to_owned()),
            other => {
                eprintln!("unknown providers option `{other}`");
                eprintln!("{usage}");
                return ExitCode::from(2);
            }
        }
        index += 1;
    }
    let Some(source_path) = source else {
        eprintln!("{usage}");
        return ExitCode::from(2);
    };
    let (_source, ir) = match compile_source_path_with_root(&source_path, root.as_deref()) {
        Ok(pair) => pair,
        Err(error) => return report_compile_failure(&source_path, error),
    };

    // provider name -> sorted, deduped `<kind>:<name>` references.
    let mut uses: std::collections::BTreeMap<String, std::collections::BTreeSet<String>> =
        std::collections::BTreeMap::new();
    for agent in &ir.agents {
        if let Some(provider) = &agent.provider {
            uses.entry(provider.clone())
                .or_default()
                .insert(format!("agent:{}", agent.name));
        }
    }
    for channel in &ir.channels {
        uses.entry(channel.provider.clone())
            .or_default()
            .insert(format!("channel:{}", channel.name));
    }
    for src in &ir.sources {
        uses.entry(src.provider.clone())
            .or_default()
            .insert(format!("source:{}", src.name));
    }

    if options.json {
        let providers_json: Vec<Value> = uses
            .iter()
            .map(|(provider, refs)| {
                json!({
                    "provider": provider,
                    "used_by": refs.iter().cloned().collect::<Vec<_>>(),
                })
            })
            .collect();
        return emit_json(json!({ "providers": providers_json }));
    }

    if uses.is_empty() {
        println!("no providers referenced");
        return ExitCode::SUCCESS;
    }
    for (provider, refs) in &uses {
        println!("provider {provider}");
        for reference in refs {
            println!("  {reference}");
        }
    }
    ExitCode::SUCCESS
}

/// `whip skills <workflow.whip>` — completes the agent-introspection trio
/// (agents / providers / skills): lists every skill declared across the
/// program's agents, each with the agents that declare it. Reads the compiled IR.
fn skills(options: &CliOptions) -> ExitCode {
    let usage = "usage: whip [--json] skills [--root <workflow>] <workflow.whip>";
    let mut source: Option<String> = None;
    let mut root: Option<String> = None;
    let mut index = 0;
    while index < options.args.len() {
        match options.args[index].as_str() {
            "--root" => {
                index += 1;
                root = options.args.get(index).cloned();
            }
            "--package-lock" => {
                index += 1;
            }
            arg if !arg.starts_with('-') => source = Some(arg.to_owned()),
            other => {
                eprintln!("unknown skills option `{other}`");
                eprintln!("{usage}");
                return ExitCode::from(2);
            }
        }
        index += 1;
    }
    let Some(source_path) = source else {
        eprintln!("{usage}");
        return ExitCode::from(2);
    };
    let (_source, ir) = match compile_source_path_with_root(&source_path, root.as_deref()) {
        Ok(pair) => pair,
        Err(error) => return report_compile_failure(&source_path, error),
    };

    // skill name -> sorted, deduped declaring agents.
    let mut declared: std::collections::BTreeMap<String, std::collections::BTreeSet<String>> =
        std::collections::BTreeMap::new();
    for agent in &ir.agents {
        for skill in &agent.skills {
            declared
                .entry(skill.clone())
                .or_default()
                .insert(agent.name.clone());
        }
    }

    if options.json {
        let skills_json: Vec<Value> = declared
            .iter()
            .map(|(skill, agents)| {
                json!({
                    "skill": skill,
                    "declared_by": agents.iter().cloned().collect::<Vec<_>>(),
                })
            })
            .collect();
        return emit_json(json!({ "skills": skills_json }));
    }

    if declared.is_empty() {
        println!("no skills declared");
        return ExitCode::SUCCESS;
    }
    for (skill, agents) in &declared {
        println!("skill {skill}");
        for agent in agents {
            println!("  {agent}");
        }
    }
    ExitCode::SUCCESS
}

fn lint(options: &CliOptions) -> ExitCode {
    let usage =
        "usage: whip [--json] lint [--root <workflow>] [--rule <id>] [--allow <id>] [--deny <id>] <source-or-dir>...";
    let mut sources = Vec::new();
    let mut root = None;
    // CLI-supplied actions override config and the default; last flag for an id wins.
    let mut cli_actions: std::collections::BTreeMap<String, LintAction> =
        std::collections::BTreeMap::new();
    // `--rule <id>` (repeatable) restricts the run to only the named rules; empty
    // means run every rule.
    let mut selected_rules: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();
    let mut index = 0;
    while index < options.args.len() {
        match options.args[index].as_str() {
            "--root" => {
                index += 1;
                root = options.args.get(index).cloned();
            }
            "--rule" => {
                index += 1;
                let Some(id) = options.args.get(index) else {
                    eprintln!("`--rule` needs a lint rule id");
                    eprintln!("{usage}");
                    return ExitCode::from(2);
                };
                selected_rules.insert(id.clone());
            }
            flag @ ("--allow" | "--deny") => {
                index += 1;
                let Some(id) = options.args.get(index) else {
                    eprintln!("`{flag}` needs a lint rule id");
                    eprintln!("{usage}");
                    return ExitCode::from(2);
                };
                let action = if flag == "--allow" {
                    LintAction::Allow
                } else {
                    LintAction::Deny
                };
                cli_actions.insert(id.clone(), action);
            }
            // `lint` does not resolve packages (it analyzes source structure), but
            // accepts `--package-lock <path>` and ignores it so the same argument
            // set works across `check`/`lint`/`compile` for package-locked examples.
            "--package-lock" => {
                index += 1;
            }
            other if other.starts_with('-') => {
                eprintln!("unknown lint option `{other}`");
                eprintln!("{usage}");
                return ExitCode::from(2);
            }
            value => sources.push(value.to_owned()),
        }
        index += 1;
    }
    if sources.is_empty() {
        eprintln!("{usage}");
        return ExitCode::from(2);
    }
    // A positional may be a directory; discover its `.whip` files (sorted) like `test`.
    let files = match expand_test_sources(&sources) {
        Ok(files) => files,
        Err(error) => {
            eprintln!("error: {error}");
            return ExitCode::from(2);
        }
    };
    if files.is_empty() {
        eprintln!("error: no `.whip` sources found");
        return ExitCode::from(2);
    }

    let mut json_reports = Vec::new();
    let mut denied = 0usize;
    let mut emitted = 0usize;
    for file in &files {
        match lint_source(
            file,
            root.as_deref(),
            &selected_rules,
            &cli_actions,
            options.json,
            &mut json_reports,
        ) {
            Ok((file_denied, file_emitted)) => {
                denied += file_denied;
                emitted += file_emitted;
            }
            Err(code) => return code,
        }
    }

    if options.json {
        // One source keeps the flat `{schema, path, findings}` shape; several use a
        // `reports` array so each file's findings stay attributable.
        if let [single] = json_reports.as_slice() {
            let _ = emit_json(json!({
                "schema": "whipplescript.lint.v0",
                "path": single.get("path"),
                "findings": single.get("findings"),
            }));
        } else {
            let _ = emit_json(json!({
                "schema": "whipplescript.lint.v0",
                "reports": json_reports,
            }));
        }
    } else if emitted == 0 {
        println!("no lint findings");
    }
    if denied > 0 {
        if !options.json {
            eprintln!("error: {denied} denied lint finding(s)");
        }
        return ExitCode::FAILURE;
    }
    ExitCode::SUCCESS
}

/// Read one LSP message off `reader`: the `Content-Length` header block (each
/// header `\r\n`-terminated, ended by a blank line) followed by exactly that many
/// bytes of JSON body. Returns `None` at EOF (the editor closed the pipe).
fn lsp_read_message<R: std::io::BufRead>(reader: &mut R) -> Option<String> {
    let mut content_length = 0usize;
    loop {
        let mut line = String::new();
        if reader.read_line(&mut line).ok()? == 0 {
            return None;
        }
        let trimmed = line.trim_end();
        if trimmed.is_empty() {
            break;
        }
        if let Some(rest) = trimmed.strip_prefix("Content-Length:") {
            content_length = rest.trim().parse().ok()?;
        }
    }
    if content_length == 0 {
        return None;
    }
    let mut body = vec![0u8; content_length];
    reader.read_exact(&mut body).ok()?;
    String::from_utf8(body).ok()
}

/// Write one LSP message: the `Content-Length` framing then the JSON body.
fn lsp_write<W: std::io::Write>(writer: &mut W, value: &Value) {
    let body = value.to_string();
    let _ = write!(writer, "Content-Length: {}\r\n\r\n{}", body.len(), body);
    let _ = writer.flush();
}

/// LSP `Position` (0-based `line`, UTF-16 `character`) for a byte offset.
fn lsp_byte_to_position(text: &str, offset: usize) -> (u32, u32) {
    let offset = offset.min(text.len());
    let mut line = 0u32;
    let mut character = 0u32;
    for (index, ch) in text.char_indices() {
        if index >= offset {
            break;
        }
        if ch == '\n' {
            line += 1;
            character = 0;
        } else {
            character += ch.len_utf16() as u32;
        }
    }
    (line, character)
}

/// Byte offset of an LSP `Position` (0-based `line`, UTF-16 `character`). Clamps a
/// past-the-line-end character to the line's newline, and an out-of-range line to
/// the document end.
fn lsp_position_to_byte(text: &str, line: u32, character: u32) -> usize {
    let mut current_line = 0u32;
    let mut current_char = 0u32;
    for (index, ch) in text.char_indices() {
        if current_line == line && current_char == character {
            return index;
        }
        if ch == '\n' {
            if current_line == line {
                return index;
            }
            current_line += 1;
            current_char = 0;
        } else {
            current_char += ch.len_utf16() as u32;
        }
    }
    text.len()
}

/// The identifier token spanning byte `offset`, or `None` if `offset` is not on an
/// identifier. With `include_dot`, dotted names (e.g. a `signal deploy.finished`)
/// are read as one token. Identifiers are ASCII, so byte indexing is safe.
fn lsp_identifier_at(text: &str, offset: usize, include_dot: bool) -> Option<&str> {
    let bytes = text.as_bytes();
    let is_token = |b: u8| b.is_ascii_alphanumeric() || b == b'_' || (include_dot && b == b'.');
    if offset > bytes.len() {
        return None;
    }
    let mut start = offset;
    while start > 0 && is_token(bytes[start - 1]) {
        start -= 1;
    }
    let mut end = offset;
    while end < bytes.len() && is_token(bytes[end]) {
        end += 1;
    }
    (start < end).then(|| &text[start..end])
}

/// Byte ranges of every whole-token occurrence of `name` in `text`. "Whole token"
/// means the characters immediately around it are not identifier-continuation
/// chars (dotted names like `deploy.finished` treat `.` as a continuation char so
/// they match as a unit). Identifiers are ASCII, so byte indexing is safe.
fn lsp_find_occurrences(text: &str, name: &str) -> Vec<(usize, usize)> {
    if name.is_empty() {
        return Vec::new();
    }
    let dotted = name.contains('.');
    let is_continuation = |b: u8| b.is_ascii_alphanumeric() || b == b'_' || (dotted && b == b'.');
    let bytes = text.as_bytes();
    let mut occurrences = Vec::new();
    let mut from = 0;
    while let Some(rel) = text[from..].find(name) {
        let start = from + rel;
        let end = start + name.len();
        let before_ok = start == 0 || !is_continuation(bytes[start - 1]);
        let after_ok = end >= bytes.len() || !is_continuation(bytes[end]);
        if before_ok && after_ok {
            occurrences.push((start, end));
        }
        from = end;
    }
    occurrences
}

/// Converts a `file://` URI to a filesystem path (Linux/macOS form, minimal
/// percent-decoding). Returns `None` for non-`file` URIs.
fn lsp_uri_to_path(uri: &str) -> Option<PathBuf> {
    let path = uri.strip_prefix("file://")?;
    Some(PathBuf::from(path.replace("%20", " ")))
}

/// Converts a filesystem path to a `file://` URI.
fn lsp_path_to_uri(path: &Path) -> String {
    format!("file://{}", path.display())
}

/// Recursively collects `.whip` files under `dir`, skipping VCS/build/hidden
/// directories so the workspace scan stays bounded.
/// Recursion-depth ceiling for the LSP workspace scan: a guard against a
/// pathologically deep tree exhausting the stack. With the symlink skip below,
/// a crafted workspace (e.g. a `evil -> .` directory-symlink cycle, or one
/// pointing at `/`) can neither loop the scanner nor walk outside the project.
const LSP_MAX_SCAN_DEPTH: usize = 64;

fn lsp_collect_whip_files(dir: &Path, out: &mut Vec<PathBuf>, depth: usize) {
    if depth >= LSP_MAX_SCAN_DEPTH {
        return;
    }
    let Ok(entries) = std::fs::read_dir(dir) else {
        return;
    };
    for entry in entries.flatten() {
        // `file_type()` reports the entry WITHOUT resolving a final symlink, so
        // a symlink is never recursed into or read — a directory-symlink cycle
        // can't loop the scan and a symlink out of the tree can't escape it.
        let Ok(file_type) = entry.file_type() else {
            continue;
        };
        if file_type.is_symlink() {
            continue;
        }
        let path = entry.path();
        let name = entry.file_name();
        let name = name.to_string_lossy();
        if file_type.is_dir() {
            if name.starts_with('.') || name == "target" || name == "node_modules" {
                continue;
            }
            lsp_collect_whip_files(&path, out, depth + 1);
        } else if path.extension().and_then(|ext| ext.to_str()) == Some("whip") {
            out.push(path);
        }
    }
}

/// The workspace document set for cross-file features: every `.whip` file under
/// the workspace roots, with OPEN (in-memory) documents overriding their on-disk
/// content (so unsaved edits win). With no roots it degrades to just the open
/// documents, matching the single-document behavior.
fn lsp_workspace_documents(
    roots: &[PathBuf],
    open: &std::collections::HashMap<String, String>,
) -> std::collections::HashMap<String, String> {
    let mut docs = std::collections::HashMap::new();
    for root in roots {
        let mut files = Vec::new();
        lsp_collect_whip_files(root, &mut files, 0);
        for file in files {
            if let Ok(text) = std::fs::read_to_string(&file) {
                docs.insert(lsp_path_to_uri(&file), text);
            }
        }
    }
    for (uri, text) in open {
        docs.insert(uri.clone(), text.clone());
    }
    docs
}

/// Map a `DeclSymbol` kind tag to an LSP `SymbolKind` number.
fn lsp_symbol_kind(kind: &str) -> i32 {
    match kind {
        "workflow" => 2,                             // Module
        "class" => 5,                                // Class
        "enum" => 10,                                // Enum
        "rule" | "coerce" | "flow" | "action" => 12, // Function
        "signal" => 24,                              // Event
        "table" => 18,                               // Array
        "pattern" => 11,                             // Interface
        _ => 19,                                     // Object (coordination resources etc.)
    }
}

/// Map a `DeclSymbol` kind tag to an LSP `CompletionItemKind` number.
fn lsp_completion_kind(kind: &str) -> i32 {
    match kind {
        "workflow" => 9,                            // Module
        "class" => 7,                               // Class
        "enum" => 13,                               // Enum
        "rule" | "coerce" | "flow" | "action" => 3, // Function
        "signal" => 23,                             // Event
        "pattern" => 8,                             // Interface
        _ => 6,                                     // Variable (coordination resources, agent)
    }
}

/// The WhippleScript keywords offered as completions (top-level declaration
/// introducers + rule-body statement verbs). A flat list — editors filter by the
/// typed prefix; context-aware filtering is future work.
const LSP_KEYWORDS: &[&str] = &[
    "workflow", "class", "enum", "agent", "rule", "coerce", "flow", "action", "signal", "source",
    "table", "tracker", "channel", "lease", "ledger", "counter", "output", "failure", "input",
    "when", "record", "done", "tell", "decide", "askHuman", "exec", "call", "invoke", "with",
    "access", "to", "read", "write", "import", "export", "recall", "learn", "emit", "after",
    "case", "complete", "fail", "timer", "cancel", "claim", "release", "finish", "file", "acquire",
    "renew", "append", "consume",
];

/// Compile `text` and publish its diagnostics (errors + warnings) for `uri`. This
/// is the live error-squiggle path — it reuses the same compiler as `whip check`.
fn lsp_publish_diagnostics<W: std::io::Write>(writer: &mut W, uri: &str, text: &str) {
    let compiled = whipplescript_parser::compile_program(text);
    let to_lsp = |diagnostic: &Diagnostic, severity: i32| {
        let (start_line, start_char) = lsp_byte_to_position(text, diagnostic.span.start);
        let (end_line, end_char) = lsp_byte_to_position(text, diagnostic.span.end);
        let mut message = diagnostic.message.clone();
        if let Some(suggestion) = &diagnostic.suggestion {
            message.push_str(&format!("\nhelp: {suggestion}"));
        }
        let mut entry = json!({
            "range": {
                "start": { "line": start_line, "character": start_char },
                "end": { "line": end_line, "character": end_char },
            },
            "severity": severity,
            "source": "whip",
            "message": message,
        });
        // Secondary spans map to LSP `relatedInformation` (the editor renders
        // them as linked "note" locations), omitted when empty.
        if !diagnostic.related.is_empty() {
            let related: Vec<Value> = diagnostic
                .related
                .iter()
                .map(|info| {
                    let (rs_line, rs_char) = lsp_byte_to_position(text, info.span.start);
                    let (re_line, re_char) = lsp_byte_to_position(text, info.span.end);
                    json!({
                        "location": {
                            "uri": uri,
                            "range": {
                                "start": { "line": rs_line, "character": rs_char },
                                "end": { "line": re_line, "character": re_char },
                            },
                        },
                        "message": info.message,
                    })
                })
                .collect();
            entry
                .as_object_mut()
                .expect("diagnostic json is object")
                .insert("relatedInformation".to_owned(), Value::Array(related));
        }
        entry
    };
    let mut diagnostics = Vec::new();
    for diagnostic in &compiled.diagnostics {
        diagnostics.push(to_lsp(diagnostic, Severity::Error.lsp_code()));
    }
    for warning in &compiled.warnings {
        diagnostics.push(to_lsp(warning, Severity::Warning.lsp_code()));
    }
    // Lint findings (only when the program compiles, since they need the IR) surface
    // as diagnostics tagged `whip lint` — distinct from `whip` correctness diagnostics
    // via that `source` and the `lint.*` code, while keeping the LSP severity faithful
    // to the finding's own severity. Each carries the span resolved by `lint_program`.
    if let Some(ir) = &compiled.ir {
        for finding in lint_program(text, ir) {
            let Some(span) = finding.span else { continue };
            let (start_line, start_char) = lsp_byte_to_position(text, span.start);
            let (end_line, end_char) = lsp_byte_to_position(text, span.end);
            diagnostics.push(json!({
                "range": {
                    "start": { "line": start_line, "character": start_char },
                    "end": { "line": end_line, "character": end_char },
                },
                "severity": finding.severity.lsp_code(),
                "source": "whip lint",
                "code": finding.code,
                "message": finding.message,
            }));
        }
    }
    lsp_write(
        writer,
        &json!({
            "jsonrpc": "2.0",
            "method": "textDocument/publishDiagnostics",
            "params": { "uri": uri, "diagnostics": diagnostics },
        }),
    );
}

/// `whip lsp`: a minimal Language Server over stdio (spec/editor-tooling.md). v0
/// is the diagnostics-on-edit core — `initialize`, full-sync `didOpen`/`didChange`
/// (re-compile and publish diagnostics), and `didClose` (clear them). It is
/// hand-rolled JSON-RPC (no async/LSP crate, consistent with the workspace's
/// no-runtime-dependency stance). Hover/definition/completion are future work.
fn lsp(_options: &CliOptions) -> ExitCode {
    let stdin = std::io::stdin();
    let mut reader = std::io::BufReader::new(stdin.lock());
    let stdout = std::io::stdout();
    let mut writer = stdout.lock();
    let mut documents: std::collections::HashMap<String, String> = std::collections::HashMap::new();
    // Workspace roots (from `initialize`), used to scan `.whip` files on disk for
    // cross-file definition/references and filesystem-wide `workspace/symbol`.
    let mut workspace_roots: Vec<PathBuf> = Vec::new();

    while let Some(message) = lsp_read_message(&mut reader) {
        let Ok(value) = serde_json::from_str::<Value>(&message) else {
            continue;
        };
        let method = value.get("method").and_then(Value::as_str).unwrap_or("");
        let id = value.get("id").cloned();
        let params = value.get("params").cloned().unwrap_or(Value::Null);
        let document_text = |params: &Value| -> Option<(String, String)> {
            let document = params.get("textDocument")?;
            let uri = document.get("uri").and_then(Value::as_str)?.to_owned();
            // Full-sync: didOpen carries `textDocument.text`; didChange's last
            // content change carries the whole document.
            let text = document
                .get("text")
                .and_then(Value::as_str)
                .map(str::to_owned)
                .or_else(|| {
                    params
                        .get("contentChanges")
                        .and_then(Value::as_array)
                        .and_then(|changes| changes.last())
                        .and_then(|change| change.get("text"))
                        .and_then(Value::as_str)
                        .map(str::to_owned)
                })?;
            Some((uri, text))
        };
        match method {
            "initialize" => {
                // Capture workspace roots from rootUri / rootPath / workspaceFolders
                // so cross-file features can scan the project's `.whip` files.
                if let Some(uri) = params.get("rootUri").and_then(Value::as_str) {
                    if let Some(path) = lsp_uri_to_path(uri) {
                        workspace_roots.push(path);
                    }
                } else if let Some(path) = params.get("rootPath").and_then(Value::as_str) {
                    workspace_roots.push(PathBuf::from(path));
                }
                if let Some(folders) = params.get("workspaceFolders").and_then(Value::as_array) {
                    for folder in folders {
                        if let Some(uri) = folder.get("uri").and_then(Value::as_str) {
                            if let Some(path) = lsp_uri_to_path(uri) {
                                workspace_roots.push(path);
                            }
                        }
                    }
                }
                workspace_roots.sort();
                workspace_roots.dedup();
                lsp_write(
                    &mut writer,
                    &json!({
                        "jsonrpc": "2.0",
                        "id": id,
                        "result": {
                            "capabilities": {
                                "textDocumentSync": 1, // 1 = Full
                                "documentSymbolProvider": true,
                                "definitionProvider": true,
                                "hoverProvider": true,
                                "completionProvider": {},
                                "referencesProvider": true,
                                "renameProvider": true,
                                "documentFormattingProvider": true,
                                "documentHighlightProvider": true,
                                "workspaceSymbolProvider": true,
                            },
                            "serverInfo": { "name": "whip-lsp", "version": "0" },
                        },
                    }),
                );
            }
            "initialized" => {}
            "textDocument/didOpen" | "textDocument/didChange" => {
                if let Some((uri, text)) = document_text(&params) {
                    documents.insert(uri.clone(), text.clone());
                    lsp_publish_diagnostics(&mut writer, &uri, &text);
                }
            }
            "textDocument/completion" => {
                // A flat candidate list: language keywords plus the document's
                // declared top-level names. Editors filter by the typed prefix;
                // context/scope-aware filtering is future work.
                let mut items: Vec<Value> = LSP_KEYWORDS
                    .iter()
                    .map(|keyword| json!({ "label": keyword, "kind": 14 })) // 14 = Keyword
                    .collect();
                if let Some(text) = params
                    .get("textDocument")
                    .and_then(|document| document.get("uri"))
                    .and_then(Value::as_str)
                    .and_then(|uri| documents.get(uri))
                {
                    for symbol in whipplescript_parser::document_symbols(text) {
                        items.push(json!({
                            "label": symbol.name,
                            "detail": symbol.kind,
                            "kind": lsp_completion_kind(symbol.kind),
                        }));
                    }
                }
                lsp_write(
                    &mut writer,
                    &json!({
                        "jsonrpc": "2.0",
                        "id": id,
                        "result": { "isIncomplete": false, "items": items },
                    }),
                );
            }
            "textDocument/formatting" => {
                // Format the whole document via the same comment-preserving formatter
                // as `whip fmt`. Returns one whole-document edit, or no edits when
                // the document doesn't parse or `fmt` would refuse it (so it never
                // corrupts content).
                let edits = (|| {
                    let document = params.get("textDocument")?;
                    let uri = document.get("uri").and_then(Value::as_str)?;
                    let text = documents.get(uri)?;
                    let formatted = whipplescript_parser::format_program_preserving_comments(text)?;
                    if formatted == *text {
                        return Some(Vec::new());
                    }
                    let (end_line, end_char) = lsp_byte_to_position(text, text.len());
                    Some(vec![json!({
                        "range": {
                            "start": { "line": 0, "character": 0 },
                            "end": { "line": end_line, "character": end_char },
                        },
                        "newText": formatted,
                    })])
                })();
                lsp_write(
                    &mut writer,
                    &json!({
                        "jsonrpc": "2.0",
                        "id": id,
                        "result": edits.map(Value::Array).unwrap_or(Value::Null),
                    }),
                );
            }
            "textDocument/rename" => {
                // Rename a top-level symbol across the document. Like references but
                // EDITING — so occurrences inside string literals or comments (e.g. a
                // class name mentioned in a prompt) are excluded to avoid corrupting
                // text. Names are program-unique, so every code occurrence is the
                // symbol.
                let edit = (|| {
                    let document = params.get("textDocument")?;
                    let uri = document.get("uri").and_then(Value::as_str)?;
                    let text = documents.get(uri)?;
                    let new_name = params.get("newName").and_then(Value::as_str)?;
                    let position = params.get("position")?;
                    let line = position.get("line").and_then(Value::as_u64)? as u32;
                    let character = position.get("character").and_then(Value::as_u64)? as u32;
                    let offset = lsp_position_to_byte(text, line, character);
                    let symbols = whipplescript_parser::document_symbols(text);
                    let regions = whipplescript_parser::string_and_comment_spans(text);
                    let in_string_or_comment =
                        |start: usize| regions.iter().any(|r| r.start <= start && start < r.end);
                    for include_dot in [true, false] {
                        let Some(token) = lsp_identifier_at(text, offset, include_dot) else {
                            continue;
                        };
                        let Some(symbol) = symbols.iter().find(|symbol| symbol.name == token)
                        else {
                            continue;
                        };
                        let edits = lsp_find_occurrences(text, &symbol.name)
                            .into_iter()
                            .filter(|(start, _)| !in_string_or_comment(*start))
                            .map(|(start, end)| {
                                let (start_line, start_char) = lsp_byte_to_position(text, start);
                                let (end_line, end_char) = lsp_byte_to_position(text, end);
                                json!({
                                    "range": {
                                        "start": { "line": start_line, "character": start_char },
                                        "end": { "line": end_line, "character": end_char },
                                    },
                                    "newText": new_name,
                                })
                            })
                            .collect::<Vec<_>>();
                        return Some(json!({ "changes": { uri: edits } }));
                    }
                    None
                })();
                lsp_write(
                    &mut writer,
                    &json!({
                        "jsonrpc": "2.0",
                        "id": id,
                        "result": edit.unwrap_or(Value::Null),
                    }),
                );
            }
            "workspace/symbol" => {
                // Symbols across the whole workspace matching the query (a
                // case-insensitive substring; empty query matches all). Scans every
                // `.whip` file under the workspace roots, with open documents
                // overriding their on-disk content; with no roots this degrades to
                // the open documents.
                let query = params
                    .get("query")
                    .and_then(Value::as_str)
                    .unwrap_or("")
                    .to_lowercase();
                let mut results = Vec::new();
                let workspace = lsp_workspace_documents(&workspace_roots, &documents);
                for (uri, text) in &workspace {
                    for symbol in whipplescript_parser::document_symbols(text) {
                        if !query.is_empty() && !symbol.name.to_lowercase().contains(&query) {
                            continue;
                        }
                        let (start_line, start_char) =
                            lsp_byte_to_position(text, symbol.span.start);
                        let (end_line, end_char) = lsp_byte_to_position(text, symbol.span.end);
                        results.push(json!({
                            "name": symbol.name,
                            "kind": lsp_symbol_kind(symbol.kind),
                            "location": {
                                "uri": uri,
                                "range": {
                                    "start": { "line": start_line, "character": start_char },
                                    "end": { "line": end_line, "character": end_char },
                                },
                            },
                        }));
                    }
                }
                lsp_write(
                    &mut writer,
                    &json!({ "jsonrpc": "2.0", "id": id, "result": results }),
                );
            }
            "textDocument/documentHighlight" => {
                // Highlight every occurrence of the symbol under the cursor in the
                // current document (the editor's always-on cursor highlighting).
                // Same occurrence scan as references, shaped as DocumentHighlight[].
                let highlights = (|| {
                    let document = params.get("textDocument")?;
                    let uri = document.get("uri").and_then(Value::as_str)?;
                    let text = documents.get(uri)?;
                    let position = params.get("position")?;
                    let line = position.get("line").and_then(Value::as_u64)? as u32;
                    let character = position.get("character").and_then(Value::as_u64)? as u32;
                    let offset = lsp_position_to_byte(text, line, character);
                    let symbols = whipplescript_parser::document_symbols(text);
                    for include_dot in [true, false] {
                        let Some(token) = lsp_identifier_at(text, offset, include_dot) else {
                            continue;
                        };
                        let Some(symbol) = symbols.iter().find(|symbol| symbol.name == token)
                        else {
                            continue;
                        };
                        let highlights = lsp_find_occurrences(text, &symbol.name)
                            .into_iter()
                            .map(|(start, end)| {
                                let (start_line, start_char) = lsp_byte_to_position(text, start);
                                let (end_line, end_char) = lsp_byte_to_position(text, end);
                                json!({
                                    "range": {
                                        "start": { "line": start_line, "character": start_char },
                                        "end": { "line": end_line, "character": end_char },
                                    },
                                    "kind": 1, // Text
                                })
                            })
                            .collect::<Vec<_>>();
                        return Some(highlights);
                    }
                    None
                })();
                lsp_write(
                    &mut writer,
                    &json!({
                        "jsonrpc": "2.0",
                        "id": id,
                        "result": highlights.map(Value::Array).unwrap_or(Value::Null),
                    }),
                );
            }
            "textDocument/references" => {
                // All whole-token occurrences of the top-level symbol under the
                // cursor, ACROSS the workspace. Top-level names are program-unique,
                // so every occurrence in any `.whip` file is a reference to the same
                // symbol. Honors `context.includeDeclaration` (only the declaration
                // file's own declaration-span occurrence is filtered).
                let locations = (|| {
                    let document = params.get("textDocument")?;
                    let uri = document.get("uri").and_then(Value::as_str)?;
                    let text = documents.get(uri)?;
                    let position = params.get("position")?;
                    let line = position.get("line").and_then(Value::as_u64)? as u32;
                    let character = position.get("character").and_then(Value::as_u64)? as u32;
                    let offset = lsp_position_to_byte(text, line, character);
                    let include_declaration = params
                        .get("context")
                        .and_then(|context| context.get("includeDeclaration"))
                        .and_then(Value::as_bool)
                        .unwrap_or(true);
                    let symbols = whipplescript_parser::document_symbols(text);
                    let workspace = lsp_workspace_documents(&workspace_roots, &documents);
                    for include_dot in [true, false] {
                        let Some(token) = lsp_identifier_at(text, offset, include_dot) else {
                            continue;
                        };
                        let Some(symbol) = symbols.iter().find(|symbol| symbol.name == token)
                        else {
                            continue;
                        };
                        let mut locations = Vec::new();
                        for (doc_uri, doc_text) in &workspace {
                            // The declaration span only applies to the file that
                            // declares the symbol (the current document).
                            let declaration_span = (doc_uri == uri).then_some(symbol.span);
                            for (start, end) in lsp_find_occurrences(doc_text, &symbol.name) {
                                if !include_declaration {
                                    if let Some(decl) = declaration_span {
                                        if start >= decl.start && start < decl.end {
                                            continue;
                                        }
                                    }
                                }
                                let (start_line, start_char) =
                                    lsp_byte_to_position(doc_text, start);
                                let (end_line, end_char) = lsp_byte_to_position(doc_text, end);
                                locations.push(json!({
                                    "uri": doc_uri,
                                    "range": {
                                        "start": { "line": start_line, "character": start_char },
                                        "end": { "line": end_line, "character": end_char },
                                    },
                                }));
                            }
                        }
                        return Some(locations);
                    }
                    None
                })();
                lsp_write(
                    &mut writer,
                    &json!({
                        "jsonrpc": "2.0",
                        "id": id,
                        "result": locations.map(Value::Array).unwrap_or(Value::Null),
                    }),
                );
            }
            "textDocument/hover" => {
                // Show the declaration source for the symbol under the cursor (so
                // hovering a reference reveals the target's definition). Reuses the
                // same name→declaration resolution as go-to-definition.
                let contents = (|| {
                    let document = params.get("textDocument")?;
                    let uri = document.get("uri").and_then(Value::as_str)?;
                    let text = documents.get(uri)?;
                    let position = params.get("position")?;
                    let line = position.get("line").and_then(Value::as_u64)? as u32;
                    let character = position.get("character").and_then(Value::as_u64)? as u32;
                    let offset = lsp_position_to_byte(text, line, character);
                    let symbols = whipplescript_parser::document_symbols(text);
                    for include_dot in [true, false] {
                        let Some(token) = lsp_identifier_at(text, offset, include_dot) else {
                            continue;
                        };
                        if let Some(symbol) = symbols.iter().find(|symbol| symbol.name == token) {
                            let end = symbol.span.end.min(text.len());
                            let start = symbol.span.start.min(end);
                            // Cap long declarations (e.g. rule bodies) for a tidy hover.
                            let snippet = text.get(start..end)?;
                            let shown: Vec<&str> = snippet.lines().take(40).collect();
                            return Some(format!("```whip\n{}\n```", shown.join("\n")));
                        }
                    }
                    None
                })();
                let result = match contents {
                    Some(value) => json!({ "contents": { "kind": "markdown", "value": value } }),
                    None => Value::Null,
                };
                lsp_write(
                    &mut writer,
                    &json!({ "jsonrpc": "2.0", "id": id, "result": result }),
                );
            }
            "textDocument/definition" => {
                // Resolve the identifier under the cursor to a top-level
                // declaration. Top-level names are program-unique, so a name match
                // is the definition (no scope analysis needed yet). Dotted signal
                // names are tried first, then the bare identifier. The current
                // document is searched first; a name declared in another workspace
                // file resolves cross-file.
                let location = (|| {
                    let document = params.get("textDocument")?;
                    let uri = document.get("uri").and_then(Value::as_str)?;
                    let text = documents.get(uri)?;
                    let position = params.get("position")?;
                    let line = position.get("line").and_then(Value::as_u64)? as u32;
                    let character = position.get("character").and_then(Value::as_u64)? as u32;
                    let offset = lsp_position_to_byte(text, line, character);
                    let symbols = whipplescript_parser::document_symbols(text);
                    let location_json = |doc_uri: &str, doc_text: &str, span: SourceSpan| {
                        let (start_line, start_char) = lsp_byte_to_position(doc_text, span.start);
                        let (end_line, end_char) = lsp_byte_to_position(doc_text, span.end);
                        json!({
                            "uri": doc_uri,
                            "range": {
                                "start": { "line": start_line, "character": start_char },
                                "end": { "line": end_line, "character": end_char },
                            },
                        })
                    };
                    let mut workspace: Option<std::collections::HashMap<String, String>> = None;
                    for include_dot in [true, false] {
                        let Some(token) = lsp_identifier_at(text, offset, include_dot) else {
                            continue;
                        };
                        // Same-document declaration wins.
                        if let Some(symbol) = symbols.iter().find(|symbol| symbol.name == token) {
                            return Some(location_json(uri, text, symbol.span));
                        }
                        // Otherwise search the rest of the workspace (scanned lazily).
                        let workspace = workspace.get_or_insert_with(|| {
                            lsp_workspace_documents(&workspace_roots, &documents)
                        });
                        for (doc_uri, doc_text) in workspace.iter() {
                            if doc_uri == uri {
                                continue;
                            }
                            if let Some(symbol) = whipplescript_parser::document_symbols(doc_text)
                                .into_iter()
                                .find(|symbol| symbol.name == token)
                            {
                                return Some(location_json(doc_uri, doc_text, symbol.span));
                            }
                        }
                    }
                    None
                })();
                lsp_write(
                    &mut writer,
                    &json!({
                        "jsonrpc": "2.0",
                        "id": id,
                        "result": location.unwrap_or(Value::Null),
                    }),
                );
            }
            "textDocument/documentSymbol" => {
                let symbols = params
                    .get("textDocument")
                    .and_then(|document| document.get("uri"))
                    .and_then(Value::as_str)
                    .and_then(|uri| documents.get(uri))
                    .map(|text| {
                        whipplescript_parser::document_symbols(text)
                            .into_iter()
                            .map(|symbol| {
                                let (start_line, start_char) =
                                    lsp_byte_to_position(text, symbol.span.start);
                                let (end_line, end_char) =
                                    lsp_byte_to_position(text, symbol.span.end);
                                let range = json!({
                                    "start": { "line": start_line, "character": start_char },
                                    "end": { "line": end_line, "character": end_char },
                                });
                                json!({
                                    "name": symbol.name,
                                    "detail": symbol.kind,
                                    "kind": lsp_symbol_kind(symbol.kind),
                                    "range": range,
                                    "selectionRange": range,
                                })
                            })
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                lsp_write(
                    &mut writer,
                    &json!({ "jsonrpc": "2.0", "id": id, "result": symbols }),
                );
            }
            "textDocument/didClose" => {
                if let Some(uri) = params
                    .get("textDocument")
                    .and_then(|d| d.get("uri"))
                    .and_then(Value::as_str)
                {
                    documents.remove(uri);
                    lsp_write(
                        &mut writer,
                        &json!({
                            "jsonrpc": "2.0",
                            "method": "textDocument/publishDiagnostics",
                            "params": { "uri": uri, "diagnostics": [] },
                        }),
                    );
                }
            }
            "shutdown" => {
                lsp_write(
                    &mut writer,
                    &json!({ "jsonrpc": "2.0", "id": id, "result": Value::Null }),
                );
            }
            "exit" => break,
            _ => {
                // Respond to unknown *requests* (those with an id) so the client is
                // not left awaiting; ignore unknown notifications.
                if matches!(&id, Some(value) if !value.is_null()) {
                    lsp_write(
                        &mut writer,
                        &json!({
                            "jsonrpc": "2.0",
                            "id": id,
                            "error": { "code": -32601, "message": format!("unhandled method `{method}`") },
                        }),
                    );
                }
            }
        }
    }
    ExitCode::SUCCESS
}

fn check(options: &CliOptions) -> ExitCode {
    let check_options = match CheckOptions::parse(&options.args) {
        Ok(check_options) => check_options,
        Err(message) => {
            eprintln!("{message}");
            return ExitCode::from(2);
        }
    };
    if check_options.paths.is_empty() {
        eprintln!("usage: whip check [--model-search] <workflow.whip>...");
        return ExitCode::from(2);
    }

    let mut failed = false;
    let mut reports = Vec::new();
    let script_manifest = match load_script_manifest(check_options.script_manifest_path.as_deref())
    {
        Ok(manifest) => manifest,
        Err(message) => {
            if options.json {
                let _ = emit_json(json!([{
                    "schema": "whipplescript.check_report.v0",
                    "status": "error",
                    "error": {"kind": "script_manifest", "message": message},
                }]));
            } else {
                eprintln!("{message}");
            }
            return ExitCode::from(2);
        }
    };
    let check_source_paths: Vec<&Path> = check_options.paths.iter().map(Path::new).collect();
    let package_lock = match load_package_lock(
        check_options.package_lock_path.as_deref(),
        &check_source_paths,
    ) {
        Ok(package_lock) => package_lock,
        Err(message) => {
            if options.json {
                let _ = emit_json(json!([{
                    "schema": "whipplescript.check_report.v0",
                    "status": "error",
                    "error": {"kind": "package_lock", "message": message},
                }]));
            } else {
                eprintln!("{message}");
            }
            return ExitCode::from(2);
        }
    };
    for path in check_options.paths {
        match compile_source_path_for_validation(&path, check_options.root.as_deref()) {
            Ok((source, ir)) => {
                let contract_registry = match contract_registry_for_ir(package_lock.as_ref(), &ir) {
                    Ok(registry) => registry,
                    Err(message) => {
                        failed = true;
                        if options.json {
                            reports.push(json!({
                                "schema": "whipplescript.check_report.v0",
                                "path": display_path(&path),
                                "status": "error",
                                "error": {
                                    "kind": "package_lock",
                                    "message": message,
                                },
                            }));
                        } else {
                            eprintln!("{path}: {message}");
                        }
                        continue;
                    }
                };
                let package_contract =
                    package_contract_json(package_lock.as_ref(), &contract_registry);
                let hosted_exec_diagnostics =
                    lint_hosted_exec(&ir, check_options.exec_profile, script_manifest.as_ref());
                if !hosted_exec_diagnostics.is_empty() {
                    failed = true;
                    if options.json {
                        reports.push(json!({
                            "schema": "whipplescript.check_report.v0",
                            "path": display_path(&path),
                            "status": "error",
                            "error": {
                                "kind": "diagnostics",
                                "diagnostics": hosted_exec_diagnostics
                                    .iter()
                                    .map(parser_diagnostic_to_json)
                                    .collect::<Vec<_>>(),
                            },
                        }));
                    } else {
                        for diagnostic in hosted_exec_diagnostics {
                            eprint!("{}", render_diagnostic(&path, &source, &diagnostic));
                        }
                    }
                    continue;
                }
                let grant_diagnostics = lint_agent_tool_grants(
                    Path::new(&path),
                    &ir,
                    check_options.package_lock_path.as_deref(),
                );
                if !grant_diagnostics.is_empty() {
                    failed = true;
                    if options.json {
                        reports.push(json!({
                            "schema": "whipplescript.check_report.v0",
                            "path": display_path(&path),
                            "status": "error",
                            "error": {
                                "kind": "diagnostics",
                                "diagnostics": grant_diagnostics
                                    .iter()
                                    .map(parser_diagnostic_to_json)
                                    .collect::<Vec<_>>(),
                            },
                        }));
                    } else {
                        for diagnostic in grant_diagnostics {
                            eprint!("{}", render_diagnostic(&path, &source, &diagnostic));
                        }
                    }
                    continue;
                }
                if !options.json {
                    if let Some(report) = ifc::report_for_check(&ir) {
                        eprint!("{report}");
                    }
                }
                // Imported @tool IRs (DR-0029 cross-package signal carriage, H8 stage
                // b): the consumer recompiles the pinned tool sources so an imported
                // `emit signal X` contributes its carried integrity to the consumer's
                // `signal:X`.
                let imported_irs = imported_tool_irs(package_lock.as_ref());
                let mut ifc_diagnostics = ifc::check_ifc_program_with_imports(&ir, &imported_irs);
                // Consumer-side cross-package check (DR-0029): each imported @tool's
                // IFC surface must be governed by the consumer envelope.
                ifc_diagnostics.extend(ifc::check_imported_tool_surfaces(&imported_tool_surfaces(
                    package_lock.as_ref(),
                )));
                if !ifc_diagnostics.is_empty() {
                    failed = true;
                    if options.json {
                        reports.push(json!({
                            "schema": "whipplescript.check_report.v0",
                            "path": display_path(&path),
                            "status": "error",
                            "error": {
                                "kind": "diagnostics",
                                "diagnostics": ifc_diagnostics
                                    .iter()
                                    .map(parser_diagnostic_to_json)
                                    .collect::<Vec<_>>(),
                            },
                        }));
                    } else {
                        for diagnostic in ifc_diagnostics {
                            eprint!("{}", render_diagnostic(&path, &source, &diagnostic));
                        }
                    }
                    continue;
                }
                let construct_graph = construct_graph_json(
                    &path,
                    &source,
                    &ir,
                    &contract_registry,
                    package_lock.as_ref(),
                );
                let lowered_ir_report = lowered_ir_report_json(
                    &path,
                    &source,
                    &ir,
                    &construct_graph,
                    package_lock.as_ref(),
                );
                if construct_graph_has_error_diagnostics(&construct_graph) {
                    failed = true;
                    if options.json {
                        reports.push(json!({
                            "schema": "whipplescript.check_report.v0",
                            "path": display_path(&path),
                            "status": "error",
                            "error": {
                                "kind": "construct_graph",
                                "diagnostics": construct_graph_error_diagnostics(&construct_graph),
                            },
                            "construct_graph": construct_graph,
                        }));
                    } else {
                        for diagnostic in construct_graph_error_diagnostics(&construct_graph) {
                            eprintln!(
                                "construct graph diagnostic {}: {}",
                                diagnostic
                                    .get("code")
                                    .and_then(Value::as_str)
                                    .unwrap_or("unknown"),
                                diagnostic
                                    .get("message")
                                    .and_then(Value::as_str)
                                    .unwrap_or("invalid construct graph")
                            );
                        }
                    }
                    continue;
                }
                if lowered_ir_report_has_error_diagnostics(&lowered_ir_report) {
                    failed = true;
                    if options.json {
                        reports.push(json!({
                            "schema": "whipplescript.check_report.v0",
                            "path": display_path(&path),
                            "status": "error",
                            "error": {
                                "kind": "lowered_ir_report",
                                "diagnostics": lowered_ir_report_error_diagnostics(&lowered_ir_report),
                            },
                            "construct_graph": construct_graph,
                            "lowered_ir_report": lowered_ir_report,
                        }));
                    } else {
                        for diagnostic in lowered_ir_report_error_diagnostics(&lowered_ir_report) {
                            eprintln!(
                                "lowered IR diagnostic {}: {}",
                                diagnostic
                                    .get("code")
                                    .and_then(Value::as_str)
                                    .unwrap_or("unknown"),
                                diagnostic
                                    .get("message")
                                    .and_then(Value::as_str)
                                    .unwrap_or("invalid lowered IR report")
                            );
                        }
                    }
                    continue;
                }

                let snapshot = ir.to_snapshot();
                let mut report = json!({
                    "schema": "whipplescript.check_report.v0",
                    "path": display_path(&path),
                    "status": "ok",
                    "workflow": ir.workflow.as_str(),
                    "source_hash": stable_hash_hex(&source),
                    "ir_hash": stable_hash_hex(&snapshot),
                    "snapshot": snapshot,
                    "source_metadata": source_metadata_json(&ir),
                    "contract_registry": contract_registry_to_json(&contract_registry),
                    "package_contract": package_contract,
                    "construct_graph": construct_graph,
                    "lowered_ir_report": lowered_ir_report,
                });
                if !options.json {
                    println!("== {}", display_path(&path));
                    print!("{}", ir.to_snapshot());
                }
                if check_options.model_search {
                    match run_model_search(
                        &path,
                        &source,
                        &ir,
                        &construct_graph,
                        &lowered_ir_report,
                        &report,
                    ) {
                        Ok(model_report) if model_report.searches == 0 => {
                            if options.json {
                                insert_model_search_fields(&mut report, &model_report);
                            } else {
                                println!("model search: no generated checks");
                            }
                        }
                        Ok(model_report) => {
                            if options.json {
                                insert_model_search_fields(&mut report, &model_report);
                            } else {
                                println!(
                                    "model search: {} checks passed (solutions={}, no_solutions={})",
                                    model_report.searches,
                                    model_report.solutions,
                                    model_report.no_solutions
                                );
                            }
                        }
                        Err(message) => {
                            if options.json {
                                insert_json_field(
                                    &mut report,
                                    "model_search",
                                    json!({
                                        "status": "error",
                                        "message": message,
                                    }),
                                );
                            } else {
                                eprintln!("{path}: model search failed: {message}");
                            }
                            failed = true;
                        }
                    }
                }
                reports.push(report);
            }
            Err(CompileFailure::Io(error)) => {
                if options.json {
                    reports.push(json!({
                        "schema": "whipplescript.check_report.v0",
                        "path": display_path(&path),
                        "status": "error",
                        "error": {
                            "kind": "io",
                            "message": error.to_string(),
                        },
                    }));
                } else {
                    eprintln!("{path}: failed to read: {error}");
                }
                failed = true;
            }
            Err(CompileFailure::Diagnostics {
                source,
                segments,
                diagnostics,
            }) => {
                failed = true;
                if options.json {
                    reports.push(json!({
                        "schema": "whipplescript.check_report.v0",
                        "path": display_path(&path),
                        "status": "error",
                        "error": {
                            "kind": "diagnostics",
                            "diagnostics": diagnostics
                                .iter()
                                .map(parser_diagnostic_to_json)
                                .collect::<Vec<_>>(),
                        },
                    }));
                } else {
                    for diagnostic in diagnostics {
                        eprint!(
                            "{}",
                            render_bundle_diagnostic(
                                &path,
                                &source,
                                &segments,
                                &diagnostic,
                                "error"
                            )
                        );
                    }
                }
            }
        }
    }

    if options.json {
        let code = if failed {
            ExitCode::FAILURE
        } else {
            ExitCode::SUCCESS
        };
        let _ = emit_json(Value::Array(reports));
        return code;
    }

    if failed {
        ExitCode::FAILURE
    } else {
        ExitCode::SUCCESS
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct CheckOptions {
    model_search: bool,
    root: Option<String>,
    exec_profile: ExecProfile,
    script_manifest_path: Option<PathBuf>,
    package_lock_path: Option<PathBuf>,
    paths: Vec<String>,
}

impl CheckOptions {
    fn parse(args: &[String]) -> Result<Self, String> {
        let mut model_search = false;
        let mut root = None;
        let mut exec_profile = ExecProfile::from_env();
        let mut script_manifest_path = script_manifest_path_from_env();
        let mut package_lock_path = None;
        let mut paths = Vec::new();
        let mut index = 0;
        while index < args.len() {
            match args[index].as_str() {
                "--model-search" => model_search = true,
                "--root" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err("expected workflow name after `--root`".to_owned());
                    };
                    root = Some(value.clone());
                }
                "--exec-profile" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err("expected profile after `--exec-profile`".to_owned());
                    };
                    exec_profile = ExecProfile::parse(value)?;
                }
                "--script-manifest" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err("expected path after `--script-manifest`".to_owned());
                    };
                    script_manifest_path = Some(PathBuf::from(value));
                }
                "--package-lock" => {
                    index += 1;
                    let Some(value) = args.get(index) else {
                        return Err("expected path after `--package-lock`".to_owned());
                    };
                    package_lock_path = Some(PathBuf::from(value));
                }
                "--" => {}
                arg if arg.starts_with('-') => {
                    return Err(format!("unknown check option `{arg}`"));
                }
                arg => paths.push(arg.to_owned()),
            }
            index += 1;
        }
        Ok(Self {
            model_search,
            root,
            exec_profile,
            script_manifest_path,
            package_lock_path,
            paths,
        })
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum ExecProfile {
    Dev,
    Hosted,
}

impl ExecProfile {
    fn parse(value: &str) -> Result<Self, String> {
        match value {
            "dev" => Ok(Self::Dev),
            "hosted" => Ok(Self::Hosted),
            other => Err(format!(
                "unknown exec profile `{other}`; expected `dev` or `hosted`"
            )),
        }
    }

    fn from_env() -> Self {
        env::var("WHIPPLESCRIPT_EXEC_PROFILE")
            .ok()
            .and_then(|value| Self::parse(&value).ok())
            .unwrap_or(Self::Dev)
    }

    fn is_hosted(self) -> bool {
        self == Self::Hosted
    }
}

fn script_manifest_path_from_env() -> Option<PathBuf> {
    env::var_os("WHIPPLESCRIPT_SCRIPT_MANIFEST").map(PathBuf::from)
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct ScriptCapability {
    name: String,
    argv: Vec<String>,
    sha256: String,
    env: BTreeMap<String, String>,
    /// Operator-declared hermeticity (compute plane P8-1): the script's output
    /// depends only on its argv, declared env, and stdin, so results are
    /// memoizable by content key in the delta-kernel result cache. Opt-in per
    /// manifest entry (`"hermetic": true`); default false = never cached.
    hermetic: bool,
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct ScriptManifest {
    capabilities: BTreeMap<String, ScriptCapability>,
}

impl ScriptManifest {
    fn load(path: &Path) -> Result<Self, String> {
        let text = fs::read_to_string(path).map_err(|error| {
            format!(
                "failed to read script manifest `{}`: {error}",
                path.display()
            )
        })?;
        let value = serde_json::from_str::<Value>(&text).map_err(|error| {
            format!(
                "failed to parse script manifest `{}`: {error}",
                path.display()
            )
        })?;
        let object = value.as_object().ok_or_else(|| {
            format!(
                "script manifest `{}` must be a JSON object keyed by capability name",
                path.display()
            )
        })?;
        let mut capabilities = BTreeMap::new();
        for (name, entry) in object {
            // Reserved-key namespace (spec/std-script.md "Capability ids"): an
            // operator entry named `raw` would shadow the `script.raw`
            // capability id the raw dev form is demoted onto, collapsing the
            // Layer-2 two-key namespace.
            if name == "raw" {
                return Err(
                    "script manifest key `raw` is reserved: `script.raw` is the raw dev-exec \
                     capability id; rename the entry"
                        .to_owned(),
                );
            }
            if !is_valid_script_manifest_key(name) {
                return Err(format!(
                    "script manifest key `{name}` is invalid: keys must match [a-z_][a-z0-9_]*"
                ));
            }
            let entry_object = entry
                .as_object()
                .ok_or_else(|| format!("script manifest entry `{name}` must be a JSON object"))?;
            let argv = entry_object
                .get("argv")
                .and_then(Value::as_array)
                .ok_or_else(|| format!("script manifest entry `{name}` must have argv array"))?
                .iter()
                .map(|value| {
                    value.as_str().map(str::to_owned).ok_or_else(|| {
                        format!("script manifest entry `{name}` argv values must be strings")
                    })
                })
                .collect::<Result<Vec<_>, _>>()?;
            if argv.is_empty() {
                return Err(format!(
                    "script manifest entry `{name}` argv must not be empty"
                ));
            }
            // Control-plane deny-list at pin time (spec/std-script.md "Static
            // checks" item 5): same list the runtime exec path re-checks, so
            // operators learn at manifest load, not first execution.
            if let Some(denied) = script_argv_denied_executable(&argv) {
                return Err(format!(
                    "script manifest entry `{name}` argv may not execute the `{denied}` \
                     control-plane binary"
                ));
            }
            let sha256 = entry_object
                .get("sha256")
                .and_then(Value::as_str)
                .ok_or_else(|| format!("script manifest entry `{name}` must have sha256 string"))?
                .trim_start_matches("sha256:")
                .to_ascii_lowercase();
            if sha256.len() != 64 || !sha256.chars().all(|ch| ch.is_ascii_hexdigit()) {
                return Err(format!(
                    "script manifest entry `{name}` sha256 must be a 64-character hex digest"
                ));
            }
            let env = entry_object
                .get("env")
                .and_then(Value::as_object)
                .map(|env_object| {
                    env_object
                        .iter()
                        .map(|(key, value)| {
                            value
                                .as_str()
                                .map(|value| (key.clone(), value.to_owned()))
                                .ok_or_else(|| {
                                    format!(
                                        "script manifest entry `{name}` env value `{key}` must be a string reference"
                                    )
                                })
                        })
                        .collect::<Result<BTreeMap<_, _>, _>>()
                })
                .transpose()?
                .unwrap_or_default();
            let hermetic = match entry_object.get("hermetic") {
                None => false,
                Some(Value::Bool(flag)) => *flag,
                Some(_) => {
                    return Err(format!(
                        "script manifest entry `{name}` hermetic must be a boolean"
                    ))
                }
            };
            capabilities.insert(
                name.clone(),
                ScriptCapability {
                    name: name.clone(),
                    argv,
                    sha256,
                    env,
                    hermetic,
                },
            );
        }
        Ok(Self { capabilities })
    }

    fn names(&self) -> Vec<String> {
        self.capabilities.keys().cloned().collect()
    }

    fn get(&self, name: &str) -> Option<&ScriptCapability> {
        self.capabilities.get(name)
    }
}

/// Operator script-manifest keys name `script.<key>` capability ids, so they
/// keep the id grammar: `[a-z_][a-z0-9_]*` (spec/std-script.md "Capability
/// ids"). `raw` is additionally reserved (checked separately at load).
fn is_valid_script_manifest_key(name: &str) -> bool {
    let mut chars = name.chars();
    chars
        .next()
        .is_some_and(|ch| ch.is_ascii_lowercase() || ch == '_')
        && chars.all(|ch| ch.is_ascii_lowercase() || ch.is_ascii_digit() || ch == '_')
}

fn load_script_manifest(path: Option<&Path>) -> Result<Option<ScriptManifest>, String> {
    path.map(ScriptManifest::load).transpose()
}

fn register_script_manifest_capabilities(
    store: &SqliteStore,
    manifest: &ScriptManifest,
    program_id: &str,
) -> Result<(), StoreError> {
    for name in manifest.capabilities.keys() {
        let capability = format!("script.{name}");
        store.register_capability_schema(CapabilitySchemaRegistration {
            capability: &capability,
            description: "Run an operator-pinned script capability.",
            schema_json: "{}",
            registered_by_package_id: None,
        })?;
        let binding_id = format!("binding_script_{}_{}", name, stable_hash_hex(program_id));
        store.bind_capability(CapabilityBinding {
            binding_id: &binding_id,
            program_id: Some(program_id),
            capability: &capability,
            provider: "builtin-script",
            config_json: "{}",
        })?;
    }
    Ok(())
}

/// Whether the operator granted any raw exec at all: a non-empty
/// `WHIPPLESCRIPT_EXEC_ALLOW` allowlist (the same source `exec_command_granted`
/// filters against). Presence is seeding key (b) for `script.raw`
/// (spec/std-script.md "Raw `exec` demotion"); the per-command glob match stays
/// the raw handler's convenience filter, not the boundary.
fn exec_allowlist_present() -> bool {
    env::var("WHIPPLESCRIPT_EXEC_ALLOW")
        .map(|allow| allow.split(':').any(|pattern| !pattern.is_empty()))
        .unwrap_or(false)
}

/// Seeds the `script.raw` capability row for `program_id` (script hard-off
/// Layer 2, raw form). Callers must have verified BOTH seeding keys: the
/// program's IR imports std.script, and the dev-profile allowlist authority
/// exists. Hosted profiles never seed `script.raw`, so hosted raw exec blocks
/// at store admission even from forged IR.
fn register_raw_script_capability(store: &SqliteStore, program_id: &str) -> Result<(), StoreError> {
    store.register_capability_schema(CapabilitySchemaRegistration {
        capability: "script.raw",
        description: "Run raw dev-profile exec commands behind the operator allowlist.",
        schema_json: "{}",
        registered_by_package_id: None,
    })?;
    store.bind_capability(CapabilityBinding {
        binding_id: &format!("binding_script_raw_{}", stable_hash_hex(program_id)),
        program_id: Some(program_id),
        capability: "script.raw",
        provider: "builtin-script",
        config_json: "{}",
    })?;
    Ok(())
}

/// Hosted-profile exec gate (spec/std-script.md "Static checks" item 2): raw
/// string exec is a check error suggesting the capability form, and a
/// capability name absent from the supplied manifest is a check error listing
/// the declared capabilities. Walks the IR effect nodes (the same structures
/// `check_script_hard_off` walks) — `IrEffectKind::ExecCommand` carries its
/// surface form as `exec_target` — so exec-looking text inside prompts or
/// string literals cannot misfire the gate.
fn lint_hosted_exec(
    ir: &IrProgram,
    exec_profile: ExecProfile,
    script_manifest: Option<&ScriptManifest>,
) -> Vec<Diagnostic> {
    if !exec_profile.is_hosted() {
        return Vec::new();
    }
    let available = script_manifest
        .map(ScriptManifest::names)
        .unwrap_or_default();
    let mut diagnostics = Vec::new();
    for rule in &ir.rules {
        for effect in &rule.metadata.effects {
            if effect.kind != IrEffectKind::ExecCommand {
                continue;
            }
            match &effect.exec_target {
                Some(IrExecTarget::Raw) => diagnostics.push(Diagnostic {
                    related: Vec::new(),
                    span: effect.span,
                    message: "raw `exec \"...\"` is not allowed in hosted exec profile".to_owned(),
                    suggestion: Some(
                        "use `exec <capability> with <record> -> <Type> as <binding>` from the script manifest"
                            .to_owned(),
                    ),
                }),
                Some(IrExecTarget::Capability { name })
                    if script_manifest
                        .and_then(|manifest| manifest.get(name))
                        .is_none() =>
                {
                    let declared = if available.is_empty() {
                        "no script capabilities declared".to_owned()
                    } else {
                        format!("declared script capabilities: {}", available.join(", "))
                    };
                    diagnostics.push(Diagnostic {
                        related: Vec::new(),
                        span: effect.span,
                        message: format!(
                            "exec capability `{name}` is not declared in the script manifest"
                        ),
                        suggestion: Some(declared),
                    });
                }
                _ => {}
            }
        }
    }
    diagnostics
}

fn canonical_json(value: &Value) -> String {
    match value {
        Value::Array(items) => {
            let items = items.iter().map(canonical_json).collect::<Vec<_>>();
            format!("[{}]", items.join(","))
        }
        Value::Object(object) => {
            let mut entries = object.iter().collect::<Vec<_>>();
            entries.sort_by_key(|(key, _)| *key);
            let entries = entries
                .into_iter()
                .map(|(key, value)| {
                    let key_json = serde_json::to_string(key)
                        .unwrap_or_else(|_| Value::String(key.clone()).to_string());
                    format!("{key_json}:{}", canonical_json(value))
                })
                .collect::<Vec<_>>();
            format!("{{{}}}", entries.join(","))
        }
        _ => serde_json::to_string(value).unwrap_or_else(|_| value.to_string()),
    }
}

fn source_metadata_json(ir: &IrProgram) -> Value {
    let tags = ir
        .source_tags
        .iter()
        .map(|tag| {
            json!({
                "name": tag.name,
                "target_kind": tag.target_kind,
                "target": tag.target,
                "source_span": source_span_to_json(tag.span),
            })
        })
        .collect::<Vec<_>>();
    let descriptions = ir
        .source_descriptions
        .iter()
        .map(|description| {
            json!({
                "value": description.value,
                "target_kind": description.target_kind,
                "target": description.target,
                "source_span": source_span_to_json(description.span),
            })
        })
        .collect::<Vec<_>>();
    json!({
        "tags": tags,
        "descriptions": descriptions,
        "targets": source_metadata_targets_json(ir),
    })
}

#[cfg(test)]
fn contract_registry_json(ir: &IrProgram) -> Value {
    let registry = ir.contract_registry();
    contract_registry_to_json(&registry)
}

fn contract_registry_to_json(registry: &ContractRegistry) -> Value {
    json!({
        "schema": "whipplescript.contract_registry.v0",
        "libraries": registry
            .libraries
            .iter()
            .map(|library| {
                json!({
                    "id": library.id.as_str(),
                    "version": library.version.as_str(),
                    "standard": library.standard,
                })
            })
            .collect::<Vec<_>>(),
        "constructs": registry
            .constructs
            .iter()
            .map(|form| {
                json!({
                    "id": form.id.as_str(),
                    "library_id": form.library_id.as_str(),
                    "version": form.version.as_str(),
                    "construct_family": form.construct_family.as_str(),
                    "keyword": form.keyword.as_str(),
                    "scope": form.scope.as_str(),
                    "fields": form.fields
                        .iter()
                        .map(|field| {
                            json!({
                                "name": field.name.as_str(),
                                "kind": field.kind.as_str(),
                                "required": field.required,
                            })
                        })
                        .collect::<Vec<_>>(),
                    "requires": construct_interfaces_json(&form.requires),
                    "provides": construct_interfaces_json(&form.provides),
                    "lowering_target": form.lowering_target.as_str(),
                    "target_capability": form.target_capability.as_deref(),
                })
            })
            .collect::<Vec<_>>(),
        "effect_contracts": registry
            .effect_contracts
            .iter()
            .map(|contract| {
                json!({
                    "id": contract.id.as_str(),
                    "library_id": contract.library_id.as_str(),
                    "version": contract.version.as_str(),
                    "effect_kind": contract.effect_kind.as_str(),
                    "source_forms": &contract.source_forms,
                    "input_schema": contract.input_schema.as_deref(),
                    "output_schema": contract.output_schema.as_deref(),
                    "required_capabilities": &contract.required_capabilities,
                    "provider_kinds": &contract.provider_kinds,
                    "projected_facts": &contract.projected_facts,
                    "validation": contract.validation.as_str(),
                })
            })
            .collect::<Vec<_>>(),
        "diagnostics": registry
            .validate()
            .iter()
            .map(|diagnostic| {
                json!({
                    "code": diagnostic.code.as_str(),
                    "message": diagnostic.message.as_str(),
                })
            })
            .collect::<Vec<_>>(),
    })
}

fn contract_registry_from_artifact_json(
    registry: &Value,
    label: &str,
) -> Result<ContractRegistry, String> {
    let libraries = require_json_array_field(registry, "libraries", label)?
        .iter()
        .enumerate()
        .map(|(index, library)| {
            let library_label = format!("{label}.libraries[{index}]");
            Ok(LibraryRegistration {
                id: required_json_str(library, "id", &library_label)?.to_owned(),
                version: required_json_str(library, "version", &library_label)?.to_owned(),
                standard: library
                    .get("standard")
                    .and_then(Value::as_bool)
                    .ok_or_else(|| format!("{library_label}.standard must be a boolean"))?,
            })
        })
        .collect::<Result<Vec<_>, String>>()?;
    let constructs = require_json_array_field(registry, "constructs", label)?
        .iter()
        .enumerate()
        .map(|(index, construct)| {
            let construct_label = format!("{label}.constructs[{index}]");
            let fields = require_json_array_field(construct, "fields", &construct_label)?
                .iter()
                .enumerate()
                .map(|(field_index, field)| {
                    let field_label = format!("{construct_label}.fields[{field_index}]");
                    Ok(ConstructField {
                        name: required_json_str(field, "name", &field_label)?.to_owned(),
                        kind: required_json_str(field, "kind", &field_label)?.to_owned(),
                        required: field
                            .get("required")
                            .and_then(Value::as_bool)
                            .ok_or_else(|| format!("{field_label}.required must be a boolean"))?,
                    })
                })
                .collect::<Result<Vec<_>, String>>()?;
            Ok(ConstructRegistration {
                id: required_json_str(construct, "id", &construct_label)?.to_owned(),
                library_id: required_json_str(construct, "library_id", &construct_label)?
                    .to_owned(),
                version: required_json_str(construct, "version", &construct_label)?.to_owned(),
                construct_family: required_json_str(
                    construct,
                    "construct_family",
                    &construct_label,
                )?
                .to_owned(),
                keyword: required_json_str(construct, "keyword", &construct_label)?.to_owned(),
                scope: required_json_str(construct, "scope", &construct_label)?.to_owned(),
                // Contract-registry artifacts carry the derived `fields[]`
                // view only; the grammar object stays a manifest-side input
                // (nothing downstream of the artifact boundary parses by it).
                grammar: None,
                fields,
                requires: contract_registry_interfaces_from_json(
                    construct,
                    "requires",
                    &construct_label,
                )?,
                provides: contract_registry_interfaces_from_json(
                    construct,
                    "provides",
                    &construct_label,
                )?,
                lowering_target: required_json_str(construct, "lowering_target", &construct_label)?
                    .to_owned(),
                target_capability: construct
                    .get("target_capability")
                    .and_then(Value::as_str)
                    .map(str::to_owned),
            })
        })
        .collect::<Result<Vec<_>, String>>()?;
    let effect_contracts = require_json_array_field(registry, "effect_contracts", label)?
        .iter()
        .enumerate()
        .map(|(index, contract)| {
            let contract_label = format!("{label}.effect_contracts[{index}]");
            Ok(EffectContract {
                id: required_json_str(contract, "id", &contract_label)?.to_owned(),
                library_id: required_json_str(contract, "library_id", &contract_label)?.to_owned(),
                version: required_json_str(contract, "version", &contract_label)?.to_owned(),
                effect_kind: required_json_str(contract, "effect_kind", &contract_label)?
                    .to_owned(),
                source_forms: required_json_string_array(
                    contract,
                    "source_forms",
                    &contract_label,
                )?,
                input_schema: optional_report_string(contract, "input_schema", &contract_label)?,
                output_schema: optional_report_string(contract, "output_schema", &contract_label)?,
                required_capabilities: required_json_string_array(
                    contract,
                    "required_capabilities",
                    &contract_label,
                )?,
                provider_kinds: required_json_string_array(
                    contract,
                    "provider_kinds",
                    &contract_label,
                )?,
                projected_facts: required_json_string_array(
                    contract,
                    "projected_facts",
                    &contract_label,
                )?,
                validation: typed_output_validation_from_json(
                    required_json_str(contract, "validation", &contract_label)?,
                    &format!("{contract_label}.validation"),
                )?,
            })
        })
        .collect::<Result<Vec<_>, String>>()?;
    Ok(ContractRegistry {
        libraries,
        constructs,
        effect_contracts,
    })
}

fn contract_registry_interfaces_from_json(
    construct: &Value,
    field: &str,
    construct_label: &str,
) -> Result<Vec<ConstructInterface>, String> {
    require_json_array_field(construct, field, construct_label)?
        .iter()
        .enumerate()
        .map(|(index, interface)| {
            let interface_label = format!("{construct_label}.{field}[{index}]");
            Ok(ConstructInterface {
                kind: required_json_str(interface, "kind", &interface_label)?.to_owned(),
                name: optional_report_string(interface, "name", &interface_label)?,
                type_ref: optional_report_string(interface, "type", &interface_label)?,
                phase: required_json_str(interface, "phase", &interface_label)?.to_owned(),
                cardinality: required_json_str(interface, "cardinality", &interface_label)?
                    .to_owned(),
            })
        })
        .collect()
}

fn optional_report_string(
    value: &Value,
    field: &str,
    owner: &str,
) -> Result<Option<String>, String> {
    match value.get(field) {
        Some(Value::String(value)) => Ok(Some(value.clone())),
        Some(Value::Null) | None => Ok(None),
        Some(_) => Err(format!("{owner}.{field} must be a string or null")),
    }
}

fn required_json_string_array(
    value: &Value,
    field: &str,
    owner: &str,
) -> Result<Vec<String>, String> {
    require_json_array_field(value, field, owner)?
        .iter()
        .enumerate()
        .map(|(index, item)| {
            item.as_str()
                .map(str::to_owned)
                .ok_or_else(|| format!("{owner}.{field}[{index}] must be a string"))
        })
        .collect()
}

fn typed_output_validation_from_json(
    value: &str,
    label: &str,
) -> Result<TypedOutputValidation, String> {
    match value {
        "none" => Ok(TypedOutputValidation::None),
        "runtime_boundary" => Ok(TypedOutputValidation::RuntimeBoundary),
        other => Err(format!(
            "{label} must be `none` or `runtime_boundary`, got `{other}`"
        )),
    }
}

fn validate_construct_uses_against_registry(
    ir: &IrProgram,
    registry: &ContractRegistry,
    label: &str,
) -> Result<(), String> {
    for use_form in ir.construct_uses() {
        let Some(form) = registry_construct_for_use(registry, use_form) else {
            return Err(format!(
                "{label} source-backed artifact registry does not authorize `{}` as a {} {} construct lowering to `{}`",
                use_form.keyword,
                use_form.scope,
                use_form.construct_family,
                use_form.target_capability
            ));
        };
        if !registry.effect_contracts.iter().any(|contract| {
            contract.id == use_form.target_capability && contract.effect_kind == "capability.call"
        }) {
            return Err(format!(
                "{label} source-backed artifact registry construct `{}` lowers to `{}` but has no matching `capability.call` effect contract",
                form.id, use_form.target_capability
            ));
        }
    }
    Ok(())
}

fn package_contract_json(
    package_lock: Option<&LoadedPackageLock>,
    registry: &ContractRegistry,
) -> Value {
    let manifests = package_lock
        .map(|lock| lock.manifests.as_slice())
        .unwrap_or(&[]);
    let package_lock_digest = package_lock_digest(package_lock);
    package_contract_json_from_manifests(manifests, &package_lock_digest, registry)
}

fn package_contract_json_from_manifests(
    manifests: &[PackageManifest],
    package_lock_digest: &str,
    registry: &ContractRegistry,
) -> Value {
    let diagnostics = registry
        .validate()
        .iter()
        .map(|diagnostic| {
            json!({
                "code": diagnostic.code.as_str(),
                "message": diagnostic.message.as_str(),
            })
        })
        .collect::<Vec<_>>();
    let mut artifact = json!({
        "schema": PACKAGE_CONTRACT_SCHEMA,
        "package_lock_digest": package_lock_digest,
        "platform_version": whipplescript_core::version(),
        "manifests": manifests
            .iter()
            .map(package_manifest_summary_json)
            .collect::<Vec<_>>(),
        "platform_construct_catalog": platform_construct_catalog_json(),
        "contract_registry": contract_registry_to_json(registry),
        "workflow_tools": package_workflow_tool_attestations_json(manifests),
        "diagnostics": diagnostics,
    });
    let digest_input = canonical_json(&artifact);
    insert_json_field(
        &mut artifact,
        "package_contract_digest",
        Value::String(sha256_hex(digest_input.as_bytes())),
    );
    artifact
}

/// The cross-package `@tool` attestation (DR-0025): for each workflow a package
/// exports, the eligibility flag, the derived input/output tool schemas, and the
/// outgoing invoke-tool edges. v1 `@tool` workflows are leaves, so `invokes` is
/// always empty — the field is reserved for the deferred nested-composition
/// acyclicity check. A consumer reads this to check a grant without the source.
/// Each imported `@tool`'s name + computed IFC surface, for the consumer-side
/// cross-package check (DR-0029). Recomputed from the tool source the lock pins.
/// The imported `@tool` programs, recompiled from the sources the lock pins, for the
/// consumer-side cross-package signal carriage (DR-0029 / H8 stage b). Best effort —
/// a tool that cannot be compiled standalone is skipped (its surface is then governed
/// fail-closed by `check_imported_tool_surfaces`).
fn imported_tool_irs(
    package_lock: Option<&LoadedPackageLock>,
) -> Vec<whipplescript_parser::IrProgram> {
    let mut out = Vec::new();
    if let Some(lock) = package_lock {
        for manifest in &lock.manifests {
            for tool in &manifest.workflow_tools {
                if let Ok(source) = std::fs::read_to_string(&tool.source) {
                    if let Some(tool_ir) = whipplescript_parser::compile_program(&source).ir {
                        out.push(tool_ir);
                    }
                }
            }
        }
    }
    out
}

fn package_tool_ifc_surface(
    package_id: &str,
    tool_name: &str,
    tool_ir: &whipplescript_parser::IrProgram,
) -> Vec<String> {
    let mut surface = ifc::ifc_surface(tool_ir);
    surface.push(format!("invoke:{package_id}/{tool_name}"));
    surface.sort();
    surface.dedup();
    surface
}

fn imported_tool_surfaces(package_lock: Option<&LoadedPackageLock>) -> Vec<(String, Vec<String>)> {
    let mut out = Vec::new();
    if let Some(lock) = package_lock {
        for manifest in &lock.manifests {
            for tool in &manifest.workflow_tools {
                if let Ok(source) = std::fs::read_to_string(&tool.source) {
                    if let Some(tool_ir) = whipplescript_parser::compile_program(&source).ir {
                        out.push((
                            tool.name.clone(),
                            package_tool_ifc_surface(&manifest.package_id, &tool.name, &tool_ir),
                        ));
                    }
                }
            }
        }
    }
    out
}

fn package_workflow_tool_attestations_json(manifests: &[PackageManifest]) -> Vec<Value> {
    let mut attestations = Vec::new();
    for manifest in manifests {
        for tool in &manifest.workflow_tools {
            let mut entry = json!({
                "name": tool.name,
                "package_id": manifest.package_id,
                "convergence_eligible": true,
                "input_schema": json_from_str(&tool.input_schema),
                "output_schema": json_from_str(&tool.output_schema),
                "invokes": [],
            });
            // DR-0029 X1/X5: attest the tool's information-flow surface. The surface
            // is computed from the tool's lowered effects, so `lowered ⊆ declared`
            // holds by construction; `flow` is the opaque join box (Fork A). Best
            // effort — if the source cannot be compiled standalone, the optional
            // block is omitted (the consumer then governs it fail-closed).
            if let Ok(source) = std::fs::read_to_string(&tool.source) {
                if let Some(tool_ir) = whipplescript_parser::compile_program(&source).ir {
                    entry["information_flow"] = json!({
                        "surface": package_tool_ifc_surface(&manifest.package_id, &tool.name, &tool_ir),
                        "flow": "join_box",
                        "ifc_attested": true,
                    });
                }
            }
            attestations.push(entry);
        }
    }
    attestations
}

fn package_contract_digest(
    package_lock: Option<&LoadedPackageLock>,
    registry: &ContractRegistry,
) -> String {
    package_contract_json(package_lock, registry)
        .get("package_contract_digest")
        .and_then(Value::as_str)
        .unwrap_or("")
        .to_owned()
}

fn construct_interfaces_json(interfaces: &[ConstructInterface]) -> Vec<Value> {
    interfaces
        .iter()
        .map(|interface| {
            json!({
                "kind": interface.kind.as_str(),
                "name": interface.name.as_deref(),
                "type": interface.type_ref.as_deref(),
                "phase": interface.phase.as_str(),
                "cardinality": interface.cardinality.as_str(),
            })
        })
        .collect()
}

fn core_capability_call_required_interfaces(capabilities: &[String]) -> Vec<Value> {
    capabilities
        .iter()
        .map(|capability| {
            json!({
                "kind": CONSTRUCT_INTERFACE_CAPABILITY,
                "name": capability,
                "type": null,
                "phase": CONSTRUCT_INTERFACE_PHASE_COMPILE_RUNTIME,
                "cardinality": CONSTRUCT_INTERFACE_CARDINALITY_EXACTLY_ONE,
            })
        })
        .collect()
}

fn core_capability_call_provided_interfaces(output_type: &str) -> Vec<Value> {
    vec![json!({
        "kind": CONSTRUCT_INTERFACE_EFFECT_HANDLE,
        "name": null,
        "type": output_type,
        "phase": CONSTRUCT_INTERFACE_PHASE_COMPILE_RUNTIME,
        "cardinality": CONSTRUCT_INTERFACE_CARDINALITY_EXACTLY_ONE,
    })]
}

fn core_effect_provided_interfaces(output_type: &str) -> Vec<Value> {
    core_capability_call_provided_interfaces(output_type)
}

fn platform_construct_catalog_json() -> Value {
    json!({
        "schema": "whipplescript.platform_construct_catalog.v0",
        "families": PLATFORM_CONSTRUCT_CATALOG
            .families
            .iter()
            .map(|family| {
                json!({
                    "id": family.id,
                    "description": family.description,
                })
            })
            .collect::<Vec<_>>(),
        "lowerings": PLATFORM_CONSTRUCT_CATALOG
            .lowerings
            .iter()
            .map(|lowering| {
                json!({
                    "id": lowering.id,
                    "compatible_families": lowering.compatible_families,
                    "package_authorable": lowering.package_authorable,
                    "required_scope": lowering.required_scope,
                    "target_capability": lowering.target_capability.as_str(),
                    "required_interfaces": lowering.required_interfaces,
                    "provided_interfaces": lowering.provided_interfaces,
                    "lifecycle_profiles": lowering.lifecycle_profiles,
                    "authority_profile": lowering.authority_profile.as_str(),
                    "static_guarantees": lowering.static_guarantees,
                })
            })
            .collect::<Vec<_>>(),
        "scopes": PLATFORM_CONSTRUCT_CATALOG.scopes,
        "field_kinds": PLATFORM_CONSTRUCT_CATALOG.field_kinds,
        "interface_kinds": PLATFORM_CONSTRUCT_CATALOG.interface_kinds,
        "interface_phases": PLATFORM_CONSTRUCT_CATALOG.interface_phases,
        "interface_cardinalities": PLATFORM_CONSTRUCT_CATALOG.interface_cardinalities,
        "reserved_keywords": PLATFORM_CONSTRUCT_CATALOG.reserved_keywords,
        "reserved_keyword_privileges": PLATFORM_CONSTRUCT_CATALOG
            .reserved_keyword_privileges
            .iter()
            .map(|privilege| {
                json!({
                    "keyword": privilege.keyword,
                    "library_id": privilege.library_id,
                    "construct_family": privilege.construct_family,
                    "scope": privilege.scope,
                    "lowering_target": privilege.lowering_target,
                })
            })
            .collect::<Vec<_>>(),
    })
}

fn construct_graph_json(
    path: &str,
    source: &str,
    ir: &IrProgram,
    registry: &ContractRegistry,
    package_lock: Option<&LoadedPackageLock>,
) -> Value {
    let package_lock_digest = package_lock_digest(package_lock);
    let package_contract_digest = package_contract_digest(package_lock, registry);
    construct_graph_json_with_digests(
        path,
        source,
        ir,
        registry,
        &package_lock_digest,
        &package_contract_digest,
    )
}

fn construct_graph_json_with_digests(
    path: &str,
    source: &str,
    ir: &IrProgram,
    registry: &ContractRegistry,
    package_lock_digest: &str,
    package_contract_digest: &str,
) -> Value {
    let source_digest = sha256_hex(source.as_bytes());
    let package_library_ids = package_library_ids(registry);
    let mut relevant_contract_ids = BTreeSet::new();

    for effect in ir
        .rules
        .iter()
        .flat_map(|rule| rule.metadata.effects.iter())
    {
        if effect.kind != IrEffectKind::CapabilityCall {
            continue;
        }
        for capability in &effect.required_capabilities {
            for contract in
                package_capability_contracts_for(registry, &package_library_ids, capability)
            {
                relevant_contract_ids.insert((contract.id.clone(), contract.version.clone()));
            }
        }
    }

    let relevant_contracts = registry
        .effect_contracts
        .iter()
        .filter(|contract| {
            relevant_contract_ids.contains(&(contract.id.clone(), contract.version.clone()))
        })
        .collect::<Vec<_>>();
    let mut contract_port_by_capability = BTreeMap::<String, (String, String)>::new();
    let mut nodes = Vec::new();
    let mut ports = Vec::new();
    let mut edges = Vec::new();
    let mut effect_dependencies = Vec::new();
    let mut derived_facts = Vec::new();
    let mut construct_effect_node_ids = BTreeMap::<(String, String), String>::new();

    for contract in &relevant_contracts {
        let node_id = construct_contract_node_id(contract);
        let produced_ports = contract
            .required_capabilities
            .iter()
            .map(|capability| construct_contract_capability_port_id(contract, capability))
            .collect::<Vec<_>>();
        nodes.push(json!({
            "node_id": node_id,
            "construct_id": contract.id.as_str(),
            "construct_family": "effect_contract",
            "lowering_class": "metadata",
            "lifecycle_profile": "none",
            "owner": contract.library_id.as_str(),
            "source_span": construct_graph_span(None, SourceSpan { start: 0, end: 0 }, Some("effect_contract")),
            "required_ports": [],
            "produced_ports": produced_ports,
            "declared_required_interfaces": [],
            "declared_provided_interfaces": [],
            "required_capabilities": [],
            "lowered_effect_capabilities": [],
            "lowering_output_kind": "contract_registry_entry",
            "allowed_core_object_kinds": [],
            "allowed_runtime_entrypoints": [],
        }));
        derived_facts.push(json!({
            "predicate": format!("accepted_effect_contract:{}", contract.id),
            "owner_subsystem": "package_lock",
            "input_refs": [node_id.as_str()],
            "diagnostic_span": construct_graph_span(None, SourceSpan { start: 0, end: 0 }, Some("effect_contract")),
        }));
        for capability in &contract.required_capabilities {
            let port_id = construct_contract_capability_port_id(contract, capability);
            ports.push(json!({
                "port_id": port_id,
                "owner_node_id": node_id,
                "direction": "produced",
                "kind": "Capability",
                "type": capability,
                "phase": "compile",
                "resource_identity": null,
                "contract_version": contract.version.as_str(),
                "cardinality": "exactly-one",
                "source_span": construct_graph_span(None, SourceSpan { start: 0, end: 0 }, Some("effect_contract")),
            }));
            contract_port_by_capability
                .entry(capability.clone())
                .or_insert((node_id.clone(), port_id));
        }
    }

    // A `signal {}` declaration is a typed schema only (provides `Signal<T>`,
    // emits no runtime object), so it carries no authority and lowers to no core
    // object. Like `class`/`enum`, it produces no construct-graph node; signal
    // admission is represented by `source` blocks below (spec/std-time.md,
    // spec/construct-lowering-preservation.md).

    for source in &ir.sources {
        let node_id = construct_source_node_id(&source.name);
        let span = construct_graph_span(Some(path), source.span, Some("source"));
        let (lowering, lifecycle, object_kind, entrypoint, output_kind) = if source.is_clock {
            (
                CLOCK_SOURCE_LOWERING_CLASS,
                "clock_source_template",
                "clock_source",
                "clock_source_template",
                "core.clock_source_template",
            )
        } else {
            (
                SIGNAL_SOURCE_LOWERING_CLASS,
                "signal_source_template",
                "signal_source",
                "signal_source_template",
                "core.signal_source_template",
            )
        };
        nodes.push(json!({
            "node_id": node_id,
            "construct_id": format!("core.{lowering}.{}", source.name),
            "construct_family": CONSTRUCT_FAMILY_SOURCE_DECLARATION,
            "lowering_class": lowering,
            "lifecycle_profile": lifecycle,
            "owner": "core",
            "source_span": span,
            "required_ports": [],
            "produced_ports": [],
            "declared_required_interfaces": [],
            "declared_provided_interfaces": [],
            "required_capabilities": [],
            "lowered_effect_capabilities": [],
            "lowering_output_kind": output_kind,
            "allowed_core_object_kinds": [object_kind],
            "allowed_runtime_entrypoints": [entrypoint],
        }));
        derived_facts.push(json!({
            "predicate": format!("lowering_output:{}:{output_kind}", source.name),
            "owner_subsystem": "compiler",
            "input_refs": [node_id.as_str()],
            "diagnostic_span": construct_graph_span(Some(path), source.span, Some("source")),
        }));
    }

    for assertion in &ir.assertions {
        let assertion_id = construct_assertion_id(assertion);
        let node_id = construct_assertion_node_id(&assertion_id);
        let span = construct_graph_span(Some(path), assertion.expr.span, Some("assertion"));
        nodes.push(json!({
            "node_id": node_id,
            "construct_id": format!("core.assertion.{}", assertion_id),
            "construct_family": CONSTRUCT_FAMILY_ASSERTION,
            "lowering_class": ASSERTION_LOWERING_CLASS,
            "lifecycle_profile": "assertion_check",
            "owner": "core",
            "source_span": span,
            "required_ports": [],
            "produced_ports": [],
            "declared_required_interfaces": [],
            "declared_provided_interfaces": [],
            "required_capabilities": [],
            "lowered_effect_capabilities": [],
            "lowering_output_kind": "core.assertion_check",
            "allowed_core_object_kinds": ["assertion"],
            "allowed_runtime_entrypoints": ["assertion_check"],
        }));
        derived_facts.push(json!({
            "predicate": format!("lowering_output:{}:core.assertion_check", assertion_id),
            "owner_subsystem": "compiler",
            "input_refs": [node_id.as_str()],
            "diagnostic_span": construct_graph_span(Some(path), assertion.expr.span, Some("assertion")),
        }));
    }

    for rule in &ir.rules {
        for (when_index, when) in rule.whens.iter().enumerate() {
            let node_id = construct_rule_node_id(rule, when_index);
            let rule_ref = construct_rule_ref(rule, when_index);
            let span = construct_graph_span(Some(path), when.span, Some("rule"));
            let mut allowed_core_object_kinds = vec!["rule"];
            let mut allowed_runtime_entrypoints = vec!["rule_template"];
            if !rule.metadata.fact_writes.is_empty() {
                allowed_core_object_kinds.push("fact");
                allowed_runtime_entrypoints.push("fact_record");
            }
            nodes.push(json!({
                "node_id": node_id,
                "construct_id": format!("core.rule.{rule_ref}"),
                "construct_family": CONSTRUCT_FAMILY_RULE,
                "lowering_class": RULE_TEMPLATE_LOWERING_CLASS,
                "lifecycle_profile": "rule_template",
                "owner": "core",
                "source_span": span,
                "required_ports": [],
                "produced_ports": [],
                "declared_required_interfaces": [],
                "declared_provided_interfaces": [],
                "required_capabilities": [],
                "lowered_effect_capabilities": [],
                "lowering_output_kind": "core.rule_template",
                "allowed_core_object_kinds": allowed_core_object_kinds,
                "allowed_runtime_entrypoints": allowed_runtime_entrypoints,
                "metadata": {
                    "rule_name": rule.name.as_str(),
                    "fact_writes": &rule.metadata.fact_writes,
                },
            }));
            derived_facts.push(json!({
                "predicate": format!("lowering_output:{rule_ref}:core.rule_template"),
                "owner_subsystem": "compiler",
                "input_refs": [node_id.as_str()],
                "diagnostic_span": construct_graph_span(Some(path), when.span, Some("rule")),
            }));
            if let Some(guard) = &when.guard {
                let when_ref = format!("when{when_index}");
                derived_facts.push(json!({
                    "predicate": format!("model_search.guard_source:{}:{when_ref}", rule.name),
                    "owner_subsystem": "compiler",
                    "input_refs": [
                        format!("rule:{}", rule.name),
                        format!("when:{when_index}"),
                        "kind:guard"
                    ],
                    "diagnostic_span": construct_graph_span(Some(path), guard.span, Some("guard")),
                }));
            }
        }
    }

    for rule in &ir.rules {
        for (branch_index, branch) in rule.metadata.terminal_branches.iter().enumerate() {
            let tag = branch.tag.as_deref().unwrap_or("_");
            let branch_ref = format!("branch{branch_index}");
            let guard_ref = if branch.guard.is_some() {
                "guarded"
            } else {
                "unguarded"
            };
            derived_facts.push(json!({
                "predicate": format!("model_search.terminal_branch_source:{}:{branch_ref}", rule.name),
                "owner_subsystem": "compiler",
                "input_refs": [
                    format!("rule:{}", rule.name),
                    format!("branch:{branch_index}"),
                    format!("tag:{tag}"),
                    format!("guard:{guard_ref}"),
                    "kind:terminal_branch"
                ],
                "diagnostic_span": construct_graph_span(Some(path), branch.pattern_span, Some("terminal_branch")),
            }));
        }
    }

    for rule in &ir.rules {
        let span = rule
            .whens
            .iter()
            .find_map(|when| when.guard.as_ref().map(|guard| guard.span))
            .or_else(|| rule.whens.first().map(|when| when.span))
            .unwrap_or(SourceSpan { start: 0, end: 0 });
        for (read_index, read) in rule.metadata.projection_reads.iter().enumerate() {
            let read_ref = construct_rule_projection_read_ref(rule, read_index);
            let node_id = construct_projection_read_node_id(&read_ref);
            let read_source = projection_read_source(read);
            nodes.push(json!({
                "node_id": node_id,
                "construct_id": format!("core.projection_read.{read_ref}"),
                "construct_family": CONSTRUCT_FAMILY_PROJECTION_READ,
                "lowering_class": PROJECTION_READ_LOWERING_CLASS,
                "lifecycle_profile": "none",
                "owner": "compiler",
                "source_span": construct_graph_span(Some(path), span, Some("projection_read")),
                "required_ports": [],
                "produced_ports": [],
                "declared_required_interfaces": [],
                "declared_provided_interfaces": [],
                "required_capabilities": [],
                "lowered_effect_capabilities": [],
                "lowering_output_kind": "checker.projection_read",
                "allowed_core_object_kinds": [],
                "allowed_runtime_entrypoints": [],
                "metadata": {
                    "owner_kind": "rule",
                    "owner_ref": rule.name.as_str(),
                    "read_kind": projection_read_kind(read),
                    "head": read.head.as_str(),
                    "guard": read.guard.as_deref(),
                    "source": read_source,
                },
            }));
            derived_facts.push(json!({
                "predicate": format!("projection_read:{read_ref}:{}", read_source),
                "owner_subsystem": "compiler",
                "input_refs": [node_id.as_str()],
                "diagnostic_span": construct_graph_span(Some(path), span, Some("projection_read")),
            }));
        }
    }

    for assertion in &ir.assertions {
        let assertion_id = construct_assertion_id(assertion);
        for (read_index, read) in assertion.projection_reads.iter().enumerate() {
            let read_ref = construct_assertion_projection_read_ref(&assertion_id, read_index);
            let node_id = construct_projection_read_node_id(&read_ref);
            let read_source = projection_read_source(read);
            nodes.push(json!({
                "node_id": node_id,
                "construct_id": format!("core.projection_read.{read_ref}"),
                "construct_family": CONSTRUCT_FAMILY_PROJECTION_READ,
                "lowering_class": PROJECTION_READ_LOWERING_CLASS,
                "lifecycle_profile": "none",
                "owner": "compiler",
                "source_span": construct_graph_span(Some(path), assertion.expr.span, Some("projection_read")),
                "required_ports": [],
                "produced_ports": [],
                "declared_required_interfaces": [],
                "declared_provided_interfaces": [],
                "required_capabilities": [],
                "lowered_effect_capabilities": [],
                "lowering_output_kind": "checker.projection_read",
                "allowed_core_object_kinds": [],
                "allowed_runtime_entrypoints": [],
                "metadata": {
                    "owner_kind": "assertion",
                    "owner_ref": assertion_id.as_str(),
                    "read_kind": projection_read_kind(read),
                    "head": read.head.as_str(),
                    "guard": read.guard.as_deref(),
                    "source": read_source,
                },
            }));
            derived_facts.push(json!({
                "predicate": format!("projection_read:{read_ref}:{}", read_source),
                "owner_subsystem": "compiler",
                "input_refs": [node_id.as_str()],
                "diagnostic_span": construct_graph_span(Some(path), assertion.expr.span, Some("projection_read")),
            }));
        }
    }

    for rule in &ir.rules {
        for effect in &rule.metadata.effects {
            if effect.kind != IrEffectKind::CapabilityCall {
                continue;
            }
            let matched_contracts = effect
                .required_capabilities
                .iter()
                .flat_map(|capability| {
                    package_capability_contracts_for(registry, &package_library_ids, capability)
                })
                .collect::<Vec<_>>();
            if matched_contracts.is_empty() {
                continue;
            }

            let node_id = construct_effect_node_id(rule, effect);
            construct_effect_node_ids
                .insert((rule.name.clone(), effect.id.clone()), node_id.clone());
            let required_ports = effect
                .required_capabilities
                .iter()
                .map(|capability| construct_effect_capability_port_id(&node_id, capability))
                .collect::<Vec<_>>();
            let effect_handle_port = construct_effect_handle_port_id(&node_id);
            let produced_ports = vec![effect_handle_port.clone()];
            let lifecycle_profile = if matched_contracts
                .iter()
                .any(|contract| contract.output_schema.is_some())
            {
                "typed_effect_graph"
            } else {
                "effect_graph"
            };
            let contract_version = matched_contracts
                .first()
                .map(|contract| contract.version.as_str())
                .unwrap_or("unknown");
            let resolved_construct = effect
                .construct_use
                .as_ref()
                .and_then(|construct_use| registry_construct_for_use(registry, construct_use));
            let output_type = resolved_construct
                .and_then(|form| {
                    form.provides
                        .iter()
                        .find(|interface| interface.kind == CONSTRUCT_INTERFACE_EFFECT_HANDLE)
                        .and_then(|interface| interface.type_ref.as_deref())
                })
                .or_else(|| {
                    matched_contracts
                        .iter()
                        .find_map(|contract| contract.output_schema.as_deref())
                })
                .unwrap_or("capability.call.output");
            let construct_id = resolved_construct
                .map(|form| form.id.as_str())
                .unwrap_or(CORE_CAPABILITY_CALL_CONSTRUCT_ID);
            let construct_family = resolved_construct
                .map(|form| form.construct_family.as_str())
                .or_else(|| {
                    effect
                        .construct_use
                        .as_ref()
                        .map(|form| form.construct_family.as_str())
                })
                .unwrap_or(CONSTRUCT_FAMILY_EFFECT_OPERATION);
            let lowering_class = resolved_construct
                .map(|form| form.lowering_target.as_str())
                .or_else(|| {
                    effect
                        .construct_use
                        .as_ref()
                        .map(|form| form.lowering_target.as_str())
                })
                .unwrap_or(CONSTRUCT_LOWERING_CAPABILITY_CALL);
            let owner = resolved_construct
                .map(|form| form.library_id.as_str())
                .or_else(|| {
                    matched_contracts
                        .first()
                        .map(|contract| contract.library_id.as_str())
                })
                .unwrap_or("unknown");
            let construct_name = effect
                .construct_use
                .as_ref()
                .map(|form| form.keyword.as_str())
                .unwrap_or("capability.call");
            let declared_required_interfaces = resolved_construct
                .map(|form| construct_interfaces_json(&form.requires))
                .unwrap_or_else(|| {
                    core_capability_call_required_interfaces(&effect.required_capabilities)
                });
            let declared_provided_interfaces = resolved_construct
                .map(|form| construct_interfaces_json(&form.provides))
                .unwrap_or_else(|| core_capability_call_provided_interfaces(output_type));

            nodes.push(json!({
                "node_id": node_id,
                "construct_id": construct_id,
                "construct_family": construct_family,
                "lowering_class": lowering_class,
                "lifecycle_profile": lifecycle_profile,
                "owner": owner,
                "source_span": construct_graph_span(Some(path), effect.span, Some(construct_name)),
                "required_ports": required_ports,
                "produced_ports": produced_ports,
                "declared_required_interfaces": declared_required_interfaces,
                "declared_provided_interfaces": declared_provided_interfaces,
                "required_capabilities": effect.required_capabilities,
                "lowered_effect_capabilities": effect.required_capabilities,
                "lowering_output_kind": "core.effect_graph_template",
                "allowed_core_object_kinds": ["effect"],
                "allowed_runtime_entrypoints": ["effect_graph_template"],
            }));
            ports.push(json!({
                "port_id": effect_handle_port,
                "owner_node_id": node_id,
                "direction": "produced",
                "kind": "EffectHandle",
                "type": output_type,
                "phase": "runtime",
                "resource_identity": null,
                "contract_version": contract_version,
                "cardinality": "exactly-one",
                "source_span": construct_graph_span(Some(path), effect.span, Some(construct_name)),
            }));
            derived_facts.push(json!({
                "predicate": format!("lowering_output:{}:core.effect_graph_template", effect.id),
                "owner_subsystem": "compiler",
                "input_refs": [node_id.as_str()],
                "diagnostic_span": construct_graph_span(Some(path), effect.span, Some(construct_name)),
            }));
            for capability in &effect.required_capabilities {
                let required_port_id = construct_effect_capability_port_id(&node_id, capability);
                ports.push(json!({
                    "port_id": required_port_id,
                    "owner_node_id": node_id,
                    "direction": "required",
                    "kind": "Capability",
                    "type": capability,
                    "phase": "compile",
                    "resource_identity": null,
                    "contract_version": contract_version,
                    "cardinality": "exactly-one",
                    "source_span": construct_graph_span(Some(path), effect.span, Some(construct_name)),
                }));
                derived_facts.push(json!({
                    "predicate": format!("lowered_effect_requires_capability:{}:{}", effect.id, capability),
                    "owner_subsystem": "compiler",
                    "input_refs": [node_id.as_str(), required_port_id.as_str()],
                    "diagnostic_span": construct_graph_span(Some(path), effect.span, Some(construct_name)),
                }));
                if let Some((provider_node_id, provided_port_id)) =
                    contract_port_by_capability.get(capability)
                {
                    edges.push(json!({
                        "required_port_id": required_port_id,
                        "provider_node_id": provider_node_id,
                        "provided_port_id": provided_port_id,
                        "order_index": null,
                        "resource_key": null,
                        "resolution_reason": "locked_effect_contract",
                        "evidence": [
                            node_id.as_str(),
                            capability.as_str(),
                            provider_node_id.as_str(),
                            provided_port_id.as_str()
                        ],
                    }));
                }
            }
        }
    }

    for rule in &ir.rules {
        for effect in &rule.metadata.effects {
            let effect_key = (rule.name.clone(), effect.id.clone());
            if construct_effect_node_ids.contains_key(&effect_key) {
                continue;
            }

            let effect_kind = effect.kind.as_str();
            let contract = registry
                .effect_contracts
                .iter()
                .find(|contract| contract.effect_kind == effect_kind);
            let node_id = construct_effect_node_id(rule, effect);
            construct_effect_node_ids.insert(effect_key, node_id.clone());
            let effect_handle_port = construct_effect_handle_port_id(&node_id);
            let produced_ports = vec![effect_handle_port.clone()];
            let output_type = contract
                .and_then(|contract| contract.output_schema.as_deref())
                .unwrap_or("effect.terminal")
                .to_owned();
            let lifecycle_profile = if contract
                .and_then(|contract| contract.output_schema.as_deref())
                .is_some()
            {
                "typed_effect_graph"
            } else {
                "effect_graph"
            };
            let contract_version = contract
                .map(|contract| contract.version.as_str())
                .unwrap_or("0.1.0");
            let owner = contract
                .map(|contract| contract.library_id.as_str())
                .unwrap_or("core");
            let construct_name = contract
                .and_then(|contract| contract.source_forms.first().map(String::as_str))
                .unwrap_or(effect_kind);
            let required_capabilities = contract
                .map(|contract| contract.required_capabilities.clone())
                .unwrap_or_else(|| effect.required_capabilities.clone());
            let is_schedule = effect.kind == IrEffectKind::TimerWait;
            let lowering_class = if is_schedule {
                SCHEDULE_LOWERING_CLASS
            } else {
                CORE_EFFECT_LOWERING_CLASS
            };
            let lifecycle_profile = if is_schedule {
                "schedule_template"
            } else {
                lifecycle_profile
            };
            let lowering_output_kind = if is_schedule {
                "core.schedule_template"
            } else {
                "core.effect_graph_template"
            };
            let allowed_core_object_kinds = if is_schedule {
                vec!["schedule"]
            } else {
                vec!["effect"]
            };
            let allowed_runtime_entrypoints = if is_schedule {
                vec!["schedule_template"]
            } else {
                vec!["effect_graph_template"]
            };

            nodes.push(json!({
                "node_id": node_id,
                "construct_id": format!("core.effect.{effect_kind}"),
                "construct_family": CONSTRUCT_FAMILY_EFFECT_OPERATION,
                "lowering_class": lowering_class,
                "lifecycle_profile": lifecycle_profile,
                "owner": owner,
                "source_span": construct_graph_span(Some(path), effect.span, Some(construct_name)),
                "required_ports": [],
                "produced_ports": produced_ports,
                "declared_required_interfaces": [],
                "declared_provided_interfaces": core_effect_provided_interfaces(&output_type),
                "required_capabilities": required_capabilities.clone(),
                "lowered_effect_capabilities": required_capabilities,
                "lowering_output_kind": lowering_output_kind,
                "allowed_core_object_kinds": allowed_core_object_kinds,
                "allowed_runtime_entrypoints": allowed_runtime_entrypoints,
            }));
            ports.push(json!({
                "port_id": effect_handle_port,
                "owner_node_id": node_id,
                "direction": "produced",
                "kind": "EffectHandle",
                "type": output_type,
                "phase": "runtime",
                "resource_identity": null,
                "contract_version": contract_version,
                "cardinality": "exactly-one",
                "source_span": construct_graph_span(Some(path), effect.span, Some(construct_name)),
            }));
            derived_facts.push(json!({
                "predicate": format!("lowering_output:{}:{lowering_output_kind}", effect.id),
                "owner_subsystem": "compiler",
                "input_refs": [node_id.as_str()],
                "diagnostic_span": construct_graph_span(Some(path), effect.span, Some(construct_name)),
            }));
        }
    }

    for rule in &ir.rules {
        for dependency in &rule.metadata.dependencies {
            let Some(upstream_node_id) =
                construct_effect_node_ids.get(&(rule.name.clone(), dependency.upstream.clone()))
            else {
                continue;
            };
            let Some(downstream_node_id) =
                construct_effect_node_ids.get(&(rule.name.clone(), dependency.downstream.clone()))
            else {
                continue;
            };
            let predicate = dependency_predicate_str(&dependency.predicate);
            let dependency_ref = construct_effect_dependency_ref(rule, dependency);
            let source_span = construct_graph_span(
                Some(path),
                dependency_source_span(source, &dependency.upstream, predicate),
                Some("after"),
            );
            effect_dependencies.push(json!({
                "dependency_ref": dependency_ref,
                "rule_name": rule.name.as_str(),
                "upstream_node_id": upstream_node_id,
                "predicate": predicate,
                "downstream_node_id": downstream_node_id,
                "source_span": source_span,
                "evidence": [
                    rule.name.as_str(),
                    upstream_node_id.as_str(),
                    predicate,
                    downstream_node_id.as_str()
                ],
            }));
            derived_facts.push(json!({
                "predicate": format!("effect_dependency:{}:{}:{}", upstream_node_id, predicate, downstream_node_id),
                "owner_subsystem": "compiler",
                "input_refs": [dependency_ref.as_str(), upstream_node_id.as_str(), downstream_node_id.as_str()],
                "diagnostic_span": construct_graph_span(
                    Some(path),
                    dependency_source_span(source, &dependency.upstream, predicate),
                    Some("after")
                ),
            }));
        }
    }

    let mut graph = json!({
        "schema": "whipplescript.construct_graph.v0",
        "graph_id": format!("construct_graph:{source_digest}"),
        "platform_version": whipplescript_core::version(),
        "package_lock_digest": package_lock_digest,
        "package_contract_digest": package_contract_digest,
        "source_digest": source_digest,
        "nodes": nodes,
        "ports": ports,
        "edges": edges,
        "effect_dependencies": effect_dependencies,
        "derived_facts": derived_facts,
        "diagnostics": [],
    });
    let validation = validate_construct_graph_artifact(&graph);
    if let Some(object) = graph.as_object_mut() {
        if let Some(existing_facts) = object
            .get_mut("derived_facts")
            .and_then(Value::as_array_mut)
        {
            existing_facts.extend(validation.derived_facts);
        }
        object.insert(
            "diagnostics".to_owned(),
            Value::Array(validation.diagnostics),
        );
    }
    graph
}

#[derive(Default)]
struct ConstructGraphValidation {
    diagnostics: Vec<Value>,
    derived_facts: Vec<Value>,
}

fn lowered_ir_report_json(
    _path: &str,
    source: &str,
    ir: &IrProgram,
    construct_graph: &Value,
    package_lock: Option<&LoadedPackageLock>,
) -> Value {
    let package_lock_digest = package_lock_digest(package_lock);
    lowered_ir_report_json_with_digest(source, ir, construct_graph, &package_lock_digest)
}

fn lowered_ir_report_json_with_digest(
    source: &str,
    ir: &IrProgram,
    construct_graph: &Value,
    package_lock_digest: &str,
) -> Value {
    let source_digest = sha256_hex(source.as_bytes());
    let graph_id = construct_graph
        .get("graph_id")
        .and_then(Value::as_str)
        .unwrap_or("construct_graph:unknown");
    let accepted_program_digest =
        sha256_hex(format!("{graph_id}\n{}", ir.to_snapshot()).as_bytes());
    let empty = Vec::new();
    let nodes = construct_graph
        .get("nodes")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let ports = construct_graph
        .get("ports")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let edges = construct_graph
        .get("edges")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let effect_dependencies = construct_graph
        .get("effect_dependencies")
        .and_then(Value::as_array)
        .unwrap_or(&empty);
    let ports_by_id = ports
        .iter()
        .filter_map(|port| {
            port.get("port_id")
                .and_then(Value::as_str)
                .map(|port_id| (port_id.to_owned(), port))
        })
        .collect::<BTreeMap<_, _>>();

    let mut node_lowerings = Vec::new();
    let mut edge_lowerings = Vec::new();
    let mut dependency_lowerings = Vec::new();
    let mut core_objects = Vec::new();
    let rule_entrypoint_refs = construct_rule_entrypoint_refs_by_node_id(ir);
    let rule_fact_output_refs = construct_rule_fact_output_refs_by_node_id(ir);

    for node in nodes {
        let Some(node_id) = node.get("node_id").and_then(Value::as_str) else {
            continue;
        };
        let lowering_class = node
            .get("lowering_class")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        let required_ports = construct_graph_string_array(node, "required_ports");
        let produced_ports = construct_graph_string_array(node, "produced_ports");
        let mut graph_port_ids = required_ports.clone();
        graph_port_ids.extend(produced_ports.clone());
        let preserved_resource_refs =
            lowered_ir_port_field_refs(&graph_port_ids, &ports_by_id, "resource_identity");
        let preserved_version_refs =
            lowered_ir_port_field_refs(&graph_port_ids, &ports_by_id, "contract_version");
        let preserved_capability_refs = lowered_ir_node_capability_refs(node);
        let preserved_provenance_refs = vec![node_id.to_owned()];
        let preserved_terminal_binding_refs = produced_ports.clone();
        let mut produced_core_object_refs = Vec::new();

        if node.get("construct_family").and_then(Value::as_str)
            == Some(CONSTRUCT_FAMILY_EFFECT_OPERATION)
            && node.get("lowering_output_kind").and_then(Value::as_str)
                == Some("core.effect_graph_template")
        {
            let object_id = lowered_ir_node_core_object_id(node_id, "effect");
            produced_core_object_refs.push(object_id.clone());
            core_objects.push(json!({
                "object_kind": "effect",
                "object_id": object_id,
                "owner_kind": "node",
                "owner_ref": node_id,
                "runtime_entrypoint": "effect_graph_template",
                "source_span": construct_graph_span_from(node),
                "resource_refs": preserved_resource_refs.clone(),
                "capability_refs": preserved_capability_refs.clone(),
                "version_refs": preserved_version_refs.clone(),
            }));
        }

        if node.get("construct_family").and_then(Value::as_str)
            == Some(CONSTRUCT_FAMILY_EFFECT_OPERATION)
            && node.get("lowering_output_kind").and_then(Value::as_str)
                == Some("core.schedule_template")
        {
            let object_id = lowered_ir_node_core_object_id(node_id, "schedule");
            produced_core_object_refs.push(object_id.clone());
            core_objects.push(json!({
                "object_kind": "schedule",
                "object_id": object_id,
                "owner_kind": "node",
                "owner_ref": node_id,
                "runtime_entrypoint": "schedule_template",
                "entrypoint_refs": {
                    "schedule": node_id,
                },
                "source_span": construct_graph_span_from(node),
                "resource_refs": preserved_resource_refs.clone(),
                "capability_refs": preserved_capability_refs.clone(),
                "version_refs": preserved_version_refs.clone(),
            }));
        }

        if node.get("construct_family").and_then(Value::as_str)
            == Some(CONSTRUCT_FAMILY_SOURCE_DECLARATION)
        {
            let output_kind = node
                .get("lowering_output_kind")
                .and_then(Value::as_str)
                .unwrap_or_default();
            let (object_kind, runtime_entrypoint) = if output_kind == "core.clock_source_template" {
                ("clock_source", "clock_source_template")
            } else {
                ("signal_source", "signal_source_template")
            };
            let object_id = lowered_ir_node_core_object_id(node_id, object_kind);
            let emitted_signal = source_emitted_signal_by_node_id(ir, node_id).unwrap_or(node_id);
            produced_core_object_refs.push(object_id.clone());
            core_objects.push(json!({
                "object_kind": object_kind,
                "object_id": object_id,
                "owner_kind": "node",
                "owner_ref": node_id,
                "runtime_entrypoint": runtime_entrypoint,
                "entrypoint_refs": {
                    "event": emitted_signal,
                },
                "source_span": construct_graph_span_from(node),
                "resource_refs": preserved_resource_refs.clone(),
                "capability_refs": preserved_capability_refs.clone(),
                "version_refs": preserved_version_refs.clone(),
            }));
        }

        if node.get("construct_family").and_then(Value::as_str) == Some(CONSTRUCT_FAMILY_ASSERTION)
            && node.get("lowering_output_kind").and_then(Value::as_str)
                == Some("core.assertion_check")
        {
            let object_id = lowered_ir_node_core_object_id(node_id, "assertion");
            let assertion_id = construct_assertion_id_from_node_id(node_id).unwrap_or(node_id);
            produced_core_object_refs.push(object_id.clone());
            core_objects.push(json!({
                "object_kind": "assertion",
                "object_id": object_id,
                "owner_kind": "node",
                "owner_ref": node_id,
                "runtime_entrypoint": "assertion_check",
                "entrypoint_refs": {
                    "assertion": assertion_id,
                },
                "source_span": construct_graph_span_from(node),
                "resource_refs": preserved_resource_refs.clone(),
                "capability_refs": preserved_capability_refs.clone(),
                "version_refs": preserved_version_refs.clone(),
            }));
        }

        if node.get("construct_family").and_then(Value::as_str) == Some(CONSTRUCT_FAMILY_RULE)
            && node.get("lowering_output_kind").and_then(Value::as_str)
                == Some("core.rule_template")
        {
            let object_id = lowered_ir_node_core_object_id(node_id, "rule");
            let (rule_ref, fact_ref, graph_ref) = rule_entrypoint_refs
                .get(node_id)
                .cloned()
                .unwrap_or_else(|| {
                    (
                        node_id.to_owned(),
                        format!("{node_id}:fact"),
                        format!("{node_id}:graph"),
                    )
                });
            produced_core_object_refs.push(object_id.clone());
            core_objects.push(json!({
                "object_kind": "rule",
                "object_id": object_id,
                "owner_kind": "node",
                "owner_ref": node_id,
                "runtime_entrypoint": "rule_template",
                "entrypoint_refs": {
                    "rule": rule_ref,
                    "fact": fact_ref,
                    "graph": graph_ref,
                },
                "source_span": construct_graph_span_from(node),
                "resource_refs": preserved_resource_refs.clone(),
                "capability_refs": preserved_capability_refs.clone(),
                "version_refs": preserved_version_refs.clone(),
            }));
            for fact_ref in rule_fact_output_refs.get(node_id).into_iter().flatten() {
                let object_id = lowered_ir_node_fact_core_object_id(node_id, fact_ref);
                produced_core_object_refs.push(object_id.clone());
                core_objects.push(json!({
                    "object_kind": "fact",
                    "object_id": object_id,
                    "owner_kind": "node",
                    "owner_ref": node_id,
                    "runtime_entrypoint": "fact_record",
                    "entrypoint_refs": {
                        "fact": fact_ref,
                        "schema": construct_fact_schema_ref(fact_ref),
                    },
                    "source_span": construct_graph_span_from(node),
                    "resource_refs": [],
                    "capability_refs": [],
                    "version_refs": preserved_version_refs.clone(),
                }));
            }
        }

        node_lowerings.push(json!({
            "node_id": node_id,
            "lowering_class": lowering_class,
            "produced_core_object_refs": produced_core_object_refs,
            "preserved_source_span_refs": [node_id],
            "preserved_resource_refs": lowered_ir_port_field_refs(&graph_port_ids, &ports_by_id, "resource_identity"),
            "preserved_capability_refs": lowered_ir_node_capability_refs(node),
            "preserved_version_refs": lowered_ir_port_field_refs(&graph_port_ids, &ports_by_id, "contract_version"),
            "preserved_cardinality_refs": lowered_ir_port_field_refs(&graph_port_ids, &ports_by_id, "cardinality"),
            "preserved_provenance_refs": preserved_provenance_refs,
            "preserved_terminal_binding_refs": preserved_terminal_binding_refs,
        }));
    }

    for edge in edges {
        let Some(required_port_id) = edge.get("required_port_id").and_then(Value::as_str) else {
            continue;
        };
        let Some(provided_port_id) = edge.get("provided_port_id").and_then(Value::as_str) else {
            continue;
        };
        let mut edge_port_ids = vec![required_port_id.to_owned(), provided_port_id.to_owned()];
        edge_port_ids.sort();
        edge_port_ids.dedup();
        let preserved_capability_refs = edge_port_ids
            .iter()
            .filter_map(|port_id| ports_by_id.get(port_id))
            .filter(|port| port.get("kind").and_then(Value::as_str) == Some("Capability"))
            .filter_map(|port| port.get("type").and_then(Value::as_str))
            .map(str::to_owned)
            .collect::<BTreeSet<_>>()
            .into_iter()
            .collect::<Vec<_>>();

        edge_lowerings.push(json!({
            "required_port_id": required_port_id,
            "provided_port_id": provided_port_id,
            "core_relation_ref": lowered_ir_edge_relation_id(required_port_id, provided_port_id),
            "produced_core_object_refs": [],
            "preserved_type_refs": lowered_ir_port_field_refs(&edge_port_ids, &ports_by_id, "type"),
            "preserved_resource_refs": lowered_ir_port_field_refs(&edge_port_ids, &ports_by_id, "resource_identity"),
            "preserved_capability_refs": preserved_capability_refs,
            "preserved_version_refs": lowered_ir_port_field_refs(&edge_port_ids, &ports_by_id, "contract_version"),
            "preserved_span_refs": edge_port_ids,
            "preserved_cardinality_refs": lowered_ir_port_field_refs(&[required_port_id.to_owned()], &ports_by_id, "cardinality"),
            "preserved_provenance_refs": [construct_graph_edge_ref(edge)],
        }));
    }

    for dependency in effect_dependencies {
        let Some(dependency_ref) = dependency.get("dependency_ref").and_then(Value::as_str) else {
            continue;
        };
        let Some(upstream_node_id) = dependency.get("upstream_node_id").and_then(Value::as_str)
        else {
            continue;
        };
        let Some(predicate) = dependency.get("predicate").and_then(Value::as_str) else {
            continue;
        };
        let Some(downstream_node_id) = dependency.get("downstream_node_id").and_then(Value::as_str)
        else {
            continue;
        };
        let object_id = lowered_ir_dependency_core_object_id(dependency_ref);
        dependency_lowerings.push(json!({
            "dependency_ref": dependency_ref,
            "produced_core_object_refs": [object_id.as_str()],
            "preserved_effect_refs": [upstream_node_id, downstream_node_id],
            "preserved_predicate": predicate,
            "preserved_span_refs": [dependency_ref],
            "preserved_provenance_refs": construct_graph_string_array(dependency, "evidence"),
        }));
        core_objects.push(json!({
            "object_kind": "dependency",
            "object_id": object_id,
            "owner_kind": "dependency",
            "owner_ref": dependency_ref,
            "runtime_entrypoint": "effect_dependency_template",
            "entrypoint_refs": {
                "upstream_effect": upstream_node_id,
                "predicate": predicate,
                "downstream_effect": downstream_node_id,
            },
            "source_span": construct_graph_span_from(dependency),
            "resource_refs": [],
            "capability_refs": [],
            "version_refs": [],
        }));
    }

    let mut report = json!({
        "schema": "whipplescript.lowered_ir_report.v0",
        "graph_id": graph_id,
        "accepted_program_digest": accepted_program_digest,
        "lowerer_version": format!("whipplescript:{}", whipplescript_core::version()),
        "package_lock_digest": package_lock_digest,
        "source_digest": source_digest,
        "node_lowerings": node_lowerings,
        "edge_lowerings": edge_lowerings,
        "dependency_lowerings": dependency_lowerings,
        "core_objects": core_objects,
        "derived_facts": [],
        "diagnostics": [],
    });
    let validation = validate_lowered_ir_artifact(&report, construct_graph);
    if let Some(object) = report.as_object_mut() {
        object.insert(
            "derived_facts".to_owned(),
            Value::Array(validation.derived_facts),
        );
        object.insert(
            "diagnostics".to_owned(),
            Value::Array(validation.diagnostics),
        );
    }
    report
}

#[derive(Default)]
struct LoweredIrValidation {
    diagnostics: Vec<Value>,
    derived_facts: Vec<Value>,
}

#[cfg(test)]
fn validate_lowered_ir_report(report: &Value, construct_graph: &Value) -> Vec<Value> {
    validate_lowered_ir_artifact(report, construct_graph).diagnostics
}

