fn lowered_ir_core_object_entrypoint_refs(
    graph_id: &str,
    object_id: &str,
    object: &Value,
    object_kind: &str,
    runtime_entrypoint: &str,
) -> Vec<String> {
    let mut refs = vec![
        graph_id.to_owned(),
        object_id.to_owned(),
        object_kind.to_owned(),
        runtime_entrypoint.to_owned(),
    ];
    if let Some(entrypoint_refs) = object.get("entrypoint_refs").and_then(Value::as_object) {
        for (key, value) in entrypoint_refs {
            if let Some(value) = value.as_str() {
                refs.push(format!("{object_id}#entrypoint_refs.{key}:{value}"));
            }
        }
    }
    refs
}

fn lowered_ir_optional_string_ref(value: &Value, key: &str) -> Vec<String> {
    value
        .get(key)
        .and_then(Value::as_str)
        .map(|value| vec![value.to_owned()])
        .unwrap_or_default()
}

fn validate_lowered_ir_report_identity(
    report: &Value,
    construct_graph: &Value,
    diagnostics: &mut Vec<Value>,
) {
    for (field, code) in [
        ("graph_id", "lowered_ir.graph_id_mismatch"),
        ("source_digest", "lowered_ir.source_digest_mismatch"),
        (
            "package_lock_digest",
            "lowered_ir.package_lock_digest_mismatch",
        ),
    ] {
        let report_value = report.get(field).and_then(Value::as_str);
        let graph_value = construct_graph.get(field).and_then(Value::as_str);
        if report_value == graph_value && report_value.is_some() {
            continue;
        }
        diagnostics.push(lowered_ir_diagnostic(
            code,
            format!(
                "lowered IR report `{field}` {:?} does not match construct graph `{field}` {:?}",
                report_value.unwrap_or("<missing>"),
                graph_value.unwrap_or("<missing>")
            ),
            json!({"fields": [field]}),
        ));
    }
}

fn validate_lowered_ir_required_string_array_field(
    owner_kind: &str,
    owner_id: &str,
    value: &Value,
    field: &str,
    diagnostics: &mut Vec<Value>,
    refs: Value,
) {
    let Some(array) = value.get(field) else {
        diagnostics.push(lowered_ir_diagnostic(
            &format!("lowered_ir.{owner_kind}.preservation_field_missing"),
            format!("{owner_kind} lowering `{owner_id}` is missing `{field}`"),
            refs,
        ));
        return;
    };
    let Some(items) = array.as_array() else {
        diagnostics.push(lowered_ir_diagnostic(
            &format!("lowered_ir.{owner_kind}.preservation_field_invalid"),
            format!("{owner_kind} lowering `{owner_id}` field `{field}` must be an array"),
            refs,
        ));
        return;
    };
    if items
        .iter()
        .any(|item| item.as_str().is_none_or(str::is_empty))
    {
        diagnostics.push(lowered_ir_diagnostic(
            &format!("lowered_ir.{owner_kind}.preservation_field_invalid"),
            format!(
                "{owner_kind} lowering `{owner_id}` field `{field}` must contain only non-empty strings"
            ),
            refs,
        ));
        return;
    }
    let mut seen = BTreeSet::new();
    for item in items {
        let Some(item) = item.as_str() else {
            continue;
        };
        if !seen.insert(item) {
            diagnostics.push(lowered_ir_diagnostic(
                &format!("lowered_ir.{owner_kind}.preservation_field_duplicate"),
                format!(
                    "{owner_kind} lowering `{owner_id}` field `{field}` contains duplicate ref `{item}`"
                ),
                refs,
            ));
            return;
        }
    }
}

fn validate_lowered_ir_core_object_metadata_array_field(
    object_id: &str,
    value: &Value,
    field: &str,
    diagnostics: &mut Vec<Value>,
    refs: Value,
) {
    let Some(array) = value.get(field) else {
        return;
    };
    let Some(items) = array.as_array() else {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.metadata_field_invalid",
            format!("core object `{object_id}` field `{field}` must be an array"),
            refs,
        ));
        return;
    };
    if items
        .iter()
        .any(|item| item.as_str().is_none_or(str::is_empty))
    {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.metadata_field_invalid",
            format!(
                "core object `{object_id}` field `{field}` must contain only non-empty strings"
            ),
            refs,
        ));
        return;
    }
    let mut seen = BTreeSet::new();
    for item in items {
        let Some(item) = item.as_str() else {
            continue;
        };
        if !seen.insert(item) {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.core_object.metadata_field_duplicate",
                format!(
                    "core object `{object_id}` field `{field}` contains duplicate ref `{item}`"
                ),
                refs,
            ));
            return;
        }
    }
}

fn validate_lowered_ir_core_object_kind_and_entrypoint(
    object: &Value,
    object_id: &str,
    diagnostics: &mut Vec<Value>,
) {
    let Some(object_kind) = object.get("object_kind").and_then(Value::as_str) else {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.kind_missing",
            format!("core object `{object_id}` is missing object_kind"),
            json!({"core_objects": [object_id]}),
        ));
        return;
    };
    if lowered_ir_forbidden_runtime_object_kind(object_kind) {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.runtime_state_materialized",
            format!("core object `{object_id}` materializes runtime-owned `{object_kind}` state"),
            json!({"core_objects": [object_id]}),
        ));
        return;
    }
    let Some(expected_entrypoint) = lowered_ir_expected_runtime_entrypoint(object_kind) else {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.kind_unknown",
            format!("core object `{object_id}` has unknown object kind `{object_kind}`"),
            json!({"core_objects": [object_id]}),
        ));
        return;
    };
    let Some(runtime_entrypoint) = object.get("runtime_entrypoint").and_then(Value::as_str) else {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.runtime_entrypoint_missing",
            format!("core object `{object_id}` is missing runtime_entrypoint"),
            json!({"core_objects": [object_id]}),
        ));
        return;
    };
    if lowered_ir_forbidden_runtime_entrypoint(runtime_entrypoint) {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.runtime_state_materialized",
            format!(
                "core object `{object_id}` materializes runtime-owned `{runtime_entrypoint}` entrypoint"
            ),
            json!({"core_objects": [object_id]}),
        ));
        return;
    }
    if runtime_entrypoint != expected_entrypoint {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.runtime_entrypoint_mismatch",
            format!(
                "core object `{object_id}` kind `{object_kind}` must use `{expected_entrypoint}`, got `{runtime_entrypoint}`"
            ),
            json!({"core_objects": [object_id]}),
        ));
    }
    if !lowered_ir_current_core_object_kind_supported(object_kind) {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.unsupported_kind",
            format!(
                "core object `{object_id}` kind `{object_kind}` is known but not admitted by the current executable lowering/runtime handoff slice"
            ),
            json!({"core_objects": [object_id]}),
        ));
    }
    if !lowered_ir_current_runtime_entrypoint_supported(runtime_entrypoint) {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.runtime_entrypoint_unsupported",
            format!(
                "core object `{object_id}` runtime entrypoint `{runtime_entrypoint}` is known but not admitted by the current executable lowering/runtime handoff slice"
            ),
            json!({"core_objects": [object_id]}),
        ));
    }
    if object_kind == "dependency" {
        if object.get("owner_kind").and_then(Value::as_str) != Some("dependency") {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.core_object.dependency_owner_kind",
                format!("dependency core object `{object_id}` must be owned by a dependency"),
                json!({"core_objects": [object_id]}),
            ));
        }
        validate_lowered_ir_dependency_entrypoint_refs(object, object_id, diagnostics);
    } else if object_kind == "fact" {
        validate_lowered_ir_fact_entrypoint_refs(object, object_id, diagnostics);
    } else if object_kind == "event" {
        validate_lowered_ir_event_entrypoint_refs(object, object_id, diagnostics);
    } else if object_kind == "signal_source" || object_kind == "clock_source" {
        validate_lowered_ir_signal_source_entrypoint_refs(object, object_id, diagnostics);
    } else if object_kind == "schedule" {
        validate_lowered_ir_schedule_entrypoint_refs(object, object_id, diagnostics);
    } else if object_kind == "rule" {
        validate_lowered_ir_rule_entrypoint_refs(object, object_id, diagnostics);
    } else if object_kind == "projection" {
        validate_lowered_ir_projection_entrypoint_refs(object, object_id, diagnostics);
    } else if object_kind == "assertion" {
        validate_lowered_ir_assertion_entrypoint_refs(object, object_id, diagnostics);
    } else if object_kind == "diagnostic" {
        validate_lowered_ir_diagnostic_entrypoint_refs(object, object_id, diagnostics);
    }
}

fn lowered_ir_current_core_object_kind_supported(object_kind: &str) -> bool {
    matches!(
        object_kind,
        "fact"
            | "event"
            | "effect"
            | "signal_source"
            | "clock_source"
            | "schedule"
            | "rule"
            | "dependency"
            | "projection"
            | "assertion"
            | "diagnostic"
    )
}

fn lowered_ir_current_runtime_entrypoint_supported(runtime_entrypoint: &str) -> bool {
    matches!(
        runtime_entrypoint,
        "fact_record"
            | "event_record"
            | "effect_graph_template"
            | "signal_source_template"
            | "clock_source_template"
            | "schedule_template"
            | "rule_template"
            | "effect_dependency_template"
            | "event_projection"
            | "assertion_check"
            | "diagnostic_record"
    )
}

fn lowered_ir_known_runtime_entrypoint(runtime_entrypoint: &str) -> bool {
    matches!(
        runtime_entrypoint,
        "fact_record"
            | "event_record"
            | "signal_source_template"
            | "clock_source_template"
            | "schedule_template"
            | "effect_graph_template"
            | "rule_template"
            | "effect_dependency_template"
            | "event_projection"
            | "assertion_check"
            | "diagnostic_record"
    )
}

fn lowered_ir_expected_runtime_entrypoint(object_kind: &str) -> Option<&'static str> {
    match object_kind {
        "fact" => Some("fact_record"),
        "event" => Some("event_record"),
        "signal_source" => Some("signal_source_template"),
        "clock_source" => Some("clock_source_template"),
        "schedule" => Some("schedule_template"),
        "effect" => Some("effect_graph_template"),
        "rule" => Some("rule_template"),
        "dependency" => Some("effect_dependency_template"),
        "projection" => Some("event_projection"),
        "assertion" => Some("assertion_check"),
        "diagnostic" => Some("diagnostic_record"),
        _ => None,
    }
}

fn validate_lowered_ir_fact_entrypoint_refs(
    object: &Value,
    object_id: &str,
    diagnostics: &mut Vec<Value>,
) {
    let Some(refs) = object.get("entrypoint_refs").and_then(Value::as_object) else {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.entrypoint_refs_missing",
            format!("fact core object `{object_id}` is missing entrypoint_refs"),
            json!({"core_objects": [object_id]}),
        ));
        return;
    };
    for key in ["fact", "schema"] {
        if refs
            .get(key)
            .and_then(Value::as_str)
            .is_none_or(str::is_empty)
        {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.core_object.entrypoint_ref_missing",
                format!("fact core object `{object_id}` is missing `{key}`"),
                json!({"core_objects": [object_id]}),
            ));
        }
    }
}

fn validate_lowered_ir_dependency_entrypoint_refs(
    object: &Value,
    object_id: &str,
    diagnostics: &mut Vec<Value>,
) {
    let Some(refs) = object.get("entrypoint_refs").and_then(Value::as_object) else {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.entrypoint_refs_missing",
            format!("dependency core object `{object_id}` is missing entrypoint_refs"),
            json!({"core_objects": [object_id]}),
        ));
        return;
    };
    for key in ["upstream_effect", "downstream_effect"] {
        if refs
            .get(key)
            .and_then(Value::as_str)
            .is_none_or(str::is_empty)
        {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.core_object.entrypoint_ref_missing",
                format!("dependency core object `{object_id}` is missing `{key}`"),
                json!({"core_objects": [object_id]}),
            ));
        }
    }
    match refs.get("predicate").and_then(Value::as_str) {
        Some("succeeds" | "fails" | "completes") => {}
        Some(predicate) => diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.dependency_predicate_unknown",
            format!("dependency core object `{object_id}` has unknown predicate `{predicate}`"),
            json!({"core_objects": [object_id]}),
        )),
        None => diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.entrypoint_ref_missing",
            format!("dependency core object `{object_id}` is missing `predicate`"),
            json!({"core_objects": [object_id]}),
        )),
    }
}

fn validate_lowered_ir_required_entrypoint_refs(
    object: &Value,
    object_id: &str,
    object_kind: &str,
    keys: &[&str],
    diagnostics: &mut Vec<Value>,
) {
    let Some(refs) = object.get("entrypoint_refs").and_then(Value::as_object) else {
        diagnostics.push(lowered_ir_diagnostic(
            "lowered_ir.core_object.entrypoint_refs_missing",
            format!("{object_kind} core object `{object_id}` is missing entrypoint_refs"),
            json!({"core_objects": [object_id]}),
        ));
        return;
    };
    for key in keys {
        if refs
            .get(*key)
            .and_then(Value::as_str)
            .is_none_or(str::is_empty)
        {
            diagnostics.push(lowered_ir_diagnostic(
                "lowered_ir.core_object.entrypoint_ref_missing",
                format!("{object_kind} core object `{object_id}` is missing `{key}`"),
                json!({"core_objects": [object_id]}),
            ));
        }
    }
}

