    "usage: whip [--json] branch <create|fork|list|show|status|write|read|ls|remove|cut|probe|merge|restore|discard|ops|bind|reconcile> ...\n\
  whip branch create <branch> [--name <label>] [--from <parent>]\n\
  whip branch fork <branch> --from <parent> [--at-cut <cut>] [--name <label>]\n\
  whip branch list [--all]\n\
  whip branch show <branch>\n\
  whip branch status <branch>\n\
  whip branch write <branch> <path> --body <text>\n\
  whip branch read <branch> <path>\n\
  whip branch ls <branch>\n\
  whip branch remove <branch> <path>\n\
  whip branch cut <branch>\n\
  whip branch diff <branch> [--against <branch-or-cut>] [--context <n>]\n\
  whip branch probe <branch>\n\
  whip branch merge <branch>\n\
  whip branch restore <branch> <cut>\n\
  whip branch attribution <branch>\n\
  whip branch log <branch> [--limit <n>]\n\
  whip branch bisect <branch> --good <cut> --bad <cut> --run <command>\n\
  whip branch select <branch> <expr>\n\
  whip branch undo <branch> <expr> [--apply]\n\
  whip branch transport <branch> <expr> --onto <target> [--apply]\n\
  whip branch adopt-only <branch> <expr> [--apply]\n\
  whip branch conflicts <branch>\n\
  whip branch resolve <branch> <path> <--ours|--theirs|--body <text>>\n\
  whip branch discard <branch>\n\
  whip branch ops [--limit <n>]\n\
  whip branch undo-op [<op-id>]\n\
  whip branch export <branch> [--out <file>] [--delta-have <ids-file>]\n\
  whip branch import <file>\n\
  whip branch digest <branch>\n\
  whip branch have <ids-file>\n\
  whip branch erase <branch> <path>\n\
  whip branch bind <branch> <instance>\n\
  whip branch reconcile\n\
  whip branch reconcile-list";

const STREAM_USAGE: &str =
    "usage: whip [--json] stream <create|join|leave|archive|promote|list|show> ...\n\
  whip stream create <stream> [--name <label>]\n\
  whip stream join <stream> <branch>\n\
  whip stream leave <branch>\n\
  whip stream archive <stream>\n\
  whip stream promote <stream>\n\
  whip stream list\n\
  whip stream show <stream>";

fn workstream_store_path() -> PathBuf {
    env::var("WHIPPLESCRIPT_WORKSTREAM_STORE")
        .map(PathBuf::from)
        .unwrap_or_else(|_| PathBuf::from(".whipplescript/workstreams.sqlite"))
}

fn open_streams() -> Result<whipplescript_store::workstreams::WorkstreamStore, ExitCode> {
    whipplescript_store::workstreams::WorkstreamStore::open(workstream_store_path()).map_err(
        |error| {
            eprintln!("could not open the workstream store: {error:?}");
            ExitCode::FAILURE
        },
    )
}

fn stream_row_json(row: &whipplescript_store::workstreams::WorkstreamRow) -> Value {
    json!({
        "stream_id": row.stream_id,
        "name": row.name,
        "line_branch_id": row.line_branch_id,
        "status": row.status.as_str(),
    })
}

/// `whip stream …` — the workstream tier: named shared lines +
/// membership. Members auto-admit during `whip branch reconcile`
/// (greedy, certificate-gated); promotion is the explicit boundary hop
/// to mainline under the adoption lease.
fn stream_command(options: &CliOptions) -> ExitCode {
    use whipplescript_store::workstreams::{
        ArchiveOutcome, CreateStreamOutcome, JoinOutcome, StreamStatus, Workstreams,
    };
    let mut args = options.args.iter().map(String::as_str);
    let Some(verb) = args.next() else {
        eprintln!("{STREAM_USAGE}");
        return ExitCode::from(2);
    };
    let rest: Vec<&str> = args.collect();
    let at = now_stamp();
    let mut streams = match open_streams() {
        Ok(streams) => streams,
        Err(code) => return code,
    };
    match verb {
        "create" => {
            let mut name: Option<&str> = None;
            let mut stream_id: Option<&str> = None;
            let mut iter = rest.iter();
            while let Some(arg) = iter.next() {
                match *arg {
                    "--name" => name = iter.next().copied(),
                    other if stream_id.is_none() => stream_id = Some(other),
                    other => {
                        eprintln!("unexpected argument `{other}`\n{STREAM_USAGE}");
                        return ExitCode::from(2);
                    }
                }
            }
            let Some(stream_id) = stream_id else {
                eprintln!("{STREAM_USAGE}");
                return ExitCode::from(2);
            };
            // The stream's shared line is an ordinary branch off mainline.
            let line_branch_id = format!("line-{stream_id}");
            let mut vcs = match open_vcs() {
                Ok(vcs) => vcs,
                Err(code) => return code,
            };
            if let Err(error) = vcs.init(&at) {
                eprintln!("stream create failed: {error:?}");
                return ExitCode::FAILURE;
            }
            match vcs.create_branch(
                &line_branch_id,
                None,
                whipplescript_store::branches::MAINLINE_BRANCH_ID,
                &at,
            ) {
                Ok(whipplescript_store::branches::CreateBranchOutcome::Created(_))
                | Ok(whipplescript_store::branches::CreateBranchOutcome::Existing(_)) => {}
                Ok(other) => {
                    eprintln!("stream line not created: {other:?}");
                    return ExitCode::FAILURE;
                }
                Err(error) => {
                    eprintln!("stream line create failed: {error:?}");
                    return ExitCode::FAILURE;
                }
            }
            match streams.create_stream(stream_id, name, &line_branch_id, &at, None) {
                Ok(CreateStreamOutcome::Created(row)) => {
                    emit_json(json!({"created": stream_row_json(&row)}))
                }
                Ok(CreateStreamOutcome::Existing(row)) => {
                    emit_json(json!({"existing": stream_row_json(&row)}))
                }
                Ok(CreateStreamOutcome::NameTaken { holder_stream_id }) => {
                    eprintln!("stream name taken by `{holder_stream_id}`");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("stream create failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "join" => {
            let (Some(stream_id), Some(branch_id)) = (rest.first(), rest.get(1)) else {
                eprintln!("{STREAM_USAGE}");
                return ExitCode::from(2);
            };
            match streams.join(branch_id, stream_id, &at) {
                Ok(JoinOutcome::Joined { left_stream_id }) => emit_json(json!({
                    "joined": branch_id, "stream_id": stream_id,
                    "left_stream_id": left_stream_id,
                })),
                Ok(other) => {
                    eprintln!("join refused: {other:?}");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("join failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "leave" => {
            let Some(branch_id) = rest.first() else {
                eprintln!("{STREAM_USAGE}");
                return ExitCode::from(2);
            };
            match streams.leave(branch_id) {
                Ok(left) => emit_json(json!({"left": branch_id, "stream_id": left})),
                Err(error) => {
                    eprintln!("leave failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "archive" => {
            let Some(stream_id) = rest.first() else {
                eprintln!("{STREAM_USAGE}");
                return ExitCode::from(2);
            };
            match streams.archive_stream(stream_id, &at) {
                Ok(ArchiveOutcome::Archived { rehomed_branch_ids }) => emit_json(json!({
                    "archived": stream_id,
                    "rehomed_branch_ids": rehomed_branch_ids,
                })),
                Ok(other) => {
                    eprintln!("archive refused: {other:?}");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("archive failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "promote" => {
            let Some(stream_id) = rest.first() else {
                eprintln!("{STREAM_USAGE}");
                return ExitCode::from(2);
            };
            let Ok(Some(stream)) = streams.get_stream(stream_id) else {
                eprintln!("no such stream `{stream_id}`");
                return ExitCode::FAILURE;
            };
            if stream.status != StreamStatus::Active {
                eprintln!("stream `{stream_id}` is archived");
                return ExitCode::FAILURE;
            }
            let mut vcs = match open_vcs() {
                Ok(vcs) => vcs,
                Err(code) => return code,
            };
            // The boundary hop runs under the adoption lease on mainline.
            let holder = format!("whip-{}", std::process::id());
            let lease_key = format!(
                "{}::{}",
                branch_store_path().display(),
                whipplescript_store::branches::MAINLINE_BRANCH_ID
            );
            let mut coordination = match whipplescript_store::coordination::CoordinationStore::open(
                coordination_store_path(),
            ) {
                Ok(coordination) => coordination,
                Err(error) => {
                    eprintln!("coordination store unavailable: {error:?}");
                    return ExitCode::FAILURE;
                }
            };
            match coordination.try_acquire("adoption", &lease_key, 1, 60, &holder) {
                Ok(whipplescript_store::coordination::AcquireOutcome::Held) => {}
                Ok(whipplescript_store::coordination::AcquireOutcome::Contended { holders }) => {
                    eprintln!("adoption lease is held by {holders:?}; retry");
                    return ExitCode::FAILURE;
                }
                Err(error) => {
                    eprintln!("adoption lease unavailable: {error:?}");
                    return ExitCode::FAILURE;
                }
            }
            let sync_cut = generated_cut_id();
            let outcome = vcs.sync_to_line(
                &stream.line_branch_id,
                whipplescript_store::branches::MAINLINE_BRANCH_ID,
                &format!("{sync_cut}-promote"),
                &at,
            );
            let _ = coordination.release("adoption", &lease_key, &holder);
            match outcome {
                Ok(whipplescript_store::vcs::SyncOutcome::Synced { sync_cut_id }) => {
                    emit_json(json!({
                        "promoted": stream_id, "into": "main",
                        "sync_cut_id": sync_cut_id,
                    }))
                }
                Ok(whipplescript_store::vcs::SyncOutcome::UpToDate) => {
                    emit_json(json!({"promoted": stream_id, "outcome": "up_to_date"}))
                }
                Ok(whipplescript_store::vcs::SyncOutcome::Conflicts { conflicts }) => {
                    let payload = json!({
                        "conflicted": stream_id,
                        "conflicts": conflicts.iter().map(conflict_json).collect::<Vec<_>>(),
                    });
                    eprintln!("promotion conflicted: {payload}");
                    ExitCode::FAILURE
                }
                Ok(other) => {
                    eprintln!("promotion refused: {other:?}");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("promotion failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "list" => {
            let all = rest.contains(&"--all");
            let status = if all {
                None
            } else {
                Some(StreamStatus::Active)
            };
            match streams.list_streams(status) {
                Ok(rows) => emit_json(Value::Array(
                    rows.iter().map(stream_row_json).collect::<Vec<_>>(),
                )),
                Err(error) => {
                    eprintln!("stream list failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "show" => {
            let Some(stream_id) = rest.first() else {
                eprintln!("{STREAM_USAGE}");
                return ExitCode::from(2);
            };
            match streams.get_stream(stream_id) {
                Ok(Some(row)) => {
                    let members = streams.members(stream_id).unwrap_or_default();
                    let mut value = stream_row_json(&row);
                    insert_json_field(&mut value, "members", json!(members));
                    emit_json(value)
                }
                Ok(None) => {
                    eprintln!("no such stream `{stream_id}`");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("stream show failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        other => {
            eprintln!("unknown stream verb `{other}`\n{STREAM_USAGE}");
            ExitCode::from(2)
        }
    }
}

/// The versioned-workspace branch stores, workspace-scoped like the
/// coordination store (env-overridable for tests).
fn branch_store_path() -> PathBuf {
    env::var("WHIPPLESCRIPT_BRANCH_STORE")
        .map(PathBuf::from)
        .unwrap_or_else(|_| PathBuf::from(".whipplescript/branches.sqlite"))
}

fn vcs_content_store_path() -> PathBuf {
    env::var("WHIPPLESCRIPT_VCS_CONTENT_STORE")
        .map(PathBuf::from)
        .unwrap_or_else(|_| PathBuf::from(".whipplescript/vcs-content.sqlite"))
}

fn open_vcs() -> Result<whipplescript_store::vcs::NativeWorkspaceVcs, ExitCode> {
    whipplescript_store::vcs::WorkspaceVcs::open(branch_store_path(), vcs_content_store_path())
        .map(|mut vcs| {
            // Declaration-granularity source merges (kernel parser-backed):
            // conflicted `.whip` paths refine to certified merges where the
            // anti-dependence discipline holds; absent this, every source
            // conflict escalates.
            vcs.set_source_merger(Box::new(
                whipplescript_kernel::source_merge::WhipSourceMerger,
            ));
            vcs
        })
        .map_err(|error| {
            eprintln!("could not open the branch stores: {error:?}");
            ExitCode::FAILURE
        })
}

fn now_stamp() -> String {
    // Seconds-resolution wall stamp, matching the store idiom of
    // caller-provided clocks.
    let secs = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|elapsed| elapsed.as_secs())
        .unwrap_or(0);
    format!("unix:{secs}")
}

/// The file surface an instance's `file.*` effects dispatch onto: the
/// branch working set when the instance was born on a branch (its writes
/// then mint COW cuts on that branch and touch no real directory), the
/// native filesystem otherwise. The branch store is consulted only when
/// it already exists, so non-VCS workspaces never create one. `cut_seed`
/// (the effect id) keys the write-through cuts for attribution.
fn file_store_for_instance(
    instance_id: &str,
    cut_seed: &str,
) -> Box<dyn whipplescript_store::files::FileStore> {
    use whipplescript_store::vcs::{BranchFileStore, WorkspaceVcs};
    if !branch_store_path().exists() {
        return Box::new(NativeFileStore);
    }
    let Ok(vcs) = WorkspaceVcs::open(branch_store_path(), vcs_content_store_path()) else {
        return Box::new(NativeFileStore);
    };
    match vcs.instance_branch(instance_id) {
        Ok(Some(branch_id)) => Box::new(BranchFileStore::new(
            vcs,
            &branch_id,
            cut_seed,
            &now_stamp(),
        )),
        _ => Box::new(NativeFileStore),
    }
}

/// Materialize-on-exec, setup half: when the instance is branch-bound,
/// project the branch's head manifest into an effect-keyed scratch
/// directory and hand back the seeded stat cache. A crash-retried effect
/// re-materializes fresh (the whole effect re-runs; the import stays
/// idempotent by cut id). `None` = unbound instance, run in place.
#[allow(clippy::type_complexity)]
fn branch_exec_scratch(
    instance_id: &str,
    effect_id: &str,
) -> Result<
    Option<(
        String,
        PathBuf,
        whipplescript_store::materialize::MaterializedScratch,
    )>,
    String,
> {
    if !branch_store_path().exists() {
        return Ok(None);
    }
    let vcs =
        whipplescript_store::vcs::WorkspaceVcs::open(branch_store_path(), vcs_content_store_path())
            .map_err(|error| format!("branch stores unavailable: {error:?}"))?;
    let Some(branch_id) = vcs
        .instance_branch(instance_id)
        .map_err(|error| format!("binding lookup failed: {error:?}"))?
    else {
        return Ok(None);
    };
    let scratch_root = std::env::temp_dir().join(format!("whip-exec-scratch-{effect_id}"));
    let _ = std::fs::remove_dir_all(&scratch_root);
    let now_unix_nanos = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|elapsed| elapsed.as_nanos() as i128)
        .unwrap_or(0);
    let scratch = vcs
        .materialize_branch(&branch_id, &scratch_root, now_unix_nanos)
        .map_err(|error| format!("materialize failed: {error:?}"))?
        .ok_or_else(|| format!("instance is bound to unknown branch `{branch_id}`"))?;
    Ok(Some((branch_id, scratch_root, scratch)))
}

/// Materialize-on-exec, import half: scan the scratch, store every changed
/// blob, commit the diff as ONE cut keyed by the effect id, and return the
/// summary that rides the effect's terminal metadata.
fn import_branch_exec_scratch(
    branch_id: &str,
    scratch_root: &Path,
    scratch: &whipplescript_store::materialize::MaterializedScratch,
    effect_id: &str,
) -> Result<Value, String> {
    use whipplescript_store::vcs::VcsWriteOutcome;
    let mut vcs =
        whipplescript_store::vcs::WorkspaceVcs::open(branch_store_path(), vcs_content_store_path())
            .map_err(|error| format!("branch stores unavailable: {error:?}"))?;
    let now_unix_nanos = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|elapsed| elapsed.as_nanos() as i128)
        .unwrap_or(0);
    let cut_id = format!("cut-exec-{effect_id}");
    let (import, outcome) = vcs
        .import_scratch(
            branch_id,
            scratch_root,
            scratch,
            &cut_id,
            &now_stamp(),
            now_unix_nanos,
        )
        .map_err(|error| format!("import-back failed: {error:?}"))?;
    match outcome {
        VcsWriteOutcome::Written { cut_id, .. } => Ok(json!({
            "branch_id": branch_id,
            "cut_id": cut_id,
            "changed": import.changed.len(),
            "removed": import.removed.len(),
            "trusted": import.trusted,
            "rehashed": import.rehashed,
        })),
        VcsWriteOutcome::BranchNotActive => Err(format!(
            "branch `{branch_id}` closed during the exec; the diff was not adopted"
        )),
        VcsWriteOutcome::BranchMissing => Err(format!("branch `{branch_id}` disappeared")),
    }
}

/// Record an instance's branch binding: write-once in the branch store,
/// plus a `branch.bound` event on the instance log so the host-agnostic
/// kernel derives branch-distinct effect keys from state it already
/// reads.
fn bind_instance_to_branch(
    store_path: &Path,
    instance_id: &str,
    branch_id: &str,
) -> Result<(), String> {
    use whipplescript_store::branches::BindOutcome;
    let mut vcs =
        whipplescript_store::vcs::WorkspaceVcs::open(branch_store_path(), vcs_content_store_path())
            .map_err(|error| format!("could not open the branch stores: {error:?}"))?;
    match vcs
        .bind_instance(instance_id, branch_id, &now_stamp())
        .map_err(|error| format!("bind failed: {error:?}"))?
    {
        BindOutcome::Bound => {}
        BindOutcome::AlreadyBound { branch_id: other } => {
            return Err(format!(
                "instance `{instance_id}` is already bound to branch `{other}`"
            ));
        }
        BindOutcome::BranchMissing => {
            return Err(format!("no such branch `{branch_id}`"));
        }
        BindOutcome::BranchNotActive { status } => {
            return Err(format!(
                "branch `{branch_id}` is {} — instances cannot be born on a closed line",
                status.as_str()
            ));
        }
    }
    let store = SqliteStore::open(store_path)
        .map_err(|error| format!("could not open the runtime store: {error:?}"))?;
    let payload = json!({ "branch_id": branch_id }).to_string();
    store
        .append_event(whipplescript_store::NewEvent {
            instance_id,
            event_type: "branch.bound",
            payload_json: &payload,
            source: "cli",
            causation_id: None,
            correlation_id: None,
            idempotency_key: Some(&idempotency_key(&[instance_id, branch_id, "branch-bind"])),
        })
        .map_err(|error| format!("could not record the binding event: {error:?}"))?;
    Ok(())
}

fn branch_row_json(row: &whipplescript_store::branches::BranchRow) -> Value {
    json!({
        "branch_id": row.branch_id,
        "name": row.name,
        "parent_branch_id": row.parent_branch_id,
        "branch_point_cut_id": row.branch_point_cut_id,
        "head_cut_id": row.head_cut_id,
        "head_manifest_hash": row.head_manifest_hash,
        "status": row.status.as_str(),
        "adopted_merge_cut_id": row.adopted_merge_cut_id,
    })
}

fn conflict_json(conflict: &whipplescript_store::merge::PathConflict) -> Value {
    json!({
        "path": conflict.path,
        "base": conflict.base,
        "ours": conflict.ours,
        "theirs": conflict.theirs,
        "ours_branch": conflict.ours_side.label,
        "ours_cut": conflict.ours_side.cut_id,
        "theirs_branch": conflict.theirs_side.label,
        "theirs_cut": conflict.theirs_side.cut_id,
    })
}

/// `whip branch …` — the versioned-workspace surface: branch, write on a
/// branch's virtual working set, merge back (certified or honest
/// structured conflicts), discard. Every operation is a proposal over
/// immutable content; no destructive verb exists.
fn branch_command(options: &CliOptions) -> ExitCode {
    use whipplescript_store::branches::BranchStatus;
    use whipplescript_store::vcs::{VcsMergeOutcome, VcsWriteOutcome};

    let mut args = options.args.iter().map(String::as_str);
    let Some(verb) = args.next() else {
        eprintln!("{BRANCH_USAGE}");
        return ExitCode::from(2);
    };
    let rest: Vec<&str> = args.collect();
    let at = now_stamp();
    let mut vcs = match open_vcs() {
        Ok(vcs) => vcs,
        Err(code) => return code,
    };
    match verb {
        "create" => {
            let mut name: Option<&str> = None;
            let mut parent: &str = whipplescript_store::branches::MAINLINE_BRANCH_ID;
            let mut branch_id: Option<&str> = None;
            let mut iter = rest.iter();
            while let Some(arg) = iter.next() {
                match *arg {
                    "--name" => name = iter.next().copied(),
                    "--from" => parent = iter.next().copied().unwrap_or(parent),
                    other if branch_id.is_none() => branch_id = Some(other),
                    other => {
                        eprintln!("unexpected argument `{other}`\n{BRANCH_USAGE}");
                        return ExitCode::from(2);
                    }
                }
            }
            let Some(branch_id) = branch_id else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            match vcs.create_branch(branch_id, name, parent, &at) {
                Ok(whipplescript_store::branches::CreateBranchOutcome::Created(row)) => {
                    emit_json(json!({"created": branch_row_json(&row)}))
                }
                Ok(whipplescript_store::branches::CreateBranchOutcome::Existing(row)) => {
                    emit_json(json!({"existing": branch_row_json(&row)}))
                }
                Ok(other) => {
                    eprintln!("branch not created: {other:?}");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch create failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "list" => {
            let all = rest.contains(&"--all");
            let status = if all {
                None
            } else {
                Some(BranchStatus::Active)
            };
            if let Err(error) = vcs.init(&at) {
                eprintln!("branch list failed: {error:?}");
                return ExitCode::FAILURE;
            }
            match vcs.list_branches(status) {
                Ok(rows) => emit_json(Value::Array(
                    rows.iter().map(branch_row_json).collect::<Vec<_>>(),
                )),
                Err(error) => {
                    eprintln!("branch list failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "show" => {
            let Some(branch_id) = rest.first() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            match vcs.get_branch(branch_id) {
                Ok(Some(row)) => emit_json(branch_row_json(&row)),
                Ok(None) => {
                    eprintln!("no such branch `{branch_id}`");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch show failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "write" | "remove" => {
            let Some(branch_id) = rest.first().copied() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            let Some(path) = rest.get(1).copied() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            let body = if verb == "write" {
                let Some(index) = rest.iter().position(|arg| *arg == "--body") else {
                    eprintln!("`branch write` requires --body <text>\n{BRANCH_USAGE}");
                    return ExitCode::from(2);
                };
                let Some(body) = rest.get(index + 1).copied() else {
                    eprintln!("expected text after `--body`");
                    return ExitCode::from(2);
                };
                Some(body)
            } else {
                None
            };
            if let Err(error) = vcs.init(&at) {
                eprintln!("branch {verb} failed: {error:?}");
                return ExitCode::FAILURE;
            }
            let cut_id = generated_cut_id();
            match vcs.write(branch_id, path, body, &cut_id, &at) {
                Ok(VcsWriteOutcome::Written {
                    cut_id,
                    manifest_hash,
                }) => emit_json(json!({
                    "branch_id": branch_id,
                    "path": path,
                    "cut_id": cut_id,
                    "manifest_hash": manifest_hash,
                    "removed": body.is_none(),
                })),
                Ok(other) => {
                    eprintln!("branch {verb} refused: {other:?}");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch {verb} failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "read" => {
            let (Some(branch_id), Some(path)) = (rest.first(), rest.get(1)) else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            match vcs.read(branch_id, path) {
                Ok(Some(body)) => {
                    if options.json {
                        emit_json(json!({"branch_id": branch_id, "path": path, "body": body}))
                    } else {
                        println!("{body}");
                        ExitCode::SUCCESS
                    }
                }
                Ok(None) => {
                    eprintln!("no file at `{path}` on branch `{branch_id}`");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch read failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "ls" => {
            let Some(branch_id) = rest.first() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            match vcs.manifest(branch_id) {
                Ok(Some(manifest)) => emit_json(json!({
                    "branch_id": branch_id,
                    "files": manifest,
                })),
                Ok(None) => {
                    eprintln!("no such branch `{branch_id}`");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch ls failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "merge" => {
            let Some(branch_id) = rest.first() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            // Merge-up is serialized by the ADOPTION LEASE on the target
            // line (vw note §7.1; ReconciliationDaemonLifecycle.tla):
            // multi-writer hosts contend here instead of racing head
            // advances.
            let target = match vcs.get_branch(branch_id) {
                Ok(Some(row)) => row.parent_branch_id.unwrap_or_default(),
                _ => String::new(),
            };
            let holder = format!("whip-{}", std::process::id());
            // The lease guards THIS workspace's target line: the key
            // carries the branch-store identity so distinct workspaces
            // sharing one coordination store never contend.
            let lease_key = format!("{}::{target}", branch_store_path().display());
            let mut adoption_lease = None;
            if !target.is_empty() {
                match whipplescript_store::coordination::CoordinationStore::open(
                    coordination_store_path(),
                ) {
                    Ok(mut coordination) => {
                        match coordination.try_acquire("adoption", &lease_key, 1, 60, &holder) {
                            Ok(whipplescript_store::coordination::AcquireOutcome::Held) => {
                                adoption_lease = Some((coordination, lease_key.clone()));
                            }
                            Ok(whipplescript_store::coordination::AcquireOutcome::Contended {
                                holders,
                            }) => {
                                eprintln!(
                                    "adoption lease for `{target}` is held by {holders:?}; retry"
                                );
                                return ExitCode::FAILURE;
                            }
                            Err(error) => {
                                eprintln!("adoption lease unavailable: {error:?}");
                                return ExitCode::FAILURE;
                            }
                        }
                    }
                    Err(error) => {
                        eprintln!("coordination store unavailable: {error:?}");
                        return ExitCode::FAILURE;
                    }
                }
            }
            let merge_cut_id = generated_cut_id();
            let outcome = vcs.merge(branch_id, &merge_cut_id, &at);
            if let Some((mut coordination, lease_key)) = adoption_lease {
                let _ = coordination.release("adoption", &lease_key, &holder);
            }
            match outcome {
                Ok(VcsMergeOutcome::Adopted {
                    merge_cut_id,
                    into_branch_id,
                })
                | Ok(VcsMergeOutcome::Landed {
                    merge_cut_id,
                    into_branch_id,
                }) => emit_json(json!({
                    "adopted": branch_id,
                    "into": into_branch_id,
                    "merge_cut_id": merge_cut_id,
                })),
                Ok(VcsMergeOutcome::Conflicted { conflicts }) => {
                    let payload = json!({
                        "conflicted": branch_id,
                        "conflicts": conflicts.iter().map(conflict_json).collect::<Vec<_>>(),
                    });
                    // Conflicts are an honest, non-zero outcome: nothing
                    // moved; resolve on the branch and merge again.
                    if options.json {
                        println!(
                            "{}",
                            serde_json::to_string_pretty(&payload)
                                .unwrap_or_else(|_| payload.to_string())
                        );
                    } else {
                        eprintln!("merge conflicted: {payload}");
                    }
                    ExitCode::FAILURE
                }
                Ok(other) => {
                    eprintln!("merge refused: {other:?}");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch merge failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "bind" => {
            let (Some(branch_id), Some(instance_id)) = (rest.first(), rest.get(1)) else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            drop(vcs);
            match bind_instance_to_branch(&options.store_path, instance_id, branch_id) {
                Ok(()) => emit_json(json!({
                    "bound": instance_id,
                    "branch_id": branch_id,
                })),
                Err(message) => {
                    eprintln!("branch bind failed: {message}");
                    ExitCode::FAILURE
                }
            }
        }
        "reconcile" => {
            // One reconciliation-daemon pass over every live branch:
            // fold parent deltas down. Quiescence is detected from the
            // branch's bound instances — any still-running instance keeps
            // the branch mid-run, so intersecting deltas defer.
            let branches = match vcs.list_branches(Some(BranchStatus::Active)) {
                Ok(rows) => rows,
                Err(error) => {
                    eprintln!("branch list failed: {error:?}");
                    return ExitCode::FAILURE;
                }
            };
            let store = SqliteStore::open(&options.store_path).ok();
            // Stream membership redirects a member's sync target to its
            // stream's line, and quiescent members AUTO-ADMIT greedily
            // (certificate-gated; conflicts isolate per contribution).
            let streams =
                whipplescript_store::workstreams::WorkstreamStore::open(workstream_store_path())
                    .ok();
            let mut report = Vec::new();
            for row in branches {
                if row.parent_branch_id.is_none() {
                    continue; // mainline has nothing to fold down from
                }
                let quiescent = match (&store, vcs.list_bound_instances_of(&row.branch_id)) {
                    (Some(store), Ok(instances)) => instances.iter().all(|instance_id| {
                        store
                            .status(instance_id)
                            .ok()
                            .flatten()
                            .map(|status| status.instance.status != "running")
                            .unwrap_or(true)
                    }),
                    (None, _) | (_, Err(_)) => false,
                };
                use whipplescript_store::workstreams::{StreamStatus, Workstreams};
                let stream_line = streams.as_ref().and_then(|streams| {
                    let stream_id = streams.home_of(&row.branch_id).ok().flatten()?;
                    let stream = streams.get_stream(&stream_id).ok().flatten()?;
                    (stream.status == StreamStatus::Active).then_some(stream.line_branch_id)
                });
                let cut_id = generated_cut_id();
                if let Some(line_id) = stream_line {
                    if quiescent {
                        use whipplescript_store::vcs::SyncOutcome;
                        let entry = match vcs.sync_to_line(
                            &row.branch_id,
                            &line_id,
                            &format!("{cut_id}-admit"),
                            &at,
                        ) {
                            Ok(SyncOutcome::Synced { sync_cut_id }) => json!({
                                "branch_id": row.branch_id, "outcome": "admitted",
                                "line_branch_id": line_id, "sync_cut_id": sync_cut_id,
                            }),
                            Ok(SyncOutcome::UpToDate) => json!({
                                "branch_id": row.branch_id, "outcome": "up_to_date",
                                "line_branch_id": line_id,
                            }),
                            Ok(SyncOutcome::Conflicts { conflicts }) => json!({
                                "branch_id": row.branch_id, "outcome": "conflicts",
                                "line_branch_id": line_id,
                                "conflicts":
                                    conflicts.iter().map(conflict_json).collect::<Vec<_>>(),
                            }),
                            Ok(other) => json!({
                                "branch_id": row.branch_id,
                                "outcome": format!("{other:?}"),
                            }),
                            Err(error) => {
                                eprintln!("auto-admit `{}` failed: {error:?}", row.branch_id);
                                return ExitCode::FAILURE;
                            }
                        };
                        report.push(entry);
                    } else {
                        report.push(json!({
                            "branch_id": row.branch_id, "outcome": "deferred_mid_run",
                            "line_branch_id": line_id,
                        }));
                    }
                    continue;
                }
                let outcome = match vcs.reconcile_branch(
                    &row.branch_id,
                    quiescent,
                    &format!("{cut_id}-reconcile"),
                    &at,
                ) {
                    Ok(outcome) => outcome,
                    Err(error) => {
                        eprintln!("reconcile `{}` failed: {error:?}", row.branch_id);
                        return ExitCode::FAILURE;
                    }
                };
                use whipplescript_store::vcs::ReconcileOutcome;
                let entry = match outcome {
                    ReconcileOutcome::UpToDate => json!({
                        "branch_id": row.branch_id, "outcome": "up_to_date",
                    }),
                    ReconcileOutcome::Rebased { rebase_cut_id } => json!({
                        "branch_id": row.branch_id, "outcome": "rebased",
                        "rebase_cut_id": rebase_cut_id,
                    }),
                    ReconcileOutcome::DeferredMidRun => json!({
                        "branch_id": row.branch_id, "outcome": "deferred_mid_run",
                    }),
                    ReconcileOutcome::Conflicts { conflicts } => json!({
                        "branch_id": row.branch_id, "outcome": "conflicts",
                        "conflicts": conflicts.iter().map(conflict_json).collect::<Vec<_>>(),
                    }),
                    other => json!({
                        "branch_id": row.branch_id, "outcome": format!("{other:?}"),
                    }),
                };
                report.push(entry);
            }
            emit_json(Value::Array(report))
        }
        "discard" => {
            let Some(branch_id) = rest.first() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            match vcs.discard_branch(branch_id, &at) {
                Ok(whipplescript_store::branches::StatusOutcome::Done(row)) => {
                    emit_json(json!({"discarded": branch_row_json(&row)}))
                }
                Ok(other) => {
                    eprintln!("discard refused: {other:?}");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch discard failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "fork" => {
            let mut name: Option<&str> = None;
            let mut from: &str = whipplescript_store::branches::MAINLINE_BRANCH_ID;
            let mut at_cut: Option<&str> = None;
            let mut branch_id: Option<&str> = None;
            let mut iter = rest.iter();
            while let Some(arg) = iter.next() {
                match *arg {
                    "--name" => name = iter.next().copied(),
                    "--from" => from = iter.next().copied().unwrap_or(from),
                    "--at-cut" => at_cut = iter.next().copied(),
                    other if branch_id.is_none() => branch_id = Some(other),
                    other => {
                        eprintln!("unexpected argument `{other}`\n{BRANCH_USAGE}");
                        return ExitCode::from(2);
                    }
                }
            }
            let Some(branch_id) = branch_id else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            match vcs.fork_with_lineage(branch_id, name, from, at_cut, &at) {
                Ok(whipplescript_store::branches::CreateBranchOutcome::Created(row)) => {
                    emit_json(json!({"forked": branch_row_json(&row)}))
                }
                Ok(whipplescript_store::branches::CreateBranchOutcome::Existing(row)) => {
                    emit_json(json!({"existing": branch_row_json(&row)}))
                }
                Ok(other) => {
                    eprintln!("fork refused: {other:?}");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch fork failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "status" => {
            let Some(branch_id) = rest.first() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            match vcs.status_report(branch_id) {
                Ok(Some(report)) => match serde_json::to_value(&report) {
                    Ok(payload) => emit_json(payload),
                    Err(error) => {
                        eprintln!("branch status failed: {error}");
                        ExitCode::FAILURE
                    }
                },
                Ok(None) => {
                    eprintln!("no such branch `{branch_id}`");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch status failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "cut" => {
            let Some(branch_id) = rest.first() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            let cut_id = generated_cut_id();
            match vcs.cut_at_quiescence(branch_id, &cut_id, &at) {
                Ok(Some(cut)) => emit_json(json!({
                    "branch_id": branch_id,
                    "cut_id": cut.cut_id,
                    "manifest_hash": cut.manifest_hash,
                    "change_id": cut.change_id,
                })),
                Ok(None) => {
                    eprintln!("no such branch `{branch_id}`");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch cut failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "diff" => {
            let Some(branch_id) = rest.first().copied() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            let against = rest
                .iter()
                .position(|arg| *arg == "--against")
                .and_then(|index| rest.get(index + 1))
                .copied();
            let context = rest
                .iter()
                .position(|arg| *arg == "--context")
                .and_then(|index| rest.get(index + 1))
                .and_then(|value| value.parse::<usize>().ok())
                .unwrap_or(3);
            match vcs.diff_against(branch_id, against, context) {
                Ok(Some(entries)) => {
                    if options.json {
                        match serde_json::to_value(&entries) {
                            Ok(payload) => emit_json(json!({
                                "branch_id": branch_id,
                                "against": against.unwrap_or("branch-point"),
                                "entries": payload,
                            })),
                            Err(error) => {
                                eprintln!("branch diff failed: {error}");
                                ExitCode::FAILURE
                            }
                        }
                    } else {
                        for entry in &entries {
                            print!("{}", entry.to_unified());
                        }
                        ExitCode::SUCCESS
                    }
                }
                Ok(None) => {
                    eprintln!("no such branch `{branch_id}`");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch diff failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "probe" => {
            let Some(branch_id) = rest.first() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            use whipplescript_store::vcs::MergeProbeOutcome;
            match vcs.merge_probe(branch_id) {
                Ok(MergeProbeOutcome::UpToDate) => emit_json(json!({
                    "branch_id": branch_id, "probe": "up_to_date",
                })),
                Ok(MergeProbeOutcome::Clean {
                    merged_manifest_hash,
                    changed_paths,
                }) => emit_json(json!({
                    "branch_id": branch_id, "probe": "clean",
                    "merged_manifest_hash": merged_manifest_hash,
                    "changed_paths": changed_paths,
                })),
                Ok(MergeProbeOutcome::Conflicted { conflicts }) => {
                    // An honest preview, not a failure: the probe reports
                    // what the merge would escalate.
                    emit_json(json!({
                        "branch_id": branch_id, "probe": "conflicted",
                        "conflicts": conflicts.iter().map(conflict_json).collect::<Vec<_>>(),
                    }))
                }
                Ok(other) => {
                    eprintln!("probe refused: {other:?}");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch probe failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "restore" => {
            let (Some(branch_id), Some(to_cut)) = (rest.first(), rest.get(1)) else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            use whipplescript_store::vcs::RestoreOutcome;
            let new_cut_id = generated_cut_id();
            match vcs.restore(branch_id, to_cut, &new_cut_id, &at) {
                Ok(RestoreOutcome::Restored {
                    cut_id,
                    manifest_hash,
                }) => emit_json(json!({
                    "restored": branch_id,
                    "to_cut_id": to_cut,
                    "cut_id": cut_id,
                    "manifest_hash": manifest_hash,
                })),
                Ok(RestoreOutcome::AlreadyThere) => emit_json(json!({
                    "restored": branch_id,
                    "to_cut_id": to_cut,
                    "already_there": true,
                })),
                Ok(other) => {
                    eprintln!("restore refused: {other:?}");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch restore failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "ops" => {
            let limit = rest
                .iter()
                .position(|arg| *arg == "--limit")
                .and_then(|index| rest.get(index + 1))
                .and_then(|value| value.parse::<usize>().ok())
                .unwrap_or(50);
            match vcs.list_ops(limit) {
                Ok(ops) => match serde_json::to_value(&ops) {
                    Ok(payload) => emit_json(payload),
                    Err(error) => {
                        eprintln!("branch ops failed: {error}");
                        ExitCode::FAILURE
                    }
                },
                Err(error) => {
                    eprintln!("branch ops failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "export" => {
            let Some(branch_id) = rest.first().copied() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            let out = rest
                .iter()
                .position(|arg| *arg == "--out")
                .and_then(|index| rest.get(index + 1))
                .copied();
            // Pull-missing: --delta-have carries the receiver's declared
            // inventory (JSON array of ids from `whip branch have`).
            let have: std::collections::BTreeSet<String> = match rest
                .iter()
                .position(|arg| *arg == "--delta-have")
                .and_then(|index| rest.get(index + 1))
            {
                None => Default::default(),
                Some(path) => match std::fs::read_to_string(path)
                    .map_err(|error| error.to_string())
                    .and_then(|body| {
                        serde_json::from_str::<Vec<String>>(&body)
                            .map_err(|error| error.to_string())
                    }) {
                    Ok(ids) => ids.into_iter().collect(),
                    Err(error) => {
                        eprintln!("branch export failed reading `{path}`: {error}");
                        return ExitCode::FAILURE;
                    }
                },
            };
            match vcs.export_bundle_delta(branch_id, &have) {
                Ok(Some(bundle)) => {
                    let encoded = match serde_json::to_string_pretty(&bundle) {
                        Ok(encoded) => encoded,
                        Err(error) => {
                            eprintln!("branch export failed: {error}");
                            return ExitCode::FAILURE;
                        }
                    };
                    match out {
                        Some(path) => {
                            if let Err(error) = std::fs::write(path, &encoded) {
                                eprintln!("branch export failed writing `{path}`: {error}");
                                return ExitCode::FAILURE;
                            }
                            emit_json(json!({
                                "exported": branch_id,
                                "out": path,
                                "blobs": bundle.blobs.len(),
                                "files": bundle.manifest.len(),
                            }))
                        }
                        None => {
                            println!("{encoded}");
                            ExitCode::SUCCESS
                        }
                    }
                }
                Ok(None) => {
                    eprintln!("no such branch `{branch_id}`");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch export failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "import" => {
            let Some(path) = rest.first().copied() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            let body = match std::fs::read_to_string(path) {
                Ok(body) => body,
                Err(error) => {
                    eprintln!("branch import failed reading `{path}`: {error}");
                    return ExitCode::FAILURE;
                }
            };
            let bundle: whipplescript_store::bundle::WorkspaceBundle =
                match serde_json::from_str(&body) {
                    Ok(bundle) => bundle,
                    Err(error) => {
                        eprintln!("branch import failed decoding `{path}`: {error}");
                        return ExitCode::FAILURE;
                    }
                };
            use whipplescript_store::bundle::BundleImportOutcome;
            match vcs.import_bundle(&bundle, &at) {
                Ok(BundleImportOutcome::Imported {
                    branch_id,
                    cut_id,
                    manifest_hash,
                }) => emit_json(json!({
                    "imported": branch_id,
                    "cut_id": cut_id,
                    "manifest_hash": manifest_hash,
                })),
                Ok(BundleImportOutcome::AlreadyPresent { branch_id }) => emit_json(json!({
                    "imported": branch_id,
                    "already_present": true,
                })),
                Ok(BundleImportOutcome::DivergentBranch {
                    branch_id,
                    local_head_manifest_hash,
                }) => {
                    eprintln!(
                        "import refused: branch `{branch_id}` has divergent local content \
                         (head manifest {local_head_manifest_hash:?}); import never clobbers"
                    );
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch import failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "attribution" => {
            let Some(branch_id) = rest.first().copied() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            match vcs.attribution(branch_id) {
                Ok(Some(rows)) => match serde_json::to_value(&rows) {
                    Ok(payload) => emit_json(payload),
                    Err(error) => {
                        eprintln!("branch attribution failed: {error}");
                        ExitCode::FAILURE
                    }
                },
                Ok(None) => {
                    eprintln!("no such branch `{branch_id}`");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch attribution failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "log" => {
            let Some(branch_id) = rest.first().copied() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            let limit = rest
                .iter()
                .position(|arg| *arg == "--limit")
                .and_then(|index| rest.get(index + 1))
                .and_then(|value| value.parse::<usize>().ok())
                .unwrap_or(50);
            match vcs.list_cuts(branch_id, limit) {
                Ok(cuts) => match serde_json::to_value(&cuts) {
                    Ok(payload) => emit_json(payload),
                    Err(error) => {
                        eprintln!("branch log failed: {error}");
                        ExitCode::FAILURE
                    }
                },
                Err(error) => {
                    eprintln!("branch log failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "bisect" => {
            // Checkout-free bisect: candidate cuts materialize into
            // scratch directories and the predicate runs there — no
            // branch pointer ever moves.
            let Some(_branch_id) = rest.first().copied() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            let flag = |name: &str| {
                rest.iter()
                    .position(|arg| *arg == name)
                    .and_then(|index| rest.get(index + 1))
                    .copied()
            };
            let (Some(good), Some(bad), Some(run)) = (flag("--good"), flag("--bad"), flag("--run"))
            else {
                eprintln!("`branch bisect` requires --good, --bad, --run\n{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            let chain = match vcs.cut_chain(bad, good) {
                Ok(Some(chain)) if chain.len() >= 2 => chain,
                Ok(_) => {
                    eprintln!("no recorded lineage from `{bad}` back to `{good}`");
                    return ExitCode::FAILURE;
                }
                Err(error) => {
                    eprintln!("branch bisect failed: {error:?}");
                    return ExitCode::FAILURE;
                }
            };
            let probe = |cut_id: &str| -> Result<bool, String> {
                let manifest = vcs
                    .cut_manifest(cut_id)
                    .map_err(|error| format!("{error:?}"))?
                    .ok_or_else(|| format!("cut `{cut_id}` has no manifest"))?;
                let scratch = std::env::temp_dir()
                    .join(format!("whip-bisect-{}-{cut_id}", std::process::id()));
                let _ = std::fs::remove_dir_all(&scratch);
                whipplescript_store::materialize::materialize_manifest(
                    &manifest,
                    vcs.content_store(),
                    &scratch,
                    0,
                )
                .map_err(|error| format!("{error:?}"))?;
                let status = std::process::Command::new("sh")
                    .arg("-c")
                    .arg(run)
                    .current_dir(&scratch)
                    .status()
                    .map_err(|error| error.to_string())?;
                let _ = std::fs::remove_dir_all(&scratch);
                Ok(status.success())
            };
            // Invariant: chain[lo] is good, chain[hi] is bad; find the
            // first bad cut.
            let mut lo = 0usize;
            let mut hi = chain.len() - 1;
            let mut steps = Vec::new();
            while hi - lo > 1 {
                let mid = lo + (hi - lo) / 2;
                match probe(&chain[mid].cut_id) {
                    Ok(true) => {
                        steps.push(json!({"cut_id": chain[mid].cut_id, "verdict": "good"}));
                        lo = mid;
                    }
                    Ok(false) => {
                        steps.push(json!({"cut_id": chain[mid].cut_id, "verdict": "bad"}));
                        hi = mid;
                    }
                    Err(error) => {
                        eprintln!("bisect probe failed at `{}`: {error}", chain[mid].cut_id);
                        return ExitCode::FAILURE;
                    }
                }
            }
            emit_json(json!({
                "first_bad_cut": chain[hi].cut_id,
                "last_good_cut": chain[lo].cut_id,
                "change_id": chain[hi].change_id,
                "origin": chain[hi].origin,
                "steps": steps,
            }))
        }
        "select" | "undo" | "transport" | "adopt-only" => {
            let (Some(branch_id), Some(expr_text)) = (rest.first().copied(), rest.get(1).copied())
            else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            let expr = match whipplescript_store::selection::parse(expr_text) {
                Ok(expr) => expr,
                Err(error) => {
                    eprintln!("selection did not parse: {error}");
                    return ExitCode::from(2);
                }
            };
            let apply = rest.contains(&"--apply");
            match verb {
                "select" => {
                    let units = match vcs.change_units(branch_id, 500) {
                        Ok(units) => units,
                        Err(error) => {
                            eprintln!("branch select failed: {error:?}");
                            return ExitCode::FAILURE;
                        }
                    };
                    let picked: Vec<_> = whipplescript_store::selection::eval(&expr, &units)
                        .into_iter()
                        .map(|index| units[index].clone())
                        .collect();
                    match serde_json::to_value(&picked) {
                        Ok(payload) => emit_json(payload),
                        Err(error) => {
                            eprintln!("branch select failed: {error}");
                            ExitCode::FAILURE
                        }
                    }
                }
                "undo" => {
                    // Dry-run is the default interaction: show the plan
                    // (including what it would strand); --apply executes.
                    if !apply {
                        return match vcs.plan_undo_selection(branch_id, &expr) {
                            Ok(Some(plan)) => match serde_json::to_value(&plan) {
                                Ok(payload) => emit_json(json!({
                                    "dry_run": true,
                                    "plan": payload,
                                })),
                                Err(error) => {
                                    eprintln!("branch undo failed: {error}");
                                    ExitCode::FAILURE
                                }
                            },
                            Ok(None) => {
                                eprintln!("no such branch `{branch_id}`");
                                ExitCode::FAILURE
                            }
                            Err(error) => {
                                eprintln!("branch undo failed: {error:?}");
                                ExitCode::FAILURE
                            }
                        };
                    }
                    use whipplescript_store::vcs::UndoSelectionOutcome;
                    let cut_id = generated_cut_id();
                    match vcs.apply_undo_selection(branch_id, &expr, &cut_id, &at) {
                        Ok(UndoSelectionOutcome::Proposed {
                            cut_id,
                            manifest_hash,
                            reverted_paths,
                        }) => emit_json(json!({
                            "undone": branch_id,
                            "cut_id": cut_id,
                            "manifest_hash": manifest_hash,
                            "reverted_paths": reverted_paths,
                        })),
                        Ok(UndoSelectionOutcome::WouldStrand { stranded }) => {
                            let payload = serde_json::to_value(&stranded).unwrap_or_default();
                            eprintln!(
                                "undo refused: the exclusion strands retained work: {payload}"
                            );
                            ExitCode::FAILURE
                        }
                        Ok(other) => {
                            eprintln!("undo refused: {other:?}");
                            ExitCode::FAILURE
                        }
                        Err(error) => {
                            eprintln!("branch undo failed: {error:?}");
                            ExitCode::FAILURE
                        }
                    }
                }
                transport_like => {
                    use whipplescript_store::vcs::TransportOutcome;
                    let onto = rest
                        .iter()
                        .position(|arg| *arg == "--onto")
                        .and_then(|index| rest.get(index + 1))
                        .copied();
                    if transport_like == "transport" && onto.is_none() {
                        eprintln!("`branch transport` requires --onto <target>\n{BRANCH_USAGE}");
                        return ExitCode::from(2);
                    }
                    if !apply {
                        // Dry-run: the universe filtered to the selection
                        // is the preview (the apply reports conflicts
                        // instead of moving anything anyway).
                        let units = match vcs.change_units(branch_id, 500) {
                            Ok(units) => units,
                            Err(error) => {
                                eprintln!("branch {transport_like} failed: {error:?}");
                                return ExitCode::FAILURE;
                            }
                        };
                        let picked: Vec<_> = whipplescript_store::selection::eval(&expr, &units)
                            .into_iter()
                            .map(|index| units[index].clone())
                            .collect();
                        return match serde_json::to_value(&picked) {
                            Ok(payload) => emit_json(json!({
                                "dry_run": true,
                                "would_move": payload,
                            })),
                            Err(error) => {
                                eprintln!("branch {transport_like} failed: {error}");
                                ExitCode::FAILURE
                            }
                        };
                    }
                    let cut_id = generated_cut_id();
                    let outcome = if transport_like == "transport" {
                        vcs.transport_selection(
                            branch_id,
                            &expr,
                            onto.expect("checked above"),
                            &cut_id,
                            &at,
                        )
                    } else {
                        vcs.adopt_only(branch_id, &expr, &cut_id, &at)
                    };
                    match outcome {
                        Ok(TransportOutcome::Transported {
                            cut_id,
                            change_id,
                            moved_paths,
                        }) => emit_json(json!({
                            "transported": branch_id,
                            "cut_id": cut_id,
                            "change_id": change_id,
                            "moved_paths": moved_paths,
                        })),
                        Ok(TransportOutcome::UpToDate) => emit_json(json!({
                            "transported": branch_id,
                            "up_to_date": true,
                        })),
                        Ok(TransportOutcome::Conflicted { conflicts }) => {
                            let payload = json!({
                                "conflicted": branch_id,
                                "conflicts":
                                    conflicts.iter().map(conflict_json).collect::<Vec<_>>(),
                            });
                            eprintln!("{transport_like} conflicted: {payload}");
                            ExitCode::FAILURE
                        }
                        Ok(other) => {
                            eprintln!("{transport_like} refused: {other:?}");
                            ExitCode::FAILURE
                        }
                        Err(error) => {
                            eprintln!("branch {transport_like} failed: {error:?}");
                            ExitCode::FAILURE
                        }
                    }
                }
            }
        }
        "conflicts" => {
            let Some(branch_id) = rest.first().copied() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            match vcs.open_conflicts(branch_id) {
                Ok(rows) => match serde_json::to_value(&rows) {
                    Ok(payload) => emit_json(payload),
                    Err(error) => {
                        eprintln!("branch conflicts failed: {error}");
                        ExitCode::FAILURE
                    }
                },
                Err(error) => {
                    eprintln!("branch conflicts failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "resolve" => {
            let (Some(branch_id), Some(path)) = (rest.first().copied(), rest.get(1).copied())
            else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            use whipplescript_store::vcs::{ResolutionChoice, ResolveOutcome};
            let body_arg = rest
                .iter()
                .position(|arg| *arg == "--body")
                .and_then(|index| rest.get(index + 1))
                .copied();
            let choice = if rest.contains(&"--ours") {
                ResolutionChoice::TakeOurs
            } else if rest.contains(&"--theirs") {
                ResolutionChoice::TakeTheirs
            } else if let Some(body) = body_arg {
                ResolutionChoice::Body(body)
            } else {
                eprintln!("`branch resolve` needs --ours, --theirs, or --body\n{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            let cut_id = generated_cut_id();
            match vcs.resolve_conflict(branch_id, path, choice, &cut_id, &at) {
                Ok(ResolveOutcome::Resolved { cut_id, resolution }) => emit_json(json!({
                    "resolved": path,
                    "branch_id": branch_id,
                    "cut_id": cut_id,
                    "resolution": resolution,
                })),
                Ok(ResolveOutcome::NoOpenConflict) => {
                    eprintln!("no open conflict at `{path}` on branch `{branch_id}`");
                    ExitCode::FAILURE
                }
                Ok(other) => {
                    eprintln!("resolve refused: {other:?}");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch resolve failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "undo-op" => {
            // Default target: the newest op — jj's `undo` ergonomics.
            let op_id = match rest.first().copied() {
                Some(op_id) => op_id.to_owned(),
                None => match vcs.list_ops(1) {
                    Ok(ops) => match ops.first() {
                        Some(op) => op.op_id.clone(),
                        None => {
                            eprintln!("the op log is empty; nothing to undo");
                            return ExitCode::FAILURE;
                        }
                    },
                    Err(error) => {
                        eprintln!("branch undo-op failed: {error:?}");
                        return ExitCode::FAILURE;
                    }
                },
            };
            use whipplescript_store::vcs::UndoOpOutcome;
            let undo_op_id = format!("op-undo-{}", generated_cut_id());
            match vcs.undo_op(&op_id, &undo_op_id, &at) {
                Ok(UndoOpOutcome::Undone { undo_op_id }) => emit_json(json!({
                    "undone": op_id,
                    "undo_op_id": undo_op_id,
                })),
                Ok(UndoOpOutcome::HeadMoved {
                    branch_id,
                    current_head_cut_id,
                    expected_head_cut_id,
                }) => {
                    eprintln!(
                        "undo refused: branch `{branch_id}` moved since op `{op_id}` \
                         (head {current_head_cut_id:?}, op left it at {expected_head_cut_id:?}); \
                         undo the newer ops first"
                    );
                    ExitCode::FAILURE
                }
                Ok(UndoOpOutcome::OpMissing) => {
                    eprintln!("no op `{op_id}` in the log");
                    ExitCode::FAILURE
                }
                Ok(UndoOpOutcome::NothingToUndo) => {
                    eprintln!("op `{op_id}` moved no branch pointers; nothing to undo");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch undo-op failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "digest" => {
            let Some(branch_id) = rest.first().copied() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            match vcs.transferable_ids(branch_id) {
                Ok(Some(ids)) => emit_json(json!(ids)),
                Ok(None) => {
                    eprintln!("no such branch `{branch_id}`");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch digest failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "have" => {
            let Some(path) = rest.first().copied() else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            let ids: Vec<String> = match std::fs::read_to_string(path)
                .map_err(|error| error.to_string())
                .and_then(|body| serde_json::from_str(&body).map_err(|error| error.to_string()))
            {
                Ok(ids) => ids,
                Err(error) => {
                    eprintln!("branch have failed reading `{path}`: {error}");
                    return ExitCode::FAILURE;
                }
            };
            match whipplescript_store::bundle::held_subset(&ids, vcs.content_store()) {
                Ok(held) => emit_json(json!(held)),
                Err(error) => {
                    eprintln!("branch have failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "erase" => {
            let (Some(branch_id), Some(path)) = (rest.first(), rest.get(1)) else {
                eprintln!("{BRANCH_USAGE}");
                return ExitCode::from(2);
            };
            use whipplescript_store::content::EraseOutcome;
            match vcs.erase_path(branch_id, path, &at) {
                Ok(Some((hash, EraseOutcome::Erased { byte_len }))) => emit_json(json!({
                    "erased": path,
                    "branch_id": branch_id,
                    "hash": hash,
                    "byte_len": byte_len,
                })),
                Ok(Some((hash, EraseOutcome::AlreadyErased))) => emit_json(json!({
                    "erased": path,
                    "branch_id": branch_id,
                    "hash": hash,
                    "already_erased": true,
                })),
                Ok(Some((hash, other))) => {
                    eprintln!("erase refused for {hash}: {other:?}");
                    ExitCode::FAILURE
                }
                Ok(None) => {
                    eprintln!("no file at `{path}` on branch `{branch_id}`");
                    ExitCode::FAILURE
                }
                Err(error) => {
                    eprintln!("branch erase failed: {error:?}");
                    ExitCode::FAILURE
                }
            }
        }
        "reconcile-list" => match vcs.reconcile_list() {
            Ok(entries) => match serde_json::to_value(&entries) {
                Ok(payload) => emit_json(payload),
                Err(error) => {
                    eprintln!("branch reconcile-list failed: {error}");
                    ExitCode::FAILURE
                }
            },
            Err(error) => {
                eprintln!("branch reconcile-list failed: {error:?}");
                ExitCode::FAILURE
            }
        },
        other => {
            eprintln!("unknown branch verb `{other}`\n{BRANCH_USAGE}");
            ExitCode::from(2)
        }
    }
}

fn generated_cut_id() -> String {
    let nanos = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|elapsed| elapsed.as_nanos())
        .unwrap_or(0);
    format!("cut-{nanos}")
}

fn transition_instance(
    options: &CliOptions,
    usage: &str,
    transition: impl FnOnce(
        &mut RuntimeKernel<SqliteStore>,
        &str,
    ) -> Result<whipplescript_store::StoredEvent, StoreError>,
) -> ExitCode {
    let Some(instance_id) = single_arg(options, usage) else {
        return ExitCode::from(2);
    };
    let store = match open_store_or_exit(options) {
        Ok(store) => store,
        Err(code) => return code,
    };
    let mut kernel = RuntimeKernel::new(store);
    match transition(&mut kernel, instance_id) {
        Ok(event) if options.json => emit_json(json!({
            "instance_id": instance_id,
            "event_id": event.event_id,
            "sequence": event.sequence,
        })),
        Ok(event) => {
            println!("{instance_id} updated at event #{}", event.sequence);
            ExitCode::SUCCESS
        }
        Err(error) => report_store_error("failed to transition instance", error),
    }
}

fn retry(options: &CliOptions) -> ExitCode {
    if options.args.len() != 2 {
        eprintln!("usage: whip retry <instance> <effect>");
        return ExitCode::from(2);
    }
    let instance_id = &options.args[0];
    let effect_id = &options.args[1];
    let store = match open_store_or_exit(options) {
        Ok(store) => store,
        Err(code) => return code,
    };
    let mut kernel = RuntimeKernel::new(store);
    match kernel.retry_effect(RetryEffect {
        instance_id,
        effect_id,
        retry_after: None,
        idempotency_key: Some(&idempotency_key(&[instance_id, "retry", effect_id])),
    }) {
        Ok(event) if options.json => emit_json(json!({
            "instance_id": instance_id,
            "effect_id": effect_id,
            "event_id": event.event_id,
            "sequence": event.sequence,
        })),
        Ok(event) => {
            println!("{effect_id} retried at event #{}", event.sequence);
            ExitCode::SUCCESS
        }
        Err(error) => report_store_error("failed to retry effect", error),
    }
}

fn single_arg<'a>(options: &'a CliOptions, usage: &str) -> Option<&'a str> {
    if options.args.len() == 1 {
        Some(&options.args[0])
    } else {
        eprintln!("{usage}");
        None
    }
}

fn open_store_or_exit(options: &CliOptions) -> Result<SqliteStore, ExitCode> {
    open_store(&options.store_path).map_err(|message| {
        eprintln!("{message}");
        ExitCode::FAILURE
    })
}

fn open_store(path: &Path) -> Result<SqliteStore, String> {
    if path.to_string_lossy() == ":memory:" {
        return SqliteStore::open_in_memory().map_err(store_error);
    }

    if let Some(parent) = path.parent() {
        if !parent.as_os_str().is_empty() {
            fs::create_dir_all(parent).map_err(|error| {
                format!(
                    "failed to create store directory `{}`: {error}",
                    parent.display()
                )
            })?;
            harden_store_directory(parent).map_err(|error| {
                format!(
                    "failed to set private permissions on store directory `{}`: {error}",
                    parent.display()
                )
            })?;
        }
    }

    SqliteStore::open(path).map_err(|error| {
        format!(
            "failed to open store `{}`: {}",
            path.display(),
            store_error(error)
        )
    })
}

#[cfg(unix)]
fn harden_store_directory(path: &Path) -> std::io::Result<()> {
    use std::os::unix::fs::PermissionsExt;

    let mut permissions = fs::metadata(path)?.permissions();
    if permissions.mode() & 0o1000 != 0 {
        return Ok(());
    }
    if permissions.mode() & 0o777 != 0o700 {
        permissions.set_mode(0o700);
        fs::set_permissions(path, permissions)?;
    }
    Ok(())
}

#[cfg(not(unix))]
fn harden_store_directory(_path: &Path) -> std::io::Result<()> {
    Ok(())
}

enum CompileFailure {
    Io(std::io::Error),
    Diagnostics {
        source: String,
        /// Per-file segments of `source` (sorted by start offset) so a
        /// diagnostic span can be attributed back to its originating file.
        /// Empty when the failure is not produced over an include bundle.
        segments: Vec<SourceSegment>,
        diagnostics: Vec<Diagnostic>,
    },
}

fn compile_source_path_with_root(
    path: &str,
    root: Option<&str>,
) -> Result<(String, IrProgram), CompileFailure> {
    let bundle = resolve_source_bundle(Path::new(path))?;
    let compiled = whipplescript_parser::compile_program_with_root(&bundle.source, root);
    for warning in &compiled.warnings {
        eprint!(
            "{}",
            render_bundle_diagnostic(path, &bundle.source, &bundle.segments, warning, "warning")
        );
    }
    if let Some(ir) = compiled.ir {
        let mut ir = ir;
        ir.includes = bundle.includes;
        Ok((bundle.source, ir))
    } else {
        Err(CompileFailure::Diagnostics {
            source: bundle.source,
            segments: bundle.segments,
            diagnostics: compiled.diagnostics,
        })
    }
}

/// Compile for static validation (`check`/`compile`): on top of ordinary
/// compilation this enforces the workflow liveness lints.
fn compile_source_path_for_validation(
    path: &str,
    root: Option<&str>,
) -> Result<(String, IrProgram), CompileFailure> {
    let (source, ir) = compile_source_path_with_root(path, root)?;
    let mut blocking = lint_workflow_liveness(&ir);
    // Script hard-off (M5 import ladder, Layer 1): `exec` is a check error unless
    // the program imports `std.script`. This is the author-facing consent surface;
    // the load-bearing runtime backstop is Layer 2 (S6d-6): import-conditional
    // two-key capability seeding + the store admission gate (`policy_block_on`).
    blocking.extend(check_script_hard_off(&ir));
    if !blocking.is_empty() {
        // Workflow-level diagnostics (span 0 for liveness) render against the root
        // path; the hard-off carries the offending `exec` effect's own span.
        return Err(CompileFailure::Diagnostics {
            source,
            segments: Vec::new(),
            diagnostics: blocking,
        });
    }
    Ok((source, ir))
}

/// Script hard-off, check-time gate (spec/std-script.md "Hard-off semantics",
/// Layer 1): every `exec` source form — raw (`exec "cmd"`) or capability
/// (`exec <name> with <rec> -> <Type>`), which both lower to
/// `IrEffectKind::ExecCommand` — is a check error with id `security.script_disabled`
/// unless the program contains `use std.script`. The import is the author-facing
/// declaration that script execution is intended; without it, scripts are truly
/// off. (Layer 2, the anti-forged-IR runtime backstop, is the two-key seeding in
/// `run_worker_once` + the `script.*` requirement at the store admission gate.)
fn check_script_hard_off(ir: &IrProgram) -> Vec<Diagnostic> {
    if ir.uses.iter().any(|use_decl| use_decl.name == "std.script") {
        return Vec::new();
    }
    let mut diagnostics = Vec::new();
    for rule in &ir.rules {
        for effect in &rule.metadata.effects {
            if effect.kind == IrEffectKind::ExecCommand {
                diagnostics.push(Diagnostic {
                    span: effect.span,
                    message: "`exec` requires `use std.script` (security.script_disabled): script \
                         execution is disabled unless the program imports the std.script package"
                        .to_owned(),
                    suggestion: Some(
                        "add `use std.script` at the top of the program to enable script execution"
                            .to_owned(),
                    ),
                    related: Vec::new(),
                });
            }
        }
    }
    diagnostics
}

/// Whether a rule-body line reaches a `complete`/`fail` terminal — at the start
/// of the (trimmed) line, or nested in an inline block such as
/// `after x succeeds { complete result { … } }`. The trailing space avoids
/// matching identifiers like `complete_count`.
fn line_reaches_terminal(line: &str) -> bool {
    let trimmed = line.trim();
    if trimmed.starts_with("complete ") || trimmed.starts_with("fail ") {
        return true;
    }
    let mut rest = trimmed;
    while let Some(pos) = rest.find('{') {
        let after = rest[pos + 1..].trim_start();
        if after.starts_with("complete ") || after.starts_with("fail ") {
            return true;
        }
        rest = &rest[pos + 1..];
    }
    false
}

/// Static liveness lints: every workflow must be able to terminate, and every
/// rule must have a satisfiable read set. Escape hatches: tag a workflow
/// `@service` when it intentionally runs forever, and tag a rule `@external`
/// when its facts arrive from outside the workflow (plugins, fixtures,
/// external systems).
fn lint_workflow_liveness(ir: &IrProgram) -> Vec<Diagnostic> {
    let mut diagnostics = Vec::new();

    let service_tagged = ir
        .source_tags
        .iter()
        .any(|tag| tag.target_kind == "workflow" && tag.name == "service");
    let has_terminal = ir
        .rules
        .iter()
        .any(|rule| rule.body.lines().any(line_reaches_terminal));
    if !has_terminal && !service_tagged {
        diagnostics.push(Diagnostic { related: Vec::new(),
            span: SourceSpan { start: 0, end: 0 },
            message: format!(
                "workflow `{}` has no rule that reaches `complete` or `fail`",
                ir.workflow
            ),
            suggestion: Some(
                "add a rule that runs `complete <output> { ... }` or `fail <failure> { ... }`, or tag the workflow `@service` if it intentionally runs forever"
                    .to_owned(),
            ),
        });
    }

    let produced = ir
        .rules
        .iter()
        .flat_map(|rule| rule.metadata.fact_writes.iter().cloned())
        .collect::<std::collections::BTreeSet<_>>();
    let input_schemas = ir
        .workflow_contracts
        .iter()
        .filter(|contract| contract.kind == IrWorkflowContractKind::Input)
        .filter_map(|contract| match &contract.ty {
            IrType::Ref(name) => Some(name.clone()),
            _ => None,
        })
        .collect::<std::collections::BTreeSet<_>>();
    let has_human_ask = ir.rules.iter().any(|rule| {
        rule.metadata
            .effects
            .iter()
            .any(|effect| effect.kind == IrEffectKind::HumanAsk)
    });
    let has_tell = ir.rules.iter().any(|rule| {
        rule.metadata
            .effects
            .iter()
            .any(|effect| effect.kind == IrEffectKind::AgentTell)
    });

    // Sub-workflow tool convergence (DR-0025). A `@tool` workflow is invoked
    // synchronously from inside an agent turn, so it must be provably convergent
    // or the turn could block forever. v1 admits the conservative leaf class:
    // terminates (no `@service` escape), depends on no external input (no
    // `@external` rules, no inbound messages), no human gate, and no nested
    // `invoke`. Nested `@tool` composition — which needs the acyclic invoke-graph
    // check the convergence model also covers — is a later refinement.
    let tool_tagged = ir
        .source_tags
        .iter()
        .any(|tag| tag.target_kind == "workflow" && tag.name == "tool");
    if tool_tagged {
        if service_tagged {
            diagnostics.push(Diagnostic {
                related: Vec::new(),
                span: SourceSpan { start: 0, end: 0 },
                message: format!(
                    "workflow `{}` is both `@tool` and `@service`; a `@tool` workflow must terminate",
                    ir.workflow
                ),
                suggestion: Some(
                    "remove `@service` — non-termination is a root-only privilege, not for an invokable sub-workflow"
                        .to_owned(),
                ),
            });
        }
        if has_human_ask {
            diagnostics.push(Diagnostic {
                related: Vec::new(),
                span: SourceSpan { start: 0, end: 0 },
                message: format!(
                    "`@tool` workflow `{}` uses `askHuman`; a synchronously-invoked tool may not block on a human",
                    ir.workflow
                ),
                suggestion: Some(
                    "keep human gates at the root workflow, not in a `@tool` sub-workflow".to_owned(),
                ),
            });
        }
        let has_invoke = ir.rules.iter().any(|rule| {
            rule.metadata
                .effects
                .iter()
                .any(|effect| effect.kind == IrEffectKind::WorkflowInvoke)
        });
        if has_invoke {
            diagnostics.push(Diagnostic {
                related: Vec::new(),
                span: SourceSpan { start: 0, end: 0 },
                message: format!(
                    "`@tool` workflow `{}` invokes a sub-workflow; v1 `@tool` workflows must be leaves",
                    ir.workflow
                ),
                suggestion: Some(
                    "a `@tool` workflow may not `invoke` another workflow yet; nested tool composition (with the acyclic-invoke-graph check) is a later refinement"
                        .to_owned(),
                ),
            });
        }
    }

    for rule in &ir.rules {
        let external_tagged = ir.source_tags.iter().any(|tag| {
            tag.target_kind == "rule" && tag.target == rule.name && tag.name == "external"
        });
        if tool_tagged {
            // A @tool workflow may not depend on external arrival: @external (the
            // "arrives from outside" escape) and inbound messaging break the
            // termination guarantee a synchronous tool needs.
            if external_tagged {
                diagnostics.push(Diagnostic {
                    related: Vec::new(),
                    span: SourceSpan { start: 0, end: 0 },
                    message: format!(
                        "`@tool` workflow `{}` rule `{}` is `@external`; a `@tool` workflow may not depend on external arrival",
                        ir.workflow, rule.name
                    ),
                    suggestion: Some(
                        "a `@tool` sub-workflow must be satisfiable from its own inputs and effects; external-event coordination belongs at the root"
                            .to_owned(),
                    ),
                });
            }
            for when in &rule.whens {
                if when.pattern.trim_start().starts_with("message from") {
                    diagnostics.push(Diagnostic {
                        related: Vec::new(),
                        span: when.span,
                        message: format!(
                            "`@tool` workflow `{}` rule `{}` awaits an inbound message; a `@tool` workflow may not consume external signals",
                            ir.workflow, rule.name
                        ),
                        suggestion: Some(
                            "inbound messaging / signals belong at the root workflow".to_owned(),
                        ),
                    });
                }
            }
        }
        if external_tagged {
            continue;
        }
        for when in &rule.whens {
            let pattern = when.pattern.as_str();
            if pattern == "started" || pattern.ends_with(" is available") {
                continue;
            }
            // General form: `when fact <name> as x`. Sugar phrases reduce to
            // the same runtime fact names.
            let general_name = pattern
                .strip_prefix("fact ")
                .and_then(|rest| rest.split_whitespace().next());
            let pattern = match general_name {
                Some("human.answer.received") => "human answered",
                Some("agent.turn.completed") => "worker completed turn",
                Some(name) if name.contains('.') => {
                    // Other dotted runtime facts arrive from outside the
                    // workflow's own rules; the lint cannot see producers.
                    continue;
                }
                Some(name) => {
                    // `fact ClassName` is an ordinary class match.
                    let read = format!("schema:{name}");
                    if !produced.contains(&read) && !input_schemas.contains(name) {
                        diagnostics.push(Diagnostic { related: Vec::new(),
                            span: when.span,
                            message: format!(
                                "rule `{}` can never fire: nothing produces `{name}`",
                                rule.name
                            ),
                            suggestion: Some(format!(
                                "seed `{name}` from a table, record it in another rule, declare it as a workflow input, or tag the rule `@external` if it arrives from an external system"
                            )),
                        });
                    }
                    continue;
                }
                None => pattern,
            };
            if pattern.starts_with("human answered") {
                if !has_human_ask {
                    diagnostics.push(Diagnostic { related: Vec::new(),
                        span: when.span,
                        message: format!(
                            "rule `{}` can never fire: no rule creates an `askHuman` request",
                            rule.name
                        ),
                        suggestion: Some(
                            "add an `askHuman` effect, or tag the rule `@external` if answers arrive from outside this workflow"
                                .to_owned(),
                        ),
                    });
                }
                continue;
            }
            if pattern.starts_with("worker completed turn") {
                if !has_tell {
                    diagnostics.push(Diagnostic { related: Vec::new(),
                        span: when.span,
                        message: format!(
                            "rule `{}` can never fire: no rule creates an agent turn",
                            rule.name
                        ),
                        suggestion: Some(
                            "add a `tell` effect, or tag the rule `@external` if turns arrive from outside this workflow"
                                .to_owned(),
                        ),
                    });
                }
                continue;
            }
            let first = pattern.split_whitespace().next().unwrap_or_default();
            if !first.chars().next().is_some_and(char::is_uppercase) {
                // Remaining lowercase patterns (manual review) are fed
                // by external systems the lint cannot see.
                continue;
            }
            let builtin = matches!(
                first,
                "AgentTurn"
                    | "WorkItem"
                    | "Evidence"
                    | "HumanAnswer"
                    | "TerminalFailed"
                    | "TerminalTimedOut"
                    | "TerminalCancelled"
            );
            if builtin
                || produced.contains(&format!("schema:{first}"))
                || input_schemas.contains(first)
            {
                continue;
            }
            diagnostics.push(Diagnostic { related: Vec::new(),
                span: when.span,
                message: format!(
                    "rule `{}` can never fire: nothing produces `{first}`",
                    rule.name
                ),
                suggestion: Some(format!(
                    "seed `{first}` from a table, record it in another rule, declare it as a workflow input, or tag the rule `@external` if it arrives from an external system"
                )),
            });
        }
    }

    diagnostics
}

/// Resolve and validate an agent tool grant (DR-0025): a granted name must name a
/// workflow that is `@tool` and passes the convergence check. v1 resolves the
/// name against the SAME program bundle (compile with `root = name`); the
/// cross-package fallthrough is layered on by the caller. Returns the compiled
/// tool IR on success, or a human-readable reason it is not an eligible tool.
fn resolve_same_bundle_tool_grant(program_path: &Path, name: &str) -> Result<IrProgram, String> {
    let (_, ir) =
        compile_source_path_with_root(program_path.to_str().unwrap_or_default(), Some(name))
            .map_err(|_| format!("`{name}` is not a workflow in this program"))?;
    if ir.workflow != name {
        return Err(format!("`{name}` is not a workflow in this program"));
    }
    let is_tool = ir.source_tags.iter().any(|tag| {
        tag.target_kind == "workflow" && tag.target == ir.workflow && tag.name == "tool"
    });
    if !is_tool {
        return Err(format!("`{name}` is not tagged `@tool`"));
    }
    let liveness = lint_workflow_liveness(&ir);
    if let Some(first) = liveness.into_iter().next() {
        return Err(format!(
            "`{name}` is not convergence-eligible: {}",
            first.message
        ));
    }
    Ok(ir)
}

/// Static check for agent `tools [...]` grants (DR-0025): every granted workflow
/// must resolve and be a convergence-eligible `@tool`. Emits the DR's intended
/// diagnostic, *"agent A is granted Z, which is not `@tool`"*. v1 resolves grants
/// against the same bundle; cross-package resolution extends `resolve_tool_grant`.
fn lint_agent_tool_grants(
    program_path: &Path,
    ir: &IrProgram,
    package_lock_path: Option<&Path>,
) -> Vec<Diagnostic> {
    let mut diagnostics = Vec::new();
    for agent in &ir.agents {
        for tool in &agent.tools {
            if let Err(reason) = resolve_tool_grant(program_path, ir, tool, package_lock_path) {
                diagnostics.push(Diagnostic {
                    related: Vec::new(),
                    span: SourceSpan { start: 0, end: 0 },
                    message: format!("agent `{}` is granted `{tool}`: {reason}", agent.name),
                    suggestion: Some(
                        "a granted tool must be a `@tool` workflow that passes the convergence check (same program or a `use`d package)"
                            .to_owned(),
                    ),
                });
            }
        }
    }
    diagnostics
}

/// Resolve an agent tool grant, trying the same bundle first and then any `@tool`
/// workflow exported by a `use`d package (DR-0025). Returns the tool's compiled
/// IR or a reason it is not an eligible tool. The cross-package arm is filled in
/// with the package attestation path.
fn resolve_tool_grant(
    program_path: &Path,
    ir: &IrProgram,
    name: &str,
    package_lock_path: Option<&Path>,
) -> Result<ResolvedToolGrant, String> {
    match resolve_same_bundle_tool_grant(program_path, name) {
        Ok(tool_ir) => Ok(ResolvedToolGrant {
            tool_ir,
            source_path: program_path.to_path_buf(),
            package_id: LOCAL_WORKFLOW_PACKAGE.to_owned(),
        }),
        Err(local_reason) => {
            match resolve_package_tool_grant(program_path, ir, name, package_lock_path) {
                Ok(resolved) => Ok(resolved),
                Err(package_reason) if package_reason.is_empty() => Err(local_reason),
                Err(package_reason) => Err(package_reason),
            }
        }
    }
}

/// A resolved tool grant: the compiled tool workflow IR and the source path it
/// must be driven from (the same bundle, or a package's shipped workflow source).
struct ResolvedToolGrant {
    tool_ir: IrProgram,
    source_path: PathBuf,
    package_id: String,
}

/// Resolve a tool grant against a `use`d package's exported `@tool` workflows
/// (DR-0025 cross-package attestation). The package lock is discovered from the
/// program's directory; each locked manifest's `workflow_tools` were already
/// convergence-checked and attested when the manifest loaded, so resolution here
/// just locates the exporting package and compiles its shipped source for the
/// tool IR. An empty `Err("")` means "no package resolves this name" so the
/// caller keeps the same-bundle reason; a non-empty `Err` is a concrete package
/// rejection (e.g. a broken package lock).
fn resolve_package_tool_grant(
    program_path: &Path,
    ir: &IrProgram,
    name: &str,
    package_lock_path: Option<&Path>,
) -> Result<ResolvedToolGrant, String> {
    let lock = match load_package_lock(package_lock_path, &[program_path]) {
        Ok(Some(lock)) => lock,
        Ok(None) => return Err(String::new()),
        Err(error) => return Err(error),
    };
    // A grant resolves only against a package the program actually `use`s: the
    // lock is the dependency set, but `use` is the explicit import. This keeps the
    // invoke-tool graph's edges tied to declared dependencies.
    let used = |manifest: &PackageManifest| ir.uses.iter().any(|decl| decl.name == manifest.name);
    let resolved = lock.manifests.iter().find_map(|manifest| {
        if !used(manifest) {
            return None;
        }
        manifest
            .workflow_tools
            .iter()
            .find(|tool| tool.name == name)
            .map(|tool| (manifest.package_id.clone(), tool.source.clone()))
    });
    let Some((package_id, source)) = resolved else {
        // A clearer message when the tool exists but its package is not `use`d.
        if let Some(manifest) = lock
            .manifests
            .iter()
            .find(|manifest| manifest.workflow_tools.iter().any(|tool| tool.name == name))
        {
            return Err(format!(
                "`{name}` is exported by package `{}`, which this program does not `use` (add `use {}`)",
                manifest.name, manifest.name
            ));
        }
        return Err(String::new());
    };
    let (_, tool_ir) =
        compile_source_path_with_root(source.to_str().unwrap_or_default(), Some(name)).map_err(
            |error| {
                format!(
                    "package tool `{name}` failed to compile: {}",
                    child_compile_error(name, error)
                )
            },
        )?;
    Ok(ResolvedToolGrant {
        tool_ir,
        source_path: source,
        package_id,
    })
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct SourceBundle {
    source: String,
    includes: Vec<IrInclude>,
    /// Per-file segments of `source`, sorted ascending by start offset. Each
    /// segment marks where one file's OWN text begins in the concatenated
    /// bundle, so a byte offset can be resolved back to (file, in-file offset).
    segments: Vec<SourceSegment>,
}

/// One file's contribution to a concatenated include bundle: `path` names the
/// originating file and `start` is the byte offset in the combined source where
/// that file's own text begins (its region runs to the next segment's start).
#[derive(Clone, Debug, Eq, PartialEq)]
struct SourceSegment {
    start: usize,
    path: String,
}

/// The concatenated text of a single file plus the per-file segment table
/// (offsets relative to the start of `text`).
struct ResolvedSource {
    text: String,
    segments: Vec<SourceSegment>,
}

fn resolve_source_bundle(path: &Path) -> Result<SourceBundle, CompileFailure> {
    let mut resolver = SourceBundleResolver::default();
    let display = path.display().to_string();
    let resolved = resolver.resolve_root(path, display)?;
    Ok(SourceBundle {
        source: resolved.text,
        includes: resolver.includes,
        segments: resolved.segments,
    })
}

#[derive(Default)]
struct SourceBundleResolver {
    visited: Vec<PathBuf>,
    active: Vec<PathBuf>,
    includes: Vec<IrInclude>,
}

impl SourceBundleResolver {
    fn resolve_root(
        &mut self,
        path: &Path,
        display: String,
    ) -> Result<ResolvedSource, CompileFailure> {
        let path = canonical_or_original(path)?;
        self.resolve_file(&path, &display, true)
    }

    fn resolve_file(
        &mut self,
        path: &Path,
        display: &str,
        is_root: bool,
    ) -> Result<ResolvedSource, CompileFailure> {
        if self.active.iter().any(|active| active == path) {
            return Err(CompileFailure::Diagnostics {
                source: String::new(),
                segments: Vec::new(),
                diagnostics: vec![Diagnostic {
                    related: Vec::new(),
                    span: SourceSpan { start: 0, end: 0 },
                    message: format!("include cycle through `{}`", path.display()),
                    suggestion: Some("remove the recursive include".to_owned()),
                }],
            });
        }
        if !is_root && self.visited.iter().any(|visited| visited == path) {
            return Ok(ResolvedSource {
                text: String::new(),
                segments: Vec::new(),
            });
        }

        let source = fs::read_to_string(path).map_err(CompileFailure::Io)?;
        let parsed = whipplescript_parser::parse_program(&source);
        if !parsed.diagnostics.is_empty() {
            // A parse error is confined to this single file; hand back a
            // one-entry segment table so the diagnostic names the real file.
            return Err(CompileFailure::Diagnostics {
                segments: vec![SourceSegment {
                    start: 0,
                    path: display.to_owned(),
                }],
                source,
                diagnostics: parsed.diagnostics,
            });
        }

        self.active.push(path.to_path_buf());
        let mut combined = String::new();
        let mut segments = Vec::new();
        let mut seen_includes = BTreeSet::new();
        for item in &parsed.program.items {
            let Item::Include(include) = item else {
                continue;
            };
            if !seen_includes.insert(include.path.value.clone()) {
                self.active.pop();
                return Err(CompileFailure::Diagnostics {
                    segments: vec![SourceSegment {
                        start: 0,
                        path: display.to_owned(),
                    }],
                    source,
                    diagnostics: vec![Diagnostic {
                        related: Vec::new(),
                        span: include.path.span,
                        message: format!("duplicate include `{}`", include.path.value),
                        suggestion: Some("remove the duplicate include".to_owned()),
                    }],
                });
            }
            let include_path = Path::new(&include.path.value);
            if include_path.is_absolute() {
                self.active.pop();
                return Err(CompileFailure::Diagnostics {
                    segments: vec![SourceSegment {
                        start: 0,
                        path: display.to_owned(),
                    }],
                    source,
                    diagnostics: vec![Diagnostic {
                        related: Vec::new(),
                        span: include.path.span,
                        message: "include paths must be relative".to_owned(),
                        suggestion: Some(
                            "write an include path relative to the current file".to_owned(),
                        ),
                    }],
                });
            }
            if include_path.extension().and_then(|ext| ext.to_str()) != Some("whip") {
                self.active.pop();
                return Err(CompileFailure::Diagnostics {
                    segments: vec![SourceSegment {
                        start: 0,
                        path: display.to_owned(),
                    }],
                    source,
                    diagnostics: vec![Diagnostic {
                        related: Vec::new(),
                        span: include.path.span,
                        message: "only `.whip` includes are supported right now".to_owned(),
                        suggestion: Some("include a `.whip` source library file".to_owned()),
                    }],
                });
            }
            let resolved = path
                .parent()
                .unwrap_or_else(|| Path::new("."))
                .join(include_path);
            let resolved = canonical_or_original(&resolved)?;
            let include_source = fs::read_to_string(&resolved).map_err(CompileFailure::Io)?;
            self.includes.push(IrInclude {
                path: include.path.value.clone(),
                source_hash: Some(stable_hash_hex(&include_source)),
            });
            let included = self.resolve_file(&resolved, &include.path.value, false)?;
            if !included.text.trim().is_empty() {
                let base = combined.len();
                for segment in included.segments {
                    segments.push(SourceSegment {
                        start: segment.start + base,
                        path: segment.path,
                    });
                }
                combined.push_str(&included.text);
                if !combined.ends_with('\n') {
                    combined.push('\n');
                }
                combined.push('\n');
            }
        }
        self.active.pop();
        if !is_root {
            self.visited.push(path.to_path_buf());
        }

        // This file's OWN source is appended after its expanded includes.
        segments.push(SourceSegment {
            start: combined.len(),
            path: display.to_owned(),
        });
        combined.push_str(&source);
        Ok(ResolvedSource {
            text: combined,
            segments,
        })
    }
}

/// Resolve a span's start offset to the originating file. Returns the file's
/// display path plus the `[start, end)` byte bounds of that file's own text in
/// `source`, so callers can render an in-file location. Falls back to the root
/// path spanning the whole source when the table is empty.
fn resolve_span_file<'a>(
    root_path: &'a str,
    source: &'a str,
    segments: &'a [SourceSegment],
    span: SourceSpan,
) -> (&'a str, usize, usize) {
    let mut chosen: Option<(&'a str, usize, usize)> = None;
    for (index, segment) in segments.iter().enumerate() {
        if segment.start > span.start {
            break;
        }
        let end = segments
            .get(index + 1)
            .map(|next| next.start)
            .unwrap_or(source.len());
        chosen = Some((segment.path.as_str(), segment.start, end));
    }
    chosen.unwrap_or((root_path, 0, source.len()))
}

/// Render a diagnostic, attributing it to its originating file via the bundle
/// segment table and reporting an in-file location. When `segments` is empty
/// this degrades to `render_diagnostic_with_severity` over the whole source.
fn render_bundle_diagnostic(
    root_path: &str,
    source: &str,
    segments: &[SourceSegment],
    diagnostic: &Diagnostic,
    severity: &str,
) -> String {
    let (origin, file_start, file_end) =
        resolve_span_file(root_path, source, segments, diagnostic.span);
    let file_text = &source[file_start..file_end.min(source.len())];
    let local = Diagnostic {
        span: SourceSpan {
            start: diagnostic.span.start.saturating_sub(file_start),
            end: diagnostic
                .span
                .end
                .saturating_sub(file_start)
                .min(file_text.len()),
        },
        message: diagnostic.message.clone(),
        suggestion: diagnostic.suggestion.clone(),
        related: diagnostic.related.clone(),
    };
    render_diagnostic_with_severity(origin, file_text, &local, severity)
}

fn canonical_or_original(path: &Path) -> Result<PathBuf, CompileFailure> {
    match fs::canonicalize(path) {
        Ok(path) => Ok(path),
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => {
            Err(CompileFailure::Io(error))
        }
        Err(_) => Ok(path.to_path_buf()),
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct ModelSearchReport {
    searches: usize,
    solutions: usize,
    no_solutions: usize,
    ir_searches: usize,
    artifact_searches: usize,
    obligations: Vec<ModelSearchObligation>,
    ir_obligations_artifact: Option<Value>,
    artifact_obligations_artifact: Option<Value>,
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct ModelSearchObligation {
    category: String,
    index: usize,
    description: String,
    upstream: String,
    predicate: &'static str,
    downstream: String,
    expected: ExpectedSearchResult,
    actual: ExpectedSearchResult,
    span: SourceSpan,
}

impl ModelSearchReport {
    fn empty() -> Self {
        Self {
            searches: 0,
            solutions: 0,
            no_solutions: 0,
            ir_searches: 0,
            artifact_searches: 0,
            obligations: Vec::new(),
            ir_obligations_artifact: None,
            artifact_obligations_artifact: None,
        }
    }

    fn add(&mut self, other: ModelSearchReport) {
        self.searches += other.searches;
        self.solutions += other.solutions;
        self.no_solutions += other.no_solutions;
        self.obligations.extend(other.obligations);
        if let Some(artifact) = other.ir_obligations_artifact {
            self.ir_obligations_artifact = Some(artifact);
        }
        if let Some(artifact) = other.artifact_obligations_artifact {
            self.artifact_obligations_artifact = Some(artifact);
        }
    }
}

fn model_search_report_to_json(report: &ModelSearchReport) -> Value {
    json!({
        "status": "ok",
        "searches": report.searches,
        "solutions": report.solutions,
        "no_solutions": report.no_solutions,
        "ir_searches": report.ir_searches,
        "artifact_searches": report.artifact_searches,
        "obligations": report.obligations.iter().map(model_search_obligation_to_json).collect::<Vec<_>>(),
    })
}

fn model_search_obligation_to_json(obligation: &ModelSearchObligation) -> Value {
    json!({
        "category": obligation.category.as_str(),
        "index": obligation.index,
        "description": obligation.description.as_str(),
        "upstream": obligation.upstream.as_str(),
        "predicate": obligation.predicate,
        "downstream": obligation.downstream.as_str(),
        "expected": obligation.expected.json_label(),
        "actual": obligation.actual.json_label(),
        "status": "ok",
        "source_span": source_span_to_json(obligation.span),
    })
}

fn expected_search_ir_obligation_to_json(index: usize, expected: &ExpectedSearch) -> Value {
    json!({
        "index": index,
        "description": expected.description.as_str(),
        "upstream": expected.upstream.as_str(),
        "predicate": expected.predicate,
        "downstream": expected.downstream.as_str(),
        "expected": expected.outcome.json_label(),
        "source_span": source_span_to_json(expected.span),
    })
}

fn expected_search_artifact_obligation_to_json(obligation: &ModelSearchObligation) -> Value {
    json!({
        "category": obligation.category.as_str(),
        "index": obligation.index,
        "description": obligation.description.as_str(),
        "upstream": obligation.upstream.as_str(),
        "predicate": obligation.predicate,
        "downstream": obligation.downstream.as_str(),
        "expected": obligation.expected.json_label(),
        "source_span": source_span_to_json(obligation.span),
    })
}

fn ir_model_search_obligations_artifact(
    source: &str,
    snapshot: &str,
    expected: &[ExpectedSearch],
) -> Value {
    json!({
        "schema": "whipplescript.ir_model_search_obligations.v0",
        "source_hash": stable_hash_hex(source),
        "ir_hash": stable_hash_hex(snapshot),
        "generator": format!("whipplescript-{}", whipplescript_core::version()),
        "obligations": expected
            .iter()
            .enumerate()
            .map(|(index, expected)| expected_search_ir_obligation_to_json(index + 1, expected))
            .collect::<Vec<_>>(),
    })
}

fn artifact_model_search_obligations_artifact(
    source: &str,
    report: &Value,
    obligations: &[ModelSearchObligation],
) -> Value {
    let graph = report.get("construct_graph").unwrap_or(&Value::Null);
    let lowered = report.get("lowered_ir_report").unwrap_or(&Value::Null);
    let package_contract = report.get("package_contract").unwrap_or(&Value::Null);
    let artifact_obligations = obligations
        .iter()
        .filter(|obligation| obligation.category != "ir")
        .map(expected_search_artifact_obligation_to_json)
        .collect::<Vec<_>>();
    json!({
        "schema": "whipplescript.artifact_model_search_obligations.v0",
        "source_hash": report
            .get("source_hash")
            .and_then(Value::as_str)
            .map(str::to_owned)
            .unwrap_or_else(|| stable_hash_hex(source)),
        "ir_hash": report
            .get("ir_hash")
            .and_then(Value::as_str)
            .unwrap_or_default(),
        "package_contract_digest": package_contract
            .get("package_contract_digest")
            .and_then(Value::as_str)
            .unwrap_or_default(),
        "construct_graph_id": graph
            .get("graph_id")
            .and_then(Value::as_str)
            .unwrap_or_default(),
        "accepted_program_digest": lowered
            .get("accepted_program_digest")
            .and_then(Value::as_str)
            .unwrap_or_default(),
        "generator": format!("whipplescript-{}", whipplescript_core::version()),
        "obligations": artifact_obligations,
    })
}

fn insert_model_search_fields(report: &mut Value, model_report: &ModelSearchReport) {
    insert_json_field(
        report,
        "model_search",
        model_search_report_to_json(model_report),
    );
    if let Some(artifact) = &model_report.ir_obligations_artifact {
        insert_json_field(report, "ir_model_search_obligations", artifact.clone());
    }
    if let Some(artifact) = &model_report.artifact_obligations_artifact {
        insert_json_field(
            report,
            "artifact_model_search_obligations",
            artifact.clone(),
        );
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct MaudeRunOutput {
    stdout: String,
    stderr: String,
}

fn run_model_search(
    path: &str,
    source: &str,
    ir: &IrProgram,
    construct_graph: &Value,
    lowered_ir_report: &Value,
    check_report_entry: &Value,
) -> Result<ModelSearchReport, String> {
    let kernel_path = Path::new("models/maude/kernel.maude");
    if !kernel_path.exists() {
        return Err("models/maude/kernel.maude was not found".to_owned());
    }
    let kernel_path = fs::canonicalize(kernel_path)
        .map_err(|error| format!("failed to resolve Maude kernel path: {error}"))?;
    let (maude_source, expected) = generate_maude_model_search(source, ir, &kernel_path);
    let snapshot = ir.to_snapshot();
    let mut ir_report = run_expected_model_searches(path, source, &maude_source, &expected, "ir")?;
    if !expected.is_empty() {
        ir_report.ir_obligations_artifact = Some(ir_model_search_obligations_artifact(
            source, &snapshot, &expected,
        ));
    }
    let artifact_report = run_artifact_model_search(
        path,
        source,
        construct_graph,
        lowered_ir_report,
        check_report_entry,
    )?;
    let mut report = ModelSearchReport::empty();
    report.ir_searches = ir_report.searches;
    report.artifact_searches = artifact_report.searches;
    report.add(ir_report);
    report.add(artifact_report);
    Ok(report)
}

fn run_expected_model_searches(
    path: &str,
    source: &str,
    maude_source: &str,
    expected: &[ExpectedSearch],
    category: &'static str,
) -> Result<ModelSearchReport, String> {
    if expected.is_empty() {
        return Ok(ModelSearchReport::empty());
    }
    let output = run_maude_source(path, maude_source)?;
    if !output.stderr.is_empty() && output.stdout.is_empty() {
        return Err(format!("Maude produced no stdout\n{}", output.stderr));
    }
    let actual = extract_maude_search_results(&output.stdout);
    let solutions = actual
        .iter()
        .filter(|actual| **actual == ExpectedSearchResult::Solution)
        .count();
    let no_solutions = actual.len() - solutions;
    let expected_solutions = expected
        .iter()
        .filter(|expected| expected.outcome == ExpectedSearchResult::Solution)
        .count();
    let expected_no_solutions = expected.len() - expected_solutions;
    if actual.len() != expected.len() {
        let diagnostic = expected.first().map(|first_expected| Diagnostic {
            related: Vec::new(),
            span: first_expected.span,
            message: format!(
                "model search produced {} result(s), expected {}",
                actual.len(),
                expected.len()
            ),
            suggestion: Some(
                "inspect the generated model checks or rerun with Maude available".to_owned(),
            ),
        });
        return Err(format_model_search_error(
            path,
            source,
            diagnostic.as_ref(),
            &format!(
                "expected {expected_solutions} solution(s) and {expected_no_solutions} no-solution result(s), got {solutions} solution(s) and {no_solutions} no-solution result(s)\n{}{}",
                output.stdout,
                output.stderr
            ),
        ));
    }
    for (index, (expected, actual)) in expected.iter().zip(actual.iter()).enumerate() {
        if expected.outcome != *actual {
            let diagnostic = Diagnostic {
                related: Vec::new(),
                span: expected.span,
                message: format!("model-search counterexample for {}", expected.description),
                suggestion: Some(format!(
                    "expected {}, got {}; inspect generated check {} {} {}",
                    expected.outcome.label(),
                    actual.label(),
                    expected.upstream,
                    expected.predicate,
                    expected.downstream
                )),
            };
            return Err(format_model_search_error(
                path,
                source,
                Some(&diagnostic),
                &format!(
                    "search #{} failed: expected {}, got {}\n{}{}",
                    index + 1,
                    expected.outcome.label(),
                    actual.label(),
                    output.stdout,
                    output.stderr
                ),
            ));
        }
    }
    Ok(ModelSearchReport {
        searches: expected.len(),
        solutions,
        no_solutions,
        ir_searches: 0,
        artifact_searches: 0,
        obligations: expected
            .iter()
            .zip(actual.iter())
            .enumerate()
            .map(|(index, (expected, actual))| ModelSearchObligation {
                category: category.to_owned(),
                index: index + 1,
                description: expected.description.clone(),
                upstream: expected.upstream.clone(),
                predicate: expected.predicate,
                downstream: expected.downstream.clone(),
                expected: expected.outcome,
                actual: *actual,
                span: expected.span,
            })
            .collect(),
        ir_obligations_artifact: None,
        artifact_obligations_artifact: None,
    })
}

fn run_artifact_model_search(
    path: &str,
    source: &str,
    construct_graph: &Value,
    lowered_ir_report: &Value,
    check_report_entry: &Value,
) -> Result<ModelSearchReport, String> {
    let graph_errors = construct_graph_error_diagnostics(construct_graph);
    if !graph_errors.is_empty() {
        return Ok(ModelSearchReport::empty());
    }
    let lowered_errors = lowered_ir_report_error_diagnostics(lowered_ir_report);
    if !lowered_errors.is_empty() {
        return Ok(ModelSearchReport::empty());
    }

    let construct_script = Path::new("scripts/construct-graph-to-maude.py");
    let lowered_script = Path::new("scripts/lowered-ir-to-maude.py");
    let platform_catalog_script = Path::new("scripts/platform-catalog-to-maude.py");
    if !construct_script.exists() || !lowered_script.exists() || !platform_catalog_script.exists() {
        return Err(
            "artifact model-search bridge scripts were not found under scripts/".to_owned(),
        );
    }
    let python = artifact_bridge_python()?;

    let artifact_report_path =
        write_verified_artifact_model_search_bundle(path, check_report_entry)?;
    let platform_catalog_path = match write_artifact_bridge_platform_catalog(path) {
        Ok(path) => path,
        Err(error) => {
            let _ = fs::remove_file(&artifact_report_path);
            return Err(error);
        }
    };
    let result = (|| {
        let construct_source = run_artifact_bridge_script(
            &python,
            construct_script,
            &artifact_report_path,
            &platform_catalog_path,
        )?;
        let lowered_source = run_artifact_bridge_script(
            &python,
            lowered_script,
            &artifact_report_path,
            &platform_catalog_path,
        )?;
        let platform_catalog_source = run_platform_catalog_bridge_script(
            &python,
            platform_catalog_script,
            &platform_catalog_path,
        )?;
        let construct_expected = construct_graph_artifact_expected_searches(construct_graph);
        let lowered_expected =
            lowered_ir_artifact_expected_searches(construct_graph, lowered_ir_report);
        let platform_catalog_expected = platform_catalog_artifact_expected_searches(
            construct_graph,
            &platform_construct_catalog_json(),
        );
        let mut report = run_expected_model_searches(
            path,
            source,
            &construct_source,
            &construct_expected,
            "artifact.construct_graph",
        )?;
        report.add(run_expected_model_searches(
            path,
            source,
            &lowered_source,
            &lowered_expected,
            "artifact.lowered_ir",
        )?);
        report.add(run_expected_model_searches(
            path,
            source,
            &platform_catalog_source,
            &platform_catalog_expected,
            "artifact.platform_catalog",
        )?);
        report.artifact_obligations_artifact = Some(artifact_model_search_obligations_artifact(
            source,
            check_report_entry,
            &report.obligations,
        ));
        Ok(report)
    })();
    let _ = fs::remove_file(&artifact_report_path);
    let _ = fs::remove_file(&platform_catalog_path);
    result
}

fn write_verified_artifact_model_search_bundle(
    path: &str,
    artifact_report: &Value,
) -> Result<PathBuf, String> {
    let path_hash = stable_hash_hex(path);
    let report_path = env::temp_dir().join(format!(
        "whipplescript-verified-artifact-model-search-{}-{path_hash}.json",
        std::process::id()
    ));
    let label = display_path(path);
    let verified_entry = match artifact_report.get("schema").and_then(Value::as_str) {
        Some(CHECK_REPORT_SCHEMA) => {
            verify_check_report_success_shape(artifact_report, &label)?;
            verify_report_entry_artifacts(artifact_report, &label)?;
            verified_report_entry_from_value(artifact_report, &label, &label)?
        }
        Some(COMPILE_REPORT_SCHEMA) => {
            verify_compile_report_success_shape(artifact_report, &label)?;
            verify_report_entry_artifacts(artifact_report, &label)?;
            verified_report_entry_from_value(artifact_report, &label, &label)?
        }
        Some(schema) => {
            return Err(format!(
                "artifact model-search report schema `{schema}` is not supported"
            ))
        }
        None => return Err("artifact model-search report is missing schema".to_owned()),
    };
    let bundle = verified_report_artifacts_json(&[verified_entry], VerifyReportEmit::Artifacts);
    let bytes = serde_json::to_vec(&bundle)
        .map_err(|error| format!("failed to render artifact model-search bundle: {error}"))?;
    fs::write(&report_path, bytes)
        .map_err(|error| format!("failed to write artifact model-search bundle: {error}"))?;
    Ok(report_path)
}

fn write_artifact_bridge_platform_catalog(path: &str) -> Result<PathBuf, String> {
    let path_hash = stable_hash_hex(path);
    let catalog_path = env::temp_dir().join(format!(
        "whipplescript-platform-construct-catalog-{}-{path_hash}.json",
        std::process::id()
    ));
    let bytes = serde_json::to_vec(&platform_construct_catalog_json())
        .map_err(|error| format!("failed to render platform construct catalog: {error}"))?;
    fs::write(&catalog_path, bytes)
        .map_err(|error| format!("failed to write platform construct catalog: {error}"))?;
    Ok(catalog_path)
}

fn artifact_bridge_python() -> Result<String, String> {
    let python = find_executable_in_path(&["python3", "python"], &path_value())
        .ok_or_else(|| "Python executable `python3` was not found on PATH".to_owned())?;
    ensure_python_jsonschema(&python)?;
    Ok(python)
}

fn ensure_python_jsonschema(python: &str) -> Result<(), String> {
    let output = Command::new(python)
        .arg("-c")
        .arg("import jsonschema")
        .output()
        .map_err(|error| format!("failed to run `{python} -c 'import jsonschema'`: {error}"))?;
    if output.status.success() {
        return Ok(());
    }
    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);
    let details = [stdout.trim(), stderr.trim()]
        .into_iter()
        .filter(|part| !part.is_empty())
        .collect::<Vec<_>>()
        .join("\n");
    let suffix = if details.is_empty() {
        String::new()
    } else {
        format!("\n{details}")
    };
    Err(format!(
        "Python package `jsonschema` is required for artifact model-search bridge scripts; run under `nix develop` or install `requirements-dev.txt`{suffix}"
    ))
}

fn run_artifact_bridge_script(
    python: &str,
    script: &Path,
    artifact_report: &Path,
    platform_catalog: &Path,
) -> Result<String, String> {
    let root = env::current_dir().map_err(|error| {
        format!("failed to resolve current directory for artifact bridge script: {error}")
    })?;
    let output = Command::new(python)
        .arg(script)
        .arg("--root")
        .arg(&root)
        .arg("--platform-catalog")
        .arg(platform_catalog)
        .arg(artifact_report)
        .output()
        .map_err(|error| format!("failed to run `{python}`: {error}"))?;
    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
    if !output.status.success() {
        return Err(format!(
            "artifact bridge script `{}` exited with status {:?}\n{}{}",
            script.display(),
            output.status.code(),
            stdout,
            stderr
        ));
    }
    Ok(stdout)
}

fn run_platform_catalog_bridge_script(
    python: &str,
    script: &Path,
    platform_catalog: &Path,
) -> Result<String, String> {
    let root = env::current_dir().map_err(|error| {
        format!("failed to resolve current directory for platform catalog bridge script: {error}")
    })?;
    let output = Command::new(python)
        .arg(script)
        .arg("--root")
        .arg(&root)
        .arg("--platform-catalog")
        .arg(platform_catalog)
        .output()
        .map_err(|error| format!("failed to run `{python}`: {error}"))?;
    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
    if !output.status.success() {
        return Err(format!(
            "platform catalog bridge script `{}` exited with status {:?}\n{}{}",
            script.display(),
            output.status.code(),
            stdout,
            stderr
        ));
    }
    Ok(stdout)
}

fn construct_graph_artifact_expected_searches(graph: &Value) -> Vec<ExpectedSearch> {
    let graph_id = artifact_string(graph, "graph_id");
    let graph_span = construct_graph_first_source_span(graph);
    let mut expected = Vec::new();
    for node in artifact_array(graph, "nodes") {
        let node_id = artifact_string(node, "node_id");
        expected.push(ExpectedSearch {
            outcome: ExpectedSearchResult::Solution,
            span: artifact_source_span(node).unwrap_or(graph_span),
            description: format!("Generated node acceptance for {node_id}."),
            upstream: graph_id.clone(),
            predicate: "nodeAccepted",
            downstream: node_id,
        });
    }
    for edge in artifact_array(graph, "edges") {
        let required_port_id = artifact_string(edge, "required_port_id");
        let provided_port_id = artifact_string(edge, "provided_port_id");
        expected.push(ExpectedSearch {
            outcome: ExpectedSearchResult::Solution,
            span: construct_graph_port_source_span(graph, &required_port_id).unwrap_or(graph_span),
            description: format!(
                "Generated edge acceptance for {required_port_id} -> {provided_port_id}."
            ),
            upstream: required_port_id,
            predicate: "edgeAccepted",
            downstream: provided_port_id,
        });
    }
    expected.push(ExpectedSearch {
        outcome: ExpectedSearchResult::Solution,
        span: graph_span,
        description: "Generated graph aggregation from accepted nodes.".to_owned(),
        upstream: graph_id.clone(),
        predicate: "graphAccepted",
        downstream: graph_id.clone(),
    });
    expected.push(ExpectedSearch {
        outcome: ExpectedSearchResult::Solution,
        span: graph_span,
        description: "Generated accepted program from admitted graph and adequacy evidence."
            .to_owned(),
        upstream: graph_id.clone(),
        predicate: "acceptedProgram",
        downstream: graph_id,
    });
    expected
}

fn lowered_ir_artifact_expected_searches(graph: &Value, report: &Value) -> Vec<ExpectedSearch> {
    let graph_id = artifact_string(graph, "graph_id");
    let graph_span = construct_graph_first_source_span(graph);
    let mut expected = Vec::new();
    for lowering in artifact_array(report, "edge_lowerings") {
        let required_port_id = artifact_string(lowering, "required_port_id");
        let provided_port_id = artifact_string(lowering, "provided_port_id");
        expected.push(ExpectedSearch {
            outcome: ExpectedSearchResult::Solution,
            span: construct_graph_port_source_span(graph, &required_port_id).unwrap_or(graph_span),
            description: format!(
                "Generated edge lowering preservation for {required_port_id} -> {provided_port_id}."
            ),
            upstream: required_port_id,
            predicate: "edgeLoweringPreserved",
            downstream: provided_port_id,
        });
    }
    for lowering in artifact_array(report, "dependency_lowerings") {
        let dependency_ref = artifact_string(lowering, "dependency_ref");
        expected.push(ExpectedSearch {
            outcome: ExpectedSearchResult::Solution,
            span: construct_graph_dependency_source_span(graph, &dependency_ref)
                .unwrap_or(graph_span),
            description: format!(
                "Generated dependency lowering preservation for {dependency_ref}."
            ),
            upstream: graph_id.clone(),
            predicate: "dependencyLoweringPreserved",
            downstream: dependency_ref,
        });
    }
    for lowering in artifact_array(report, "node_lowerings") {
        let node_id = artifact_string(lowering, "node_id");
        expected.push(ExpectedSearch {
            outcome: ExpectedSearchResult::Solution,
            span: construct_graph_node_source_span(graph, &node_id).unwrap_or(graph_span),
            description: format!("Generated node lowering preservation for {node_id}."),
            upstream: graph_id.clone(),
            predicate: "loweringPreservedNode",
            downstream: node_id,
        });
    }
    expected.push(ExpectedSearch {
        outcome: ExpectedSearchResult::Solution,
        span: graph_span,
        description: "Generated lowered IR report boundary.".to_owned(),
        upstream: graph_id.clone(),
        predicate: "graphLoweringBoundaryOk",
        downstream: graph_id.clone(),
    });
    expected.push(ExpectedSearch {
        outcome: ExpectedSearchResult::Solution,
        span: graph_span,
        description: "Generated graph lowering preservation aggregation.".to_owned(),
        upstream: graph_id.clone(),
        predicate: "loweringPreserved",
        downstream: graph_id.clone(),
    });
    for object in artifact_array(report, "core_objects") {
        let object_id = artifact_string(object, "object_id");
        expected.push(ExpectedSearch {
            outcome: ExpectedSearchResult::Solution,
            span: artifact_source_span(object).unwrap_or(graph_span),
            description: format!("Generated runtime object handoff for {object_id}."),
            upstream: graph_id.clone(),
            predicate: "handoffObjectOk",
            downstream: object_id,
        });
    }
    expected.push(ExpectedSearch {
        outcome: ExpectedSearchResult::Solution,
        span: graph_span,
        description: "Generated runtime lifecycle handoff.".to_owned(),
        upstream: graph_id.clone(),
        predicate: "lifecycleHandoffOk",
        downstream: graph_id,
    });
    expected
}

fn platform_catalog_artifact_expected_searches(
    graph: &Value,
    catalog: &Value,
) -> Vec<ExpectedSearch> {
    let graph_span = construct_graph_first_source_span(graph);
    artifact_array(catalog, "lowerings")
        .iter()
        .map(|lowering| {
            let lowering_id = artifact_string(lowering, "id");
            ExpectedSearch {
                outcome: ExpectedSearchResult::Solution,
                span: graph_span,
                description: format!(
                    "Generated platform catalog lifecycle profile for {lowering_id}."
                ),
                upstream: "platform_catalog".to_owned(),
                predicate: "catalogLoweringAccepted",
                downstream: lowering_id,
            }
        })
        .collect()
}

fn artifact_array<'a>(value: &'a Value, key: &str) -> &'a [Value] {
    value
        .get(key)
        .and_then(Value::as_array)
        .map(Vec::as_slice)
        .unwrap_or(&[])
}

fn artifact_string(value: &Value, key: &str) -> String {
    value
        .get(key)
        .and_then(Value::as_str)
        .unwrap_or_default()
        .to_owned()
}

fn artifact_source_span(value: &Value) -> Option<SourceSpan> {
    value.get("source_span").map(source_span_from_artifact_json)
}

fn construct_graph_node_source_span(graph: &Value, node_id: &str) -> Option<SourceSpan> {
    artifact_array(graph, "nodes")
        .iter()
        .find(|node| node.get("node_id").and_then(Value::as_str) == Some(node_id))
        .and_then(artifact_source_span)
}

fn construct_graph_port_source_span(graph: &Value, port_id: &str) -> Option<SourceSpan> {
    artifact_array(graph, "ports")
        .iter()
        .find(|port| port.get("port_id").and_then(Value::as_str) == Some(port_id))
        .and_then(artifact_source_span)
}

fn construct_graph_dependency_source_span(
    graph: &Value,
    dependency_ref: &str,
) -> Option<SourceSpan> {
    artifact_array(graph, "effect_dependencies")
        .iter()
        .find(|dependency| {
            dependency.get("dependency_ref").and_then(Value::as_str) == Some(dependency_ref)
        })
        .and_then(artifact_source_span)
}

fn construct_graph_dependency_span_for_ir_obligation(
    graph: &Value,
    upstream: &str,
    predicate: &str,
    downstream: &str,
) -> Option<SourceSpan> {
    let dependency_predicate = match predicate {
        "succeeds" | "fails" | "completes" => predicate,
        "revision-completes-cancelled" => "completes",
        _ => return None,
    };
    let spans = artifact_array(graph, "effect_dependencies")
        .iter()
        .filter(|dependency| {
            dependency.get("predicate").and_then(Value::as_str) == Some(dependency_predicate)
                && dependency_effect_node_matches(
                    dependency.get("upstream_node_id").and_then(Value::as_str),
                    upstream,
                )
                && dependency_effect_node_matches(
                    dependency.get("downstream_node_id").and_then(Value::as_str),
                    downstream,
                )
        })
        .filter_map(artifact_source_span)
        .collect::<Vec<_>>();
    (spans.len() == 1).then(|| spans[0])
}

fn construct_graph_assertion_span_for_ir_obligation(
    graph: &Value,
    upstream: &str,
    predicate: &str,
    downstream: &str,
) -> Option<SourceSpan> {
    if predicate != "assertion-read-only" || downstream != "ruleCommitEvt" {
        return None;
    }
    let assertion_index = upstream
        .strip_prefix("assertion")
        .and_then(|value| value.parse::<usize>().ok())?;
    if assertion_index == 0 {
        return None;
    }
    let assertion_spans = artifact_array(graph, "nodes")
        .iter()
        .filter(|node| node.get("construct_family").and_then(Value::as_str) == Some("assertion"))
        .filter_map(artifact_source_span)
        .collect::<Vec<_>>();
    assertion_spans.get(assertion_index - 1).copied()
}

fn construct_graph_revision_rule_span_for_ir_obligation(
    graph: &Value,
    upstream: &str,
    predicate: &str,
) -> Option<SourceSpan> {
    if !matches!(predicate, "revision-active-rule" | "revision-stale-rule") {
        return None;
    }
    let spans = artifact_array(graph, "nodes")
        .iter()
        .filter(|node| {
            node.get("construct_family").and_then(Value::as_str) == Some("rule")
                && node
                    .get("metadata")
                    .and_then(|metadata| metadata.get("rule_name"))
                    .and_then(Value::as_str)
                    == Some(upstream)
                && node
                    .get("node_id")
                    .and_then(Value::as_str)
                    .is_some_and(|node_id| node_id.ends_with(":when0"))
        })
        .filter_map(artifact_source_span)
        .collect::<Vec<_>>();
    (spans.len() == 1).then(|| spans[0])
}

fn construct_graph_revision_effect_span_for_ir_obligation(
    graph: &Value,
    upstream: &str,
    predicate: &str,
    downstream: &str,
) -> Option<SourceSpan> {
    if predicate != "revision-effect-attribution" || downstream != "effectVersion" {
        return None;
    }
    let spans = artifact_array(graph, "nodes")
        .iter()
        .filter(|node| {
            node.get("construct_family").and_then(Value::as_str) == Some("effect_operation")
                && dependency_effect_node_matches(
                    node.get("node_id").and_then(Value::as_str),
                    upstream,
                )
        })
        .filter_map(artifact_source_span)
        .collect::<Vec<_>>();
    (spans.len() == 1).then(|| spans[0])
}

fn construct_graph_compiler_anchor_spans(
    graph: &Value,
    predicate_prefix: &str,
    required_refs: &[&str],
) -> Vec<SourceSpan> {
    artifact_array(graph, "derived_facts")
        .iter()
        .filter(|fact| {
            fact.get("owner_subsystem").and_then(Value::as_str) == Some("compiler")
                && fact
                    .get("predicate")
                    .and_then(Value::as_str)
                    .is_some_and(|predicate| predicate.starts_with(predicate_prefix))
        })
        .filter(|fact| {
            let refs = artifact_array(fact, "input_refs")
                .iter()
                .filter_map(Value::as_str)
                .collect::<BTreeSet<_>>();
            required_refs.iter().all(|required| refs.contains(required))
        })
        .filter_map(|fact| {
            fact.get("diagnostic_span")
                .map(source_span_from_artifact_json)
        })
        .collect()
}

fn construct_graph_guard_span_for_ir_obligation(
    graph: &Value,
    upstream: &str,
    predicate: &str,
) -> Option<SourceSpan> {
    if !matches!(predicate, "guard-true" | "guard-false" | "guard-error") {
        return None;
    }
    let rule_ref = format!("rule:{upstream}");
    let spans = construct_graph_compiler_anchor_spans(
        graph,
        "model_search.guard_source:",
        &[rule_ref.as_str(), "kind:guard"],
    );
    (spans.len() == 1).then(|| spans[0])
}

fn terminal_tag_from_model_search_description(
    rule_name: &str,
    description: &str,
) -> Option<String> {
    let prefix = format!("{rule_name} terminal ");
    let rest = description.strip_prefix(&prefix)?;
    for suffix in [
        " branch commits on matching tag",
        " branch misses on other tag",
        " false guard cannot commit",
        " exhaustive miss diagnoses",
    ] {
        if let Some(tag) = rest.strip_suffix(suffix).filter(|tag| !tag.is_empty()) {
            return Some(tag.to_owned());
        }
    }
    None
}

fn construct_graph_terminal_branch_span_for_ir_obligation(
    graph: &Value,
    description: &str,
    upstream: &str,
    predicate: &str,
) -> Option<SourceSpan> {
    if !matches!(
        predicate,
        "terminal-branch-match"
            | "terminal-branch-miss"
            | "terminal-branch-guard-false"
            | "terminal-exhaustive-miss"
    ) {
        return None;
    }
    let tag = terminal_tag_from_model_search_description(upstream, description)?;
    let rule_ref = format!("rule:{upstream}");
    let tag_ref = format!("tag:{tag}");
    let spans = construct_graph_compiler_anchor_spans(
        graph,
        "model_search.terminal_branch_source:",
        &[rule_ref.as_str(), tag_ref.as_str(), "kind:terminal_branch"],
    );
    (spans.len() == 1).then(|| spans[0])
}

fn construct_graph_span_for_ir_obligation(
    graph: &Value,
    description: &str,
    upstream: &str,
    predicate: &str,
    downstream: &str,
) -> Option<(&'static str, SourceSpan)> {
    let checks = [
        (
            "dependency",
            construct_graph_dependency_span_for_ir_obligation(
                graph, upstream, predicate, downstream,
            ),
        ),
        (
            "assertion",
            construct_graph_assertion_span_for_ir_obligation(
                graph, upstream, predicate, downstream,
            ),
        ),
        (
            "revision rule",
            construct_graph_revision_rule_span_for_ir_obligation(graph, upstream, predicate),
        ),
        (
            "revision effect",
            construct_graph_revision_effect_span_for_ir_obligation(
                graph, upstream, predicate, downstream,
            ),
        ),
        (
            "guard",
            construct_graph_guard_span_for_ir_obligation(graph, upstream, predicate),
        ),
        (
            "terminal branch",
            construct_graph_terminal_branch_span_for_ir_obligation(
                graph,
                description,
                upstream,
                predicate,
            ),
        ),
    ];
    let matches = checks
        .into_iter()
        .filter_map(|(kind, span)| span.map(|span| (kind, span)))
        .collect::<Vec<_>>();
    (matches.len() == 1).then(|| matches[0])
}

fn dependency_effect_node_matches(node_id: Option<&str>, effect_id: &str) -> bool {
    let Some(node_id) = node_id else {
        return false;
    };
    let Some(rest) = node_id.strip_prefix("effect:") else {
        return false;
    };
    rest.rsplit(':').next() == Some(effect_id)
}

fn construct_graph_first_source_span(graph: &Value) -> SourceSpan {
    graph
        .get("nodes")
        .and_then(Value::as_array)
        .and_then(|nodes| nodes.first())
        .and_then(|node| node.get("source_span"))
        .map(source_span_from_artifact_json)
        .unwrap_or(SourceSpan { start: 0, end: 0 })
}

fn source_span_from_artifact_json(value: &Value) -> SourceSpan {
    let start = value
        .get("start")
        .and_then(Value::as_u64)
        .and_then(|value| usize::try_from(value).ok())
        .unwrap_or_default();
    let end = value
        .get("end")
        .and_then(Value::as_u64)
        .and_then(|value| usize::try_from(value).ok())
        .unwrap_or(start);
    SourceSpan { start, end }
}

fn run_maude_source(label: &str, source: &str) -> Result<MaudeRunOutput, String> {
    let path_hash = stable_hash_hex(label);
    let model_path = env::temp_dir().join(format!(
        "whipplescript-model-search-{}-{path_hash}.maude",
        std::process::id()
    ));
    fs::write(&model_path, source)
        .map_err(|error| format!("failed to write generated Maude file: {error}"))?;
    let maude = match find_executable_in_path(&["maude"], &path_value()) {
        Some(maude) => maude,
        None => {
            let _ = fs::remove_file(&model_path);
            return Err("Maude executable `maude` was not found on PATH".to_owned());
        }
    };
    let output = Command::new(&maude)
        .arg(&model_path)
        .output()
        .map_err(|error| format!("failed to run `{maude}`: {error}"))?;
    let _ = fs::remove_file(&model_path);
    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
    if !output.status.success() {
        return Err(format!(
            "Maude exited with status {:?}\n{}{}",
            output.status.code(),
            stdout,
            stderr
        ));
    }
    Ok(MaudeRunOutput { stdout, stderr })
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum ExpectedSearchResult {
    Solution,
    NoSolution,
}

impl ExpectedSearchResult {
    fn label(&self) -> &'static str {
        match self {
            Self::Solution => "solution",
            Self::NoSolution => "no solution",
        }
    }

    fn json_label(&self) -> &'static str {
        match self {
            Self::Solution => "solution",
            Self::NoSolution => "no_solution",
        }
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct ExpectedSearch {
    outcome: ExpectedSearchResult,
    span: SourceSpan,
    description: String,
    upstream: String,
    predicate: &'static str,
    downstream: String,
}

#[derive(Clone, Debug)]
struct MaudeBoolCases {
    true_expr: String,
    false_expr: String,
    error_expr: String,
}

#[derive(Default)]
struct MaudeExprContext {
    scalar_symbols: std::collections::BTreeMap<String, String>,
    query_symbols: std::collections::BTreeMap<String, String>,
}

fn generate_maude_model_search(
    source: &str,
    ir: &IrProgram,
    kernel_path: &Path,
) -> (String, Vec<ExpectedSearch>) {
    let mut effect_symbols = std::collections::BTreeMap::<String, String>::new();
    let mut rule_symbols = std::collections::BTreeMap::<String, String>::new();
    let mut fact_symbols = std::collections::BTreeMap::<String, String>::new();
    let mut graph_symbols = std::collections::BTreeMap::<String, String>::new();
    let mut assertion_symbols = std::collections::BTreeMap::<usize, String>::new();
    // Composition symbols (workflow/pattern/invoke kernel rules). These are
    // synthesized concrete ops for otherwise-abstract kernel sorts so the
    // generated module can search the elaborate-pattern, complete/fail-workflow
    // and workflow-invocation rules against real compiled IR.
    let mut pattern_symbols = std::collections::BTreeMap::<String, String>::new();
    let mut application_symbols = std::collections::BTreeMap::<String, String>::new();
    let mut workflow_symbols = std::collections::BTreeMap::<String, String>::new();
    let mut instance_symbols = std::collections::BTreeMap::<String, String>::new();
    let mut output_symbols = std::collections::BTreeMap::<String, String>::new();
    let mut failure_symbols = std::collections::BTreeMap::<String, String>::new();
    let mut expr_context = MaudeExprContext::default();
    for rule in &ir.rules {
        rule_symbols
            .entry(rule.name.clone())
            .or_insert_with(|| maude_symbol("rule", &rule.name));
        for when in &rule.whens {
            if let Some(guard) = &when.guard {
                let _ = maude_bool_cases(&guard.expr, &mut expr_context);
            }
        }
        for (when_index, when) in rule.whens.iter().enumerate() {
            let fact_key = rule_fact_key(&rule.name, when_index, &when.pattern);
            fact_symbols
                .entry(fact_key.clone())
                .or_insert_with(|| maude_symbol("fact", &fact_key));
            let graph_key = rule_graph_key(&rule.name, when_index);
            graph_symbols
                .entry(graph_key.clone())
                .or_insert_with(|| maude_symbol("graph", &graph_key));
        }
        for branch in &rule.metadata.terminal_branches {
            let graph_key = terminal_branch_graph_key(&rule.name, branch);
            graph_symbols
                .entry(graph_key.clone())
                .or_insert_with(|| maude_symbol("graph", &graph_key));
            if let Some(guard) = &branch.guard {
                let _ = maude_bool_cases(&guard.expr, &mut expr_context);
            }
        }
        for effect in &rule.metadata.effects {
            let key = effect_key(&rule.name, &effect.id);
            effect_symbols
                .entry(key.clone())
                .or_insert_with(|| maude_symbol("eff", &key));
        }
    }
    for (index, assertion) in ir.assertions.iter().enumerate() {
        assertion_symbols
            .entry(index)
            .or_insert_with(|| maude_symbol("assertion", &assertion_key(index, assertion)));
        let _ = maude_bool_cases(&assertion.expr.expr, &mut expr_context);
    }
    collect_composition_symbols(
        ir,
        &mut rule_symbols,
        &mut fact_symbols,
        &mut graph_symbols,
        &mut pattern_symbols,
        &mut application_symbols,
        &mut workflow_symbols,
        &mut instance_symbols,
        &mut output_symbols,
        &mut failure_symbols,
    );

    let mut output = String::new();
    let mut expected = Vec::new();
    output.push_str(&format!("load {}\n\n", kernel_path.display()));
    output.push_str("mod WHIPPLESCRIPT-GENERATED-CHECK is\n");
    output.push_str("  including WHIPPLESCRIPT-KERNEL .\n");
    append_maude_ops(&mut output, effect_symbols.values(), "EffectId");
    append_maude_ops(&mut output, rule_symbols.values(), "RuleId");
    append_maude_ops(&mut output, fact_symbols.values(), "FactId");
    append_maude_ops(&mut output, graph_symbols.values(), "GraphId");
    append_maude_ops(&mut output, assertion_symbols.values(), "AssertionId");
    append_maude_ops(&mut output, expr_context.scalar_symbols.values(), "Scalar");
    append_maude_ops(&mut output, expr_context.query_symbols.values(), "QueryId");
    append_maude_ops(&mut output, pattern_symbols.values(), "PatternId");
    append_maude_ops(&mut output, application_symbols.values(), "ApplicationId");
    append_maude_ops(&mut output, workflow_symbols.values(), "WorkflowId");
    append_maude_ops(&mut output, instance_symbols.values(), "InstanceId");
    append_maude_ops(&mut output, output_symbols.values(), "OutputId");
    append_maude_ops(&mut output, failure_symbols.values(), "FailureId");
    output.push_str("endm\n\n");

    for rule in &ir.rules {
        for (when_index, when) in rule.whens.iter().enumerate() {
            let Some(guard) = &when.guard else {
                continue;
            };
            let Some(rule_symbol) = rule_symbols.get(&rule.name) else {
                continue;
            };
            let fact_key = rule_fact_key(&rule.name, when_index, &when.pattern);
            let Some(fact_symbol) = fact_symbols.get(&fact_key) else {
                continue;
            };
            let graph_key = rule_graph_key(&rule.name, when_index);
            let Some(graph_symbol) = graph_symbols.get(&graph_key) else {
                continue;
            };
            let cases = maude_bool_cases(&guard.expr, &mut expr_context);
            output.push_str(&format!(
                "--- {}: lowered true guard permits rule commit for `{}`.\n",
                rule.name, guard.source
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  fact({fact_symbol}) rule({rule_symbol}, {fact_symbol}, {graph_symbol}) guardExpr({rule_symbol}, {fact_symbol}, {})\n  =>*\n  fact({fact_symbol}) rule({rule_symbol}, {fact_symbol}, {graph_symbol}) ruleFired({rule_symbol}, {fact_symbol}, {graph_symbol}) graphReady({graph_symbol}) event(ruleCommitEvt) .\n\n",
                cases.true_expr
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::Solution,
                span: guard.span,
                description: format!("{} true guard commits rule", rule.name),
                upstream: rule.name.clone(),
                predicate: "guard-true",
                downstream: "ruleCommitEvt".to_owned(),
            });

            output.push_str(&format!(
                "--- {}: lowered false guard cannot commit rule for `{}`.\n",
                rule.name, guard.source
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  fact({fact_symbol}) rule({rule_symbol}, {fact_symbol}, {graph_symbol}) guardExpr({rule_symbol}, {fact_symbol}, {})\n  =>*\n  event(ruleCommitEvt) RESIDUAL:Cfg .\n\n",
                cases.false_expr
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::NoSolution,
                span: guard.span,
                description: format!("{} false guard cannot commit rule", rule.name),
                upstream: rule.name.clone(),
                predicate: "guard-false",
                downstream: "ruleCommitEvt".to_owned(),
            });

            output.push_str(&format!(
                "--- {}: lowered guard error emits a diagnostic and cannot commit rule for `{}`.\n",
                rule.name, guard.source
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  fact({fact_symbol}) rule({rule_symbol}, {fact_symbol}, {graph_symbol}) guardExpr({rule_symbol}, {fact_symbol}, {})\n  =>*\n  fact({fact_symbol}) rule({rule_symbol}, {fact_symbol}, {graph_symbol}) diagnostic({rule_symbol}) .\n\n",
                cases.error_expr
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::Solution,
                span: guard.span,
                description: format!("{} guard error emits diagnostic", rule.name),
                upstream: rule.name.clone(),
                predicate: "guard-error",
                downstream: "diagnostic".to_owned(),
            });

            output.push_str(&format!(
                "--- {}: guard error cannot commit rule for `{}`.\n",
                rule.name, guard.source
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  fact({fact_symbol}) rule({rule_symbol}, {fact_symbol}, {graph_symbol}) guardExpr({rule_symbol}, {fact_symbol}, {})\n  =>*\n  event(ruleCommitEvt) RESIDUAL:Cfg .\n\n",
                cases.error_expr
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::NoSolution,
                span: guard.span,
                description: format!("{} guard error cannot commit rule", rule.name),
                upstream: rule.name.clone(),
                predicate: "guard-error",
                downstream: "ruleCommitEvt".to_owned(),
            });
        }

        for dependency in &rule.metadata.dependencies {
            let upstream_key = effect_key(&rule.name, &dependency.upstream);
            let downstream_key = effect_key(&rule.name, &dependency.downstream);
            let Some(upstream) = effect_symbols.get(&upstream_key) else {
                continue;
            };
            let Some(downstream) = effect_symbols.get(&downstream_key) else {
                continue;
            };
            let predicate = maude_predicate(&dependency.predicate);
            let terminal = satisfying_terminal(&dependency.predicate);
            let span = dependency_source_span(source, &dependency.upstream, predicate);
            output.push_str(&format!(
                "--- {}: {} --{}--> {} cannot run before upstream terminal.\n",
                rule.name, dependency.upstream, predicate, dependency.downstream
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  effect({upstream}, queued) dep({upstream}, {predicate}, {downstream}) effect({downstream}, blocked)\n  =>*\n  effect({upstream}, queued) dep({upstream}, {predicate}, {downstream}) effect({downstream}, running) .\n\n"
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::NoSolution,
                span,
                description: format!(
                    "{} --{}--> {} cannot run before upstream terminal",
                    dependency.upstream, predicate, dependency.downstream
                ),
                upstream: dependency.upstream.clone(),
                predicate,
                downstream: dependency.downstream.clone(),
            });

            output.push_str(&format!(
                "--- {}: satisfying terminal releases downstream.\n",
                rule.name
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  effect({upstream}, {terminal}) dep({upstream}, {predicate}, {downstream}) effect({downstream}, blocked)\n  =>*\n  effect({upstream}, {terminal}) dep({upstream}, {predicate}, {downstream}) effect({downstream}, running) .\n\n"
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::Solution,
                span,
                description: format!(
                    "{} --{}--> {} releases after satisfying terminal",
                    dependency.upstream, predicate, dependency.downstream
                ),
                upstream: dependency.upstream.clone(),
                predicate,
                downstream: dependency.downstream.clone(),
            });

            if let Some(non_terminal) = non_satisfying_terminal(&dependency.predicate) {
                output.push_str(&format!(
                    "--- {}: non-satisfying terminal does not release downstream.\n",
                    rule.name
                ));
                output.push_str(&format!(
                    "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  effect({upstream}, {non_terminal}) dep({upstream}, {predicate}, {downstream}) effect({downstream}, blocked)\n  =>*\n  effect({upstream}, {non_terminal}) dep({upstream}, {predicate}, {downstream}) effect({downstream}, running) .\n\n"
                ));
                expected.push(ExpectedSearch {
                    outcome: ExpectedSearchResult::NoSolution,
                    span,
                    description: format!(
                        "{} --{}--> {} does not release after non-satisfying terminal",
                        dependency.upstream, predicate, dependency.downstream
                    ),
                    upstream: dependency.upstream.clone(),
                    predicate,
                    downstream: dependency.downstream.clone(),
                });
            }
        }
        append_revision_model_searches(
            source,
            &mut output,
            &mut expected,
            rule,
            &rule_symbols,
            &fact_symbols,
            &graph_symbols,
            &effect_symbols,
        );
        for branch in &rule.metadata.terminal_branches {
            let Some(tag) = branch.tag.as_deref() else {
                continue;
            };
            let Some(rule_symbol) = rule_symbols.get(&rule.name) else {
                continue;
            };
            let Some(first_when) = rule.whens.first() else {
                continue;
            };
            let first_fact_key = rule_fact_key(&rule.name, 0, &first_when.pattern);
            let Some(fact_symbol) = fact_symbols.get(&first_fact_key) else {
                continue;
            };
            let graph_key = terminal_branch_graph_key(&rule.name, branch);
            let Some(graph_symbol) = graph_symbols.get(&graph_key) else {
                continue;
            };
            let tag_symbol = maude_terminal_tag(tag);
            let miss_tag_symbol = maude_terminal_miss_tag(tag);
            let guard_cases = branch
                .guard
                .as_ref()
                .map(|guard| maude_bool_cases(&guard.expr, &mut expr_context));
            let matching_gate = if let Some(cases) = &guard_cases {
                format!(
                    "terminalBranchGuard({rule_symbol}, {fact_symbol}, {tag_symbol}, {tag_symbol}, {}, {graph_symbol})",
                    cases.true_expr
                )
            } else {
                format!(
                    "terminalBranch({rule_symbol}, {fact_symbol}, {tag_symbol}, {tag_symbol}, {graph_symbol})"
                )
            };
            output.push_str(&format!(
                "--- {}: terminal branch `{tag}` commits only for matching terminal tag.\n",
                rule.name
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  fact({fact_symbol}) rule({rule_symbol}, {fact_symbol}, {graph_symbol}) {matching_gate} graph({graph_symbol}, tellEff)\n  =>*\n  fact({fact_symbol}) rule({rule_symbol}, {fact_symbol}, {graph_symbol}) ruleFired({rule_symbol}, {fact_symbol}, {graph_symbol}) event(ruleCommitEvt) graphCommitted({graph_symbol}) effect(tellEff, queued) .\n\n"
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::Solution,
                span: branch.pattern_span,
                description: format!(
                    "{} terminal {tag} branch commits on matching tag",
                    rule.name
                ),
                upstream: rule.name.clone(),
                predicate: "terminal-branch-match",
                downstream: "ruleCommitEvt".to_owned(),
            });

            let miss_gate = if let Some(cases) = &guard_cases {
                format!(
                    "terminalBranchGuard({rule_symbol}, {fact_symbol}, {miss_tag_symbol}, {tag_symbol}, {}, {graph_symbol})",
                    cases.true_expr
                )
            } else {
                format!(
                    "terminalBranch({rule_symbol}, {fact_symbol}, {miss_tag_symbol}, {tag_symbol}, {graph_symbol})"
                )
            };
            output.push_str(&format!(
                "--- {}: terminal branch `{tag}` cannot commit for another terminal tag.\n",
                rule.name
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  fact({fact_symbol}) rule({rule_symbol}, {fact_symbol}, {graph_symbol}) {miss_gate} graph({graph_symbol}, tellEff)\n  =>*\n  event(ruleCommitEvt) RESIDUAL:Cfg .\n\n"
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::NoSolution,
                span: branch.pattern_span,
                description: format!("{} terminal {tag} branch misses on other tag", rule.name),
                upstream: rule.name.clone(),
                predicate: "terminal-branch-miss",
                downstream: "ruleCommitEvt".to_owned(),
            });

            if let Some(cases) = &guard_cases {
                output.push_str(&format!(
                    "--- {}: terminal branch `{tag}` cannot commit when its branch guard is false.\n",
                    rule.name
                ));
                output.push_str(&format!(
                    "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  fact({fact_symbol}) rule({rule_symbol}, {fact_symbol}, {graph_symbol}) terminalBranchGuard({rule_symbol}, {fact_symbol}, {tag_symbol}, {tag_symbol}, {}, {graph_symbol}) graph({graph_symbol}, tellEff)\n  =>*\n  event(ruleCommitEvt) RESIDUAL:Cfg .\n\n",
                    cases.false_expr
                ));
                expected.push(ExpectedSearch {
                    outcome: ExpectedSearchResult::NoSolution,
                    span: branch.pattern_span,
                    description: format!("{} terminal {tag} false guard cannot commit", rule.name),
                    upstream: rule.name.clone(),
                    predicate: "terminal-branch-guard-false",
                    downstream: "ruleCommitEvt".to_owned(),
                });
            }

            output.push_str(&format!(
                "--- {}: exhaustive terminal branch miss emits a diagnostic.\n",
                rule.name
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  fact({fact_symbol}) exhaustiveTerminal({rule_symbol}, {fact_symbol}, {miss_tag_symbol}, {tag_symbol})\n  =>*\n  fact({fact_symbol}) diagnostic({rule_symbol}) .\n\n"
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::Solution,
                span: branch.pattern_span,
                description: format!("{} terminal {tag} exhaustive miss diagnoses", rule.name),
                upstream: rule.name.clone(),
                predicate: "terminal-exhaustive-miss",
                downstream: "diagnostic".to_owned(),
            });
        }
    }

    for (index, assertion) in ir.assertions.iter().enumerate() {
        let Some(assertion_symbol) = assertion_symbols.get(&index) else {
            continue;
        };
        let cases = maude_bool_cases(&assertion.expr.expr, &mut expr_context);
        for (result, expr) in [
            ("aPass", &cases.true_expr),
            ("aFail", &cases.false_expr),
            ("aError", &cases.error_expr),
        ] {
            output.push_str(&format!(
                "--- assertion {}: lowered {result} cannot mutate runtime state.\n",
                index + 1
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  assertionExpr({assertion_symbol}, {expr})\n  =>*\n  event(ruleCommitEvt) RESIDUAL:Cfg .\n\n"
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::NoSolution,
                span: assertion.expr.span,
                description: format!(
                    "assertion {} {result} cannot mutate runtime state",
                    index + 1
                ),
                upstream: format!("assertion{}", index + 1),
                predicate: "assertion-read-only",
                downstream: "ruleCommitEvt".to_owned(),
            });
        }
    }

    append_composition_model_searches(
        ir,
        &mut output,
        &mut expected,
        &rule_symbols,
        &fact_symbols,
        &graph_symbols,
        &effect_symbols,
        &pattern_symbols,
        &application_symbols,
        &workflow_symbols,
        &instance_symbols,
        &output_symbols,
        &failure_symbols,
    );

    (output, expected)
}

fn pattern_app_rule_key(alias: &str) -> String {
    format!("pattern:{alias}:rule")
}

fn pattern_app_fact_key(alias: &str) -> String {
    format!("pattern:{alias}:fact")
}

fn pattern_app_graph_key(alias: &str) -> String {
    format!("pattern:{alias}:graph")
}

fn workflow_instance_key(workflow: &str) -> String {
    format!("workflow:{workflow}:instance")
}

fn complete_fact_key(workflow: &str, output: &str) -> String {
    format!("complete:{workflow}:{output}")
}

fn fail_fact_key(workflow: &str, failure: &str) -> String {
    format!("fail:{workflow}:{failure}")
}

fn invoke_child_instance_key(rule: &str, effect_id: &str) -> String {
    format!("invoke:{rule}:{effect_id}:child")
}

fn invoke_target_workflow_key(rule: &str, effect_id: &str) -> String {
    format!("invoke:{rule}:{effect_id}:workflow")
}

fn invoke_payload_fact_key(rule: &str, effect_id: &str) -> String {
    format!("invoke:{rule}:{effect_id}:payload")
}

/// Register the synthetic concrete ops needed to exercise the workflow
/// composition kernel rules (pattern elaboration, workflow completion/failure
/// and workflow invocation) against real compiled IR.
#[allow(clippy::too_many_arguments)]
fn collect_composition_symbols(
    ir: &IrProgram,
    rule_symbols: &mut BTreeMap<String, String>,
    fact_symbols: &mut BTreeMap<String, String>,
    graph_symbols: &mut BTreeMap<String, String>,
    pattern_symbols: &mut BTreeMap<String, String>,
    application_symbols: &mut BTreeMap<String, String>,
    workflow_symbols: &mut BTreeMap<String, String>,
    instance_symbols: &mut BTreeMap<String, String>,
    output_symbols: &mut BTreeMap<String, String>,
    failure_symbols: &mut BTreeMap<String, String>,
) {
    for application in &ir.pattern_applications {
        pattern_symbols
            .entry(application.pattern.clone())
            .or_insert_with(|| maude_symbol("pat", &application.pattern));
        application_symbols
            .entry(application.alias.clone())
            .or_insert_with(|| maude_symbol("app", &application.alias));
        let rule_key = pattern_app_rule_key(&application.alias);
        rule_symbols
            .entry(rule_key.clone())
            .or_insert_with(|| maude_symbol("rule", &rule_key));
        let fact_key = pattern_app_fact_key(&application.alias);
        fact_symbols
            .entry(fact_key.clone())
            .or_insert_with(|| maude_symbol("fact", &fact_key));
        let graph_key = pattern_app_graph_key(&application.alias);
        graph_symbols
            .entry(graph_key.clone())
            .or_insert_with(|| maude_symbol("graph", &graph_key));
    }

    let has_workflow_terminal = ir.workflow_contracts.iter().any(|contract| {
        matches!(
            contract.kind,
            IrWorkflowContractKind::Output | IrWorkflowContractKind::Failure
        )
    });
    let has_invoke = ir.rules.iter().any(|rule| {
        rule.metadata
            .effects
            .iter()
            .any(|effect| effect.kind == IrEffectKind::WorkflowInvoke)
    });
    if has_workflow_terminal || has_invoke {
        workflow_symbols
            .entry(ir.workflow.clone())
            .or_insert_with(|| maude_symbol("wf", &ir.workflow));
        let instance_key = workflow_instance_key(&ir.workflow);
        instance_symbols
            .entry(instance_key.clone())
            .or_insert_with(|| maude_symbol("inst", &instance_key));
    }

    for contract in &ir.workflow_contracts {
        match contract.kind {
            IrWorkflowContractKind::Output => {
                output_symbols
                    .entry(contract.name.clone())
                    .or_insert_with(|| {
                        maude_symbol("out", &format!("{}:{}", ir.workflow, contract.name))
                    });
                let fact_key = complete_fact_key(&ir.workflow, &contract.name);
                fact_symbols
                    .entry(fact_key.clone())
                    .or_insert_with(|| maude_symbol("fact", &fact_key));
            }
            IrWorkflowContractKind::Failure => {
                failure_symbols
                    .entry(contract.name.clone())
                    .or_insert_with(|| {
                        maude_symbol("fail", &format!("{}:{}", ir.workflow, contract.name))
                    });
                let fact_key = fail_fact_key(&ir.workflow, &contract.name);
                fact_symbols
                    .entry(fact_key.clone())
                    .or_insert_with(|| maude_symbol("fact", &fact_key));
            }
            IrWorkflowContractKind::Input => {}
        }
    }

    for rule in &ir.rules {
        for effect in &rule.metadata.effects {
            if effect.kind != IrEffectKind::WorkflowInvoke {
                continue;
            }
            let child_key = invoke_child_instance_key(&rule.name, &effect.id);
            instance_symbols
                .entry(child_key.clone())
                .or_insert_with(|| maude_symbol("inst", &child_key));
            let workflow_key = invoke_target_workflow_key(&rule.name, &effect.id);
            workflow_symbols
                .entry(workflow_key.clone())
                .or_insert_with(|| maude_symbol("wf", &workflow_key));
            let payload_key = invoke_payload_fact_key(&rule.name, &effect.id);
            fact_symbols
                .entry(payload_key.clone())
                .or_insert_with(|| maude_symbol("fact", &payload_key));
        }
    }
}

/// Emit generated searches for the workflow composition kernel rules against
/// real compiled IR: pattern elaboration provenance, explicit workflow
/// completion/failure, and workflow invocation resolution.
#[allow(clippy::too_many_arguments)]
fn append_composition_model_searches(
    ir: &IrProgram,
    output: &mut String,
    expected: &mut Vec<ExpectedSearch>,
    rule_symbols: &BTreeMap<String, String>,
    fact_symbols: &BTreeMap<String, String>,
    graph_symbols: &BTreeMap<String, String>,
    effect_symbols: &BTreeMap<String, String>,
    pattern_symbols: &BTreeMap<String, String>,
    application_symbols: &BTreeMap<String, String>,
    workflow_symbols: &BTreeMap<String, String>,
    instance_symbols: &BTreeMap<String, String>,
    output_symbols: &BTreeMap<String, String>,
    failure_symbols: &BTreeMap<String, String>,
) {
    // Pattern applications elaborate into a provenance-tracked rule.
    for application in &ir.pattern_applications {
        let Some(pattern) = pattern_symbols.get(&application.pattern) else {
            continue;
        };
        let Some(app) = application_symbols.get(&application.alias) else {
            continue;
        };
        let Some(rule) = rule_symbols.get(&pattern_app_rule_key(&application.alias)) else {
            continue;
        };
        let Some(fact) = fact_symbols.get(&pattern_app_fact_key(&application.alias)) else {
            continue;
        };
        let Some(graph) = graph_symbols.get(&pattern_app_graph_key(&application.alias)) else {
            continue;
        };

        output.push_str(&format!(
            "--- pattern {}: applying `{}` elaborates into a provenance-tracked rule.\n",
            application.alias, application.pattern
        ));
        output.push_str(&format!(
            "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  patternApp({pattern}, {app}, {rule}, {fact}, {graph})\n  =>*\n  patternElaborated({pattern}, {app}, {rule}, {fact}, {graph}) rule({rule}, {fact}, {graph}) ruleProvenance({rule}, {pattern}, {app}) .\n\n"
        ));
        expected.push(ExpectedSearch {
            outcome: ExpectedSearchResult::Solution,
            span: SourceSpan { start: 0, end: 0 },
            description: format!("{} pattern application elaborates", application.alias),
            upstream: application.pattern.clone(),
            predicate: "pattern-elaborates",
            downstream: "ruleProvenance".to_owned(),
        });

        output.push_str(&format!(
            "--- pattern {}: rule provenance cannot appear without pattern elaboration.\n",
            application.alias
        ));
        output.push_str(&format!(
            "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  rule({rule}, {fact}, {graph})\n  =>*\n  ruleProvenance({rule}, {pattern}, {app}) RESIDUAL:Cfg .\n\n"
        ));
        expected.push(ExpectedSearch {
            outcome: ExpectedSearchResult::NoSolution,
            span: SourceSpan { start: 0, end: 0 },
            description: format!(
                "{} provenance requires pattern elaboration",
                application.alias
            ),
            upstream: application.pattern.clone(),
            predicate: "pattern-provenance-requires-elaboration",
            downstream: "ruleProvenance".to_owned(),
        });
    }

    // Explicit workflow completion and failure are terminal.
    let workflow = workflow_symbols.get(&ir.workflow);
    let instance = instance_symbols.get(&workflow_instance_key(&ir.workflow));
    if let (Some(workflow_symbol), Some(instance_symbol)) = (workflow, instance) {
        for contract in &ir.workflow_contracts {
            match contract.kind {
                IrWorkflowContractKind::Output => {
                    let Some(output_symbol) = output_symbols.get(&contract.name) else {
                        continue;
                    };
                    let Some(fact) =
                        fact_symbols.get(&complete_fact_key(&ir.workflow, &contract.name))
                    else {
                        continue;
                    };
                    output.push_str(&format!(
                        "--- {}: `complete {}` drives the instance to a completed terminal.\n",
                        ir.workflow, contract.name
                    ));
                    output.push_str(&format!(
                        "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  instance({instance_symbol}, {workflow_symbol}, instRunning) workflowOutput({workflow_symbol}, {output_symbol}) completeWorkflow({instance_symbol}, {output_symbol}, {fact}) fact({fact})\n  =>*\n  instance({instance_symbol}, {workflow_symbol}, instCompleted) workflowOutput({workflow_symbol}, {output_symbol}) terminalPayload({instance_symbol}, {fact}) fact({fact}) event(workflowCompletedEvt) .\n\n"
                    ));
                    expected.push(ExpectedSearch {
                        outcome: ExpectedSearchResult::Solution,
                        span: contract.span,
                        description: format!(
                            "{} complete {} reaches terminal",
                            ir.workflow, contract.name
                        ),
                        upstream: ir.workflow.clone(),
                        predicate: "workflow-complete",
                        downstream: "workflowCompletedEvt".to_owned(),
                    });

                    output.push_str(&format!(
                        "--- {}: completion event requires an explicit `complete {}` action.\n",
                        ir.workflow, contract.name
                    ));
                    output.push_str(&format!(
                        "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  instance({instance_symbol}, {workflow_symbol}, instRunning) workflowOutput({workflow_symbol}, {output_symbol}) fact({fact})\n  =>*\n  event(workflowCompletedEvt) RESIDUAL:Cfg .\n\n"
                    ));
                    expected.push(ExpectedSearch {
                        outcome: ExpectedSearchResult::NoSolution,
                        span: contract.span,
                        description: format!(
                            "{} completion requires explicit complete {}",
                            ir.workflow, contract.name
                        ),
                        upstream: ir.workflow.clone(),
                        predicate: "workflow-complete-requires-action",
                        downstream: "workflowCompletedEvt".to_owned(),
                    });
                }
                IrWorkflowContractKind::Failure => {
                    let Some(failure_symbol) = failure_symbols.get(&contract.name) else {
                        continue;
                    };
                    let Some(fact) = fact_symbols.get(&fail_fact_key(&ir.workflow, &contract.name))
                    else {
                        continue;
                    };
                    output.push_str(&format!(
                        "--- {}: `fail {}` drives the instance to a failed terminal.\n",
                        ir.workflow, contract.name
                    ));
                    output.push_str(&format!(
                        "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  instance({instance_symbol}, {workflow_symbol}, instRunning) workflowFailure({workflow_symbol}, {failure_symbol}) failWorkflow({instance_symbol}, {failure_symbol}, {fact}) fact({fact})\n  =>*\n  instance({instance_symbol}, {workflow_symbol}, instFailed) workflowFailure({workflow_symbol}, {failure_symbol}) terminalPayload({instance_symbol}, {fact}) fact({fact}) event(workflowFailedEvt) .\n\n"
                    ));
                    expected.push(ExpectedSearch {
                        outcome: ExpectedSearchResult::Solution,
                        span: contract.span,
                        description: format!(
                            "{} fail {} reaches terminal",
                            ir.workflow, contract.name
                        ),
                        upstream: ir.workflow.clone(),
                        predicate: "workflow-fail",
                        downstream: "workflowFailedEvt".to_owned(),
                    });

                    output.push_str(&format!(
                        "--- {}: failure event requires an explicit `fail {}` action.\n",
                        ir.workflow, contract.name
                    ));
                    output.push_str(&format!(
                        "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  instance({instance_symbol}, {workflow_symbol}, instRunning) workflowFailure({workflow_symbol}, {failure_symbol}) fact({fact})\n  =>*\n  event(workflowFailedEvt) RESIDUAL:Cfg .\n\n"
                    ));
                    expected.push(ExpectedSearch {
                        outcome: ExpectedSearchResult::NoSolution,
                        span: contract.span,
                        description: format!(
                            "{} failure requires explicit fail {}",
                            ir.workflow, contract.name
                        ),
                        upstream: ir.workflow.clone(),
                        predicate: "workflow-fail-requires-action",
                        downstream: "workflowFailedEvt".to_owned(),
                    });
                }
                IrWorkflowContractKind::Input => {}
            }
        }
    }

    // Workflow invocation is runtime composition behind an invocation effect.
    for rule in &ir.rules {
        for effect in &rule.metadata.effects {
            if effect.kind != IrEffectKind::WorkflowInvoke {
                continue;
            }
            let Some(effect_symbol) = effect_symbols.get(&effect_key(&rule.name, &effect.id))
            else {
                continue;
            };
            let Some(parent) = instance_symbols.get(&workflow_instance_key(&ir.workflow)) else {
                continue;
            };
            let Some(child) =
                instance_symbols.get(&invoke_child_instance_key(&rule.name, &effect.id))
            else {
                continue;
            };
            let Some(target) =
                workflow_symbols.get(&invoke_target_workflow_key(&rule.name, &effect.id))
            else {
                continue;
            };
            let Some(payload) = fact_symbols.get(&invoke_payload_fact_key(&rule.name, &effect.id))
            else {
                continue;
            };

            output.push_str(&format!(
                "--- {}: invoke `{}` starts a child instance behind the invocation effect.\n",
                rule.name, effect.id
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  effect({effect_symbol}, running) invokeWorkflow({effect_symbol}, {parent}, {target}, {child})\n  =>*\n  effect({effect_symbol}, running) instance({child}, {target}, instRunning) childOf({child}, {effect_symbol}) .\n\n"
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::Solution,
                span: effect.span,
                description: format!("{} invoke {} starts child instance", rule.name, effect.id),
                upstream: rule.name.clone(),
                predicate: "invoke-starts-child",
                downstream: "childOf".to_owned(),
            });

            output.push_str(&format!(
                "--- {}: invocation resolves to output only when the child completes.\n",
                rule.name
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  effect({effect_symbol}, running) childOf({child}, {effect_symbol}) instance({child}, {target}, instCompleted) terminalPayload({child}, {payload})\n  =>*\n  effect({effect_symbol}, completed) childOf({child}, {effect_symbol}) instance({child}, {target}, instCompleted) terminalPayload({child}, {payload}) invocationOutput({effect_symbol}, {payload}) .\n\n"
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::Solution,
                span: effect.span,
                description: format!(
                    "{} invoke {} resolves on child completion",
                    rule.name, effect.id
                ),
                upstream: rule.name.clone(),
                predicate: "invoke-completes",
                downstream: "invocationOutput".to_owned(),
            });

            output.push_str(&format!(
                "--- {}: invocation resolves to failure when the child fails.\n",
                rule.name
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  effect({effect_symbol}, running) childOf({child}, {effect_symbol}) instance({child}, {target}, instFailed) terminalPayload({child}, {payload})\n  =>*\n  effect({effect_symbol}, failed) childOf({child}, {effect_symbol}) instance({child}, {target}, instFailed) terminalPayload({child}, {payload}) invocationFailure({effect_symbol}, {payload}) .\n\n"
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::Solution,
                span: effect.span,
                description: format!(
                    "{} invoke {} resolves on child failure",
                    rule.name, effect.id
                ),
                upstream: rule.name.clone(),
                predicate: "invoke-fails",
                downstream: "invocationFailure".to_owned(),
            });

            output.push_str(&format!(
                "--- {}: invocation cannot resolve while the child is still running.\n",
                rule.name
            ));
            output.push_str(&format!(
                "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  effect({effect_symbol}, running) childOf({child}, {effect_symbol}) instance({child}, {target}, instRunning)\n  =>*\n  invocationOutput({effect_symbol}, {payload}) RESIDUAL:Cfg .\n\n"
            ));
            expected.push(ExpectedSearch {
                outcome: ExpectedSearchResult::NoSolution,
                span: effect.span,
                description: format!(
                    "{} invoke {} does not resolve before child terminal",
                    rule.name, effect.id
                ),
                upstream: rule.name.clone(),
                predicate: "invoke-blocks-until-terminal",
                downstream: "invocationOutput".to_owned(),
            });
        }
    }
}

#[allow(clippy::too_many_arguments)]
fn append_revision_model_searches(
    source: &str,
    output: &mut String,
    expected: &mut Vec<ExpectedSearch>,
    rule: &IrRule,
    rule_symbols: &BTreeMap<String, String>,
    fact_symbols: &BTreeMap<String, String>,
    graph_symbols: &BTreeMap<String, String>,
    effect_symbols: &BTreeMap<String, String>,
) {
    let Some(first_when) = rule.whens.first() else {
        return;
    };
    let Some(first_effect) = rule.metadata.effects.first() else {
        return;
    };
    let Some(rule_symbol) = rule_symbols.get(&rule.name) else {
        return;
    };
    let fact_key = rule_fact_key(&rule.name, 0, &first_when.pattern);
    let Some(fact_symbol) = fact_symbols.get(&fact_key) else {
        return;
    };
    let graph_key = rule_graph_key(&rule.name, 0);
    let Some(graph_symbol) = graph_symbols.get(&graph_key) else {
        return;
    };
    let first_effect_key = effect_key(&rule.name, &first_effect.id);
    let Some(effect_symbol) = effect_symbols.get(&first_effect_key) else {
        return;
    };

    output.push_str(&format!(
        "--- {}: revision-scoped rule commits after activation on the active revision.\n",
        rule.name
    ));
    output.push_str(&format!(
        "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  instance(rootInstance, rootWorkflow, instRunning) activeRevision(rootInstance, version1, epoch0) nextEpoch(epoch0, epoch1) activateRevision(rootInstance, version1, version2, epoch0, epoch1, keep) fact({fact_symbol}) scopedRuleV(rootInstance, version2, epoch1, {rule_symbol}, {fact_symbol}, {graph_symbol}) ruleReady({rule_symbol}, {fact_symbol}, {graph_symbol}) graphV({graph_symbol}, version2, epoch1, {effect_symbol})\n  =>*\n  instance(rootInstance, rootWorkflow, instRunning) activeRevision(rootInstance, version2, epoch1) nextEpoch(epoch0, epoch1) revisionActivated(rootInstance, version1, version2, epoch1, keep) revisionCancellationPolicy(rootInstance, version1, epoch0, keep) event(revisionActivatedEvt) fact({fact_symbol}) scopedRuleV(rootInstance, version2, epoch1, {rule_symbol}, {fact_symbol}, {graph_symbol}) scopedRuleFired(rootInstance, {rule_symbol}, {fact_symbol}, {graph_symbol}) event(ruleCommitEvt) graphCommitted({graph_symbol}) effect({effect_symbol}, queued) effectVersion({effect_symbol}, version2, epoch1) .\n\n"
    ));
    expected.push(ExpectedSearch {
        outcome: ExpectedSearchResult::Solution,
        span: first_when.span,
        description: format!("{} active revision scoped rule commits", rule.name),
        upstream: rule.name.clone(),
        predicate: "revision-active-rule",
        downstream: first_effect.id.clone(),
    });

    output.push_str(&format!(
        "--- {}: stale revision-scoped rule cannot commit after a newer revision is active.\n",
        rule.name
    ));
    output.push_str(&format!(
        "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  instance(rootInstance, rootWorkflow, instRunning) activeRevision(rootInstance, version2, epoch1) fact({fact_symbol}) scopedRuleV(rootInstance, version1, epoch0, {rule_symbol}, {fact_symbol}, {graph_symbol}) ruleReady({rule_symbol}, {fact_symbol}, {graph_symbol}) graphV({graph_symbol}, version1, epoch0, {effect_symbol})\n  =>*\n  instance(rootInstance, rootWorkflow, instRunning) activeRevision(rootInstance, version2, epoch1) fact({fact_symbol}) scopedRuleV(rootInstance, version1, epoch0, {rule_symbol}, {fact_symbol}, {graph_symbol}) scopedRuleFired(rootInstance, {rule_symbol}, {fact_symbol}, {graph_symbol}) event(ruleCommitEvt) graphCommitted({graph_symbol}) effect({effect_symbol}, queued) effectVersion({effect_symbol}, version1, epoch0) .\n\n"
    ));
    expected.push(ExpectedSearch {
        outcome: ExpectedSearchResult::NoSolution,
        span: first_when.span,
        description: format!("{} stale revision scoped rule cannot commit", rule.name),
        upstream: rule.name.clone(),
        predicate: "revision-stale-rule",
        downstream: first_effect.id.clone(),
    });

    output.push_str(&format!(
        "--- {}: revision activation does not rewrite old effect attribution.\n",
        rule.name
    ));
    output.push_str(&format!(
        "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  instance(rootInstance, rootWorkflow, instRunning) activeRevision(rootInstance, version1, epoch0) nextEpoch(epoch0, epoch1) activateRevision(rootInstance, version1, version2, epoch0, epoch1, keep) effect({effect_symbol}, queued) effectVersion({effect_symbol}, version1, epoch0)\n  =>*\n  instance(rootInstance, rootWorkflow, instRunning) activeRevision(rootInstance, version2, epoch1) nextEpoch(epoch0, epoch1) revisionActivated(rootInstance, version1, version2, epoch1, keep) revisionCancellationPolicy(rootInstance, version1, epoch0, keep) event(revisionActivatedEvt) effect({effect_symbol}, queued) effectVersion({effect_symbol}, version2, epoch1) .\n\n"
    ));
    expected.push(ExpectedSearch {
        outcome: ExpectedSearchResult::NoSolution,
        span: first_effect.span,
        description: format!("{} old effect keeps revision attribution", first_effect.id),
        upstream: first_effect.id.clone(),
        predicate: "revision-effect-attribution",
        downstream: "effectVersion".to_owned(),
    });

    for dependency in &rule.metadata.dependencies {
        if !matches!(&dependency.predicate, IrDependencyPredicate::Completes) {
            continue;
        }
        let upstream_key = effect_key(&rule.name, &dependency.upstream);
        let downstream_key = effect_key(&rule.name, &dependency.downstream);
        let Some(upstream) = effect_symbols.get(&upstream_key) else {
            continue;
        };
        let Some(downstream) = effect_symbols.get(&downstream_key) else {
            continue;
        };
        let span = dependency_source_span(source, &dependency.upstream, "completes");
        output.push_str(&format!(
            "--- {}: revision-cancelled upstream releases `completes` dependencies.\n",
            rule.name
        ));
        output.push_str(&format!(
            "search [1] in WHIPPLESCRIPT-GENERATED-CHECK :\n  instance(rootInstance, rootWorkflow, instRunning) activeRevision(rootInstance, version1, epoch0) nextEpoch(epoch0, epoch1) activateRevision(rootInstance, version1, version2, epoch0, epoch1, cancelQueued) effect({upstream}, queued) effectVersion({upstream}, version1, epoch0) dep({upstream}, completes, {downstream}) effect({downstream}, blocked) effectVersion({downstream}, version1, epoch0)\n  =>*\n  instance(rootInstance, rootWorkflow, instRunning) activeRevision(rootInstance, version2, epoch1) nextEpoch(epoch0, epoch1) revisionActivated(rootInstance, version1, version2, epoch1, cancelQueued) revisionCancellationPolicy(rootInstance, version1, epoch0, cancelQueued) event(revisionActivatedEvt) effect({upstream}, cancelled) effectVersion({upstream}, version1, epoch0) dep({upstream}, completes, {downstream}) effect({downstream}, queued) effectVersion({downstream}, version1, epoch0) .\n\n"
        ));
        expected.push(ExpectedSearch {
            outcome: ExpectedSearchResult::Solution,
            span,
            description: format!(
                "{} --completes--> {} releases after revision cancellation",
                dependency.upstream, dependency.downstream
            ),
            upstream: dependency.upstream.clone(),
            predicate: "revision-completes-cancelled",
            downstream: dependency.downstream.clone(),
        });
    }
}

fn maude_bool_cases(expr: &Expr, context: &mut MaudeExprContext) -> MaudeBoolCases {
    match expr {
        Expr::Literal(ExprLiteral::Bool(true)) => MaudeBoolCases {
            true_expr: "boolTrue".to_owned(),
            false_expr: "boolFalse".to_owned(),
            error_expr: "exprError".to_owned(),
        },
        Expr::Literal(ExprLiteral::Bool(false)) => MaudeBoolCases {
            true_expr: "boolTrue".to_owned(),
            false_expr: "boolFalse".to_owned(),
            error_expr: "exprError".to_owned(),
        },
        Expr::Unary {
            op: UnaryOp::Not,
            expr,
        } => {
            let inner = maude_bool_cases(expr, context);
            MaudeBoolCases {
                true_expr: format!("notExpr({})", inner.false_expr),
                false_expr: format!("notExpr({})", inner.true_expr),
                error_expr: format!("notExpr({})", inner.error_expr),
            }
        }
        Expr::Binary {
            op: BinaryOp::And,
            left,
            right,
        } => {
            let left = maude_bool_cases(left, context);
            let right = maude_bool_cases(right, context);
            MaudeBoolCases {
                true_expr: format!("andExpr({}, {})", left.true_expr, right.true_expr),
                false_expr: format!("andExpr({}, {})", left.false_expr, right.true_expr),
                error_expr: format!("andExpr({}, {})", left.error_expr, right.true_expr),
            }
        }
        Expr::Binary {
            op: BinaryOp::Or,
            left,
            right,
        } => {
            let left = maude_bool_cases(left, context);
            let right = maude_bool_cases(right, context);
            MaudeBoolCases {
                true_expr: format!("orExpr({}, {})", left.true_expr, right.false_expr),
                false_expr: format!("orExpr({}, {})", left.false_expr, right.false_expr),
                error_expr: format!("orExpr({}, {})", left.error_expr, right.false_expr),
            }
        }
        Expr::Binary {
            op: BinaryOp::Eq,
            left,
            right,
        } => MaudeBoolCases {
            true_expr: maude_eq_true_expr(left, right, context),
            false_expr: maude_eq_false_expr(left, right, context),
            error_expr: "exprError".to_owned(),
        },
        Expr::Binary {
            op: BinaryOp::Ne,
            left,
            right,
        } => MaudeBoolCases {
            true_expr: format!("notExpr({})", maude_eq_false_expr(left, right, context)),
            false_expr: format!(
                "neExpr({}, {})",
                maude_scalar_expr(left, context),
                maude_scalar_expr(right, context)
            ),
            error_expr: "exprError".to_owned(),
        },
        Expr::Binary {
            op: BinaryOp::Lt,
            left,
            right,
        } => maude_order_bool_cases("ltExpr", left, right, context),
        Expr::Binary {
            op: BinaryOp::Le,
            left,
            right,
        } => maude_order_bool_cases("leExpr", left, right, context),
        Expr::Binary {
            op: BinaryOp::Gt,
            left,
            right,
        } => maude_order_bool_cases("gtExpr", left, right, context),
        Expr::Binary {
            op: BinaryOp::Ge,
            left,
            right,
        } => maude_order_bool_cases("geExpr", left, right, context),
        Expr::Binary {
            op: BinaryOp::In,
            left,
            right,
        } => maude_membership_bool_cases(left, right, false, context),
        Expr::Binary {
            op: BinaryOp::NotIn,
            left,
            right,
        } => maude_membership_bool_cases(left, right, true, context),
        Expr::Call { name, args } if name == "exists" && args.len() == 1 => {
            let collection = maude_collection_expr(&args[0], "qOne", context);
            MaudeBoolCases {
                true_expr: format!("existsExpr({collection})"),
                false_expr: format!(
                    "existsExpr({})",
                    maude_collection_expr(&args[0], "qZero", context)
                ),
                error_expr: format!(
                    "existsExpr({})",
                    maude_collection_expr(&args[0], "qError", context)
                ),
            }
        }
        _ => MaudeBoolCases {
            true_expr: "boolTrue".to_owned(),
            false_expr: "boolFalse".to_owned(),
            error_expr: "exprError".to_owned(),
        },
    }
}

fn maude_order_bool_cases(
    op: &str,
    left: &Expr,
    right: &Expr,
    context: &mut MaudeExprContext,
) -> MaudeBoolCases {
    if let Some((count_expr, literal_expr)) = maude_count_number_pair(left, right, true, context) {
        return MaudeBoolCases {
            true_expr: format!("{op}({count_expr}, {literal_expr})"),
            false_expr: maude_false_order_expr(op),
            error_expr: format!("{op}(exprError, {literal_expr})"),
        };
    }
    if let Some((literal_expr, count_expr)) = maude_count_number_pair(right, left, true, context) {
        return MaudeBoolCases {
            true_expr: format!("{op}({literal_expr}, {count_expr})"),
            false_expr: maude_false_order_expr(op),
            error_expr: format!("{op}({literal_expr}, exprError)"),
        };
    }
    let _ = maude_scalar_expr(left, context);
    let _ = maude_scalar_expr(right, context);
    MaudeBoolCases {
        true_expr: maude_true_order_expr(op),
        false_expr: maude_false_order_expr(op),
        error_expr: format!("{op}(exprError, orderHigh)"),
    }
}

fn maude_true_order_expr(op: &str) -> String {
    let (left, right) = match op {
        "ltExpr" | "leExpr" => ("orderLow", "orderHigh"),
        "gtExpr" | "geExpr" => ("orderHigh", "orderLow"),
        _ => ("orderLow", "orderHigh"),
    };
    format!("{op}({left}, {right})")
}

fn maude_false_order_expr(op: &str) -> String {
    let (left, right) = match op {
        "ltExpr" | "leExpr" => ("orderHigh", "orderLow"),
        "gtExpr" | "geExpr" => ("orderLow", "orderHigh"),
        _ => ("orderHigh", "orderLow"),
    };
    format!("{op}({left}, {right})")
}

fn maude_membership_bool_cases(
    item: &Expr,
    collection: &Expr,
    negated: bool,
    context: &mut MaudeExprContext,
) -> MaudeBoolCases {
    let item_expr = maude_scalar_expr(item, context);
    let present_collection = maude_collection_with_member(collection, &item_expr, true, context);
    let missing_collection = maude_collection_with_member(collection, &item_expr, false, context);
    let true_expr = format!("inExpr({item_expr}, {present_collection})");
    let false_expr = format!("inExpr({item_expr}, {missing_collection})");
    let error_expr = format!("inExpr(exprError, {present_collection})");
    if negated {
        MaudeBoolCases {
            true_expr: format!("notExpr({false_expr})"),
            false_expr: format!("notExpr({true_expr})"),
            error_expr,
        }
    } else {
        MaudeBoolCases {
            true_expr,
            false_expr,
            error_expr,
        }
    }
}

fn maude_eq_true_expr(left: &Expr, right: &Expr, context: &mut MaudeExprContext) -> String {
    let pair = maude_equal_pair(left, right, true, context);
    format!("eqExpr({}, {})", pair.0, pair.1)
}

fn maude_eq_false_expr(left: &Expr, right: &Expr, context: &mut MaudeExprContext) -> String {
    if let Some((query_expr, number_expr)) = maude_count_number_pair(left, right, false, context) {
        return format!("eqExpr({query_expr}, {number_expr})");
    }
    if let Some((number_expr, query_expr)) = maude_count_number_pair(right, left, false, context) {
        return format!("eqExpr({number_expr}, {query_expr})");
    }
    let lhs = maude_scalar_expr(left, context);
    format!("notExpr(eqExpr({lhs}, {lhs}))")
}

fn maude_equal_pair(
    left: &Expr,
    right: &Expr,
    equal: bool,
    context: &mut MaudeExprContext,
) -> (String, String) {
    if let Some((query_expr, number_expr)) = maude_count_number_pair(left, right, equal, context) {
        return (query_expr, number_expr);
    }
    if let Some((number_expr, query_expr)) = maude_count_number_pair(right, left, equal, context) {
        return (number_expr, query_expr);
    }

    let lhs = maude_scalar_expr(left, context);
    if equal {
        return (lhs.clone(), lhs);
    }
    (lhs.clone(), lhs)
}

fn maude_count_number_pair(
    maybe_count: &Expr,
    maybe_number: &Expr,
    equal: bool,
    context: &mut MaudeExprContext,
) -> Option<(String, String)> {
    let Expr::Call { name, args } = maybe_count else {
        return None;
    };
    if name != "count" || args.len() != 1 {
        return None;
    }
    let Expr::Literal(ExprLiteral::Number(number)) = maybe_number else {
        return None;
    };
    let expected = maude_count_literal(number)?;
    let cardinality = if equal {
        maude_query_cardinality_for_count(number)
    } else if number == "0" {
        "qOne"
    } else {
        "qZero"
    };
    let count = format!(
        "countExpr({})",
        maude_collection_expr(&args[0], cardinality, context)
    );
    Some((count, expected))
}

fn maude_count_literal(number: &str) -> Option<String> {
    match number {
        "0" => Some("countZero".to_owned()),
        "1" => Some("countOne".to_owned()),
        "2" => Some("countTwo".to_owned()),
        "3" => Some("countThree".to_owned()),
        _ => number
            .parse::<i64>()
            .ok()
            .filter(|value| *value > 3)
            .map(|_| "countMany".to_owned()),
    }
}

fn maude_query_cardinality_for_count(number: &str) -> &'static str {
    match number {
        "0" => "qZero",
        "1" => "qOne",
        "2" => "qTwo",
        "3" => "qThree",
        _ => "qMany",
    }
}

fn maude_scalar_expr(expr: &Expr, context: &mut MaudeExprContext) -> String {
    match expr {
        Expr::Literal(ExprLiteral::Bool(true)) => "boolTrue".to_owned(),
        Expr::Literal(ExprLiteral::Bool(false)) => "boolFalse".to_owned(),
        Expr::Literal(ExprLiteral::Number(number)) => {
            maude_count_literal(number).unwrap_or_else(|| maude_scalar_symbol(expr, context))
        }
        Expr::Index { target, key } => {
            let key = maude_scalar_expr(key, context);
            let target = maude_index_target_expr(target, &key, expr, context);
            format!("indexExpr({target}, {key})")
        }
        Expr::Array(_) | Expr::Object(_) => maude_value_expr(expr, context),
        Expr::Call { name, args } if name == "count" && args.len() == 1 => {
            format!(
                "countExpr({})",
                maude_collection_expr(&args[0], "qOne", context)
            )
        }
        _ => format!("scalar({})", maude_scalar_symbol(expr, context)),
    }
}

fn maude_value_expr(expr: &Expr, context: &mut MaudeExprContext) -> String {
    match expr {
        Expr::Array(items) => maude_array_literal_expr(items, context),
        Expr::Object(fields) => maude_object_literal_expr(fields, context),
        Expr::Index { target, key } => {
            let key = maude_scalar_expr(key, context);
            let target = maude_index_target_expr(target, &key, expr, context);
            format!("indexExpr({target}, {key})")
        }
        Expr::Query { .. } => maude_collection_expr(expr, "qOne", context),
        _ => maude_scalar_expr(expr, context),
    }
}

fn maude_array_literal_expr(items: &[Expr], context: &mut MaudeExprContext) -> String {
    if items.is_empty() {
        return "arrayEmpty".to_owned();
    }
    format!("arrayOf({})", maude_expr_list(items, context))
}

fn maude_object_literal_expr(fields: &[ExprObjectField], context: &mut MaudeExprContext) -> String {
    if fields.is_empty() {
        return "objectEmpty".to_owned();
    }
    format!("objectOf({})", maude_entry_list(fields, context))
}

fn maude_expr_list(items: &[Expr], context: &mut MaudeExprContext) -> String {
    let Some((first, rest)) = items.split_first() else {
        return "exprNil".to_owned();
    };
    format!(
        "exprCons({}, {})",
        maude_scalar_expr(first, context),
        maude_expr_list(rest, context)
    )
}

fn maude_entry_list(fields: &[ExprObjectField], context: &mut MaudeExprContext) -> String {
    let Some((first, rest)) = fields.split_first() else {
        return "entryNil".to_owned();
    };
    format!(
        "entryCons(entry({}, {}), {})",
        maude_field_key_expr(&first.key, context),
        maude_scalar_expr(&first.value, context),
        maude_entry_list(rest, context)
    )
}

fn maude_collection_expr(
    expr: &Expr,
    cardinality: &'static str,
    context: &mut MaudeExprContext,
) -> String {
    match expr {
        Expr::Query { guard, .. } => {
            let query = maude_query_symbol(expr, context);
            if let Some(guard) = guard {
                let guard_cases = maude_bool_cases(guard, context);
                format!(
                    "queryFilter({query}, {}, {cardinality})",
                    guard_cases.true_expr
                )
            } else {
                format!("query({query}, {cardinality})")
            }
        }
        Expr::Array(items) => {
            let _ = cardinality;
            maude_array_literal_expr(items, context)
        }
        Expr::Object(fields) => {
            let _ = cardinality;
            maude_object_literal_expr(fields, context)
        }
        Expr::Index { .. } => maude_value_expr(expr, context),
        _ => format!(
            "query({}, {cardinality})",
            maude_query_symbol(expr, context)
        ),
    }
}

fn maude_collection_with_member(
    collection: &Expr,
    item_expr: &str,
    present: bool,
    context: &mut MaudeExprContext,
) -> String {
    match collection {
        Expr::Array(_) => {
            if present {
                format!("arrayHas({item_expr})")
            } else {
                format!("arrayMissing({item_expr})")
            }
        }
        Expr::Object(_) => {
            if present {
                format!(
                    "objectHas({item_expr}, scalar({}))",
                    maude_scalar_symbol(collection, context)
                )
            } else {
                format!("objectMissing({item_expr})")
            }
        }
        Expr::Path(_) | Expr::Index { .. } => {
            if present {
                format!(
                    "mapHas({item_expr}, scalar({}))",
                    maude_scalar_symbol(collection, context)
                )
            } else {
                format!("mapMissing({item_expr})")
            }
        }
        _ => {
            if present {
                format!("arrayHas({item_expr})")
            } else {
                format!("arrayMissing({item_expr})")
            }
        }
    }
}

fn maude_index_target_expr(
    target: &Expr,
    key_expr: &str,
    index_expr: &Expr,
    context: &mut MaudeExprContext,
) -> String {
    match target {
        Expr::Object(fields) => {
            let _ = key_expr;
            maude_object_literal_expr(fields, context)
        }
        Expr::Index { .. } => maude_value_expr(target, context),
        _ => format!(
            "mapHas({key_expr}, scalar({}))",
            maude_scalar_symbol(index_expr, context)
        ),
    }
}

fn maude_field_key_expr(key: &str, context: &mut MaudeExprContext) -> String {
    let expr = Expr::Literal(ExprLiteral::String(key.to_owned()));
    maude_scalar_expr(&expr, context)
}

fn maude_scalar_symbol(expr: &Expr, context: &mut MaudeExprContext) -> String {
    let key = expr.to_snapshot();
    context
        .scalar_symbols
        .entry(key.clone())
        .or_insert_with(|| maude_symbol("scalar", &key))
        .clone()
}

fn maude_query_symbol(expr: &Expr, context: &mut MaudeExprContext) -> String {
    let key = expr.to_snapshot();
    context
        .query_symbols
        .entry(key.clone())
        .or_insert_with(|| maude_symbol("query", &key))
        .clone()
}

fn append_maude_ops<'a>(
    output: &mut String,
    symbols: impl IntoIterator<Item = &'a String>,
    sort: &str,
) {
    let symbols = symbols.into_iter().collect::<Vec<_>>();
    if symbols.is_empty() {
        return;
    }
    output.push_str("  ops\n");
    for symbol in symbols {
        output.push_str("    ");
        output.push_str(symbol);
        output.push('\n');
    }
    output.push_str(&format!("    : -> {sort} .\n"));
}

fn extract_maude_search_results(output: &str) -> Vec<ExpectedSearchResult> {
    let mut matches = Vec::new();
    for (index, _) in output.match_indices("Solution 1") {
        matches.push((index, ExpectedSearchResult::Solution));
    }
    for (index, _) in output.match_indices("No solution.") {
        matches.push((index, ExpectedSearchResult::NoSolution));
    }
    matches.sort_by_key(|(index, _)| *index);
    matches.into_iter().map(|(_, result)| result).collect()
}

fn format_model_search_error(
    path: &str,
    source: &str,
    diagnostic: Option<&Diagnostic>,
    details: &str,
) -> String {
    let mut rendered = String::new();
    if let Some(diagnostic) = diagnostic {
        rendered.push_str(&render_diagnostic(path, source, diagnostic));
    }
    rendered.push_str(details);
    rendered
}

fn dependency_source_span(source: &str, upstream: &str, predicate: &str) -> SourceSpan {
    let pattern = format!("after {upstream} {predicate}");
    source
        .find(&pattern)
        .map(|start| SourceSpan {
            start,
            end: start + pattern.len(),
        })
        .unwrap_or(SourceSpan { start: 0, end: 0 })
}

fn effect_key(rule_name: &str, effect_id: &str) -> String {
    format!("{rule_name}:{effect_id}")
}

fn rule_fact_key(rule_name: &str, when_index: usize, pattern: &str) -> String {
    format!("{rule_name}:when{when_index}:{pattern}")
}

fn rule_graph_key(rule_name: &str, when_index: usize) -> String {
    format!("{rule_name}:when{when_index}:graph")
}

fn terminal_branch_graph_key(
    rule_name: &str,
    branch: &whipplescript_parser::IrTerminalCaseBranch,
) -> String {
    let tag = branch.tag.as_deref().unwrap_or("_");
    format!("{rule_name}:terminal:{tag}:{}", branch.body_hash)
}

fn assertion_key(index: usize, assertion: &whipplescript_parser::IrAssertion) -> String {
    format!("{index}:{}", assertion.expr.source)
}

fn maude_symbol(prefix: &str, value: &str) -> String {
    format!("{prefix}{:016x}", stable_hash(value))
}

fn maude_predicate(predicate: &whipplescript_parser::DependencyPredicate) -> &'static str {
    match predicate {
        whipplescript_parser::DependencyPredicate::Succeeds => "succeeds",
        whipplescript_parser::DependencyPredicate::Fails => "fails",
        whipplescript_parser::DependencyPredicate::TimedOut => "timed_out",
        whipplescript_parser::DependencyPredicate::Cancelled => "cancelled",
        whipplescript_parser::DependencyPredicate::Completes => "completes",
    }
}

fn maude_terminal_tag(tag: &str) -> &'static str {
    match tag {
        "Completed" => "terminalCompleted",
        "Failed" => "terminalFailed",
        "TimedOut" => "terminalTimedOut",
        "Cancelled" => "terminalCancelled",
        _ => "terminalCompleted",
    }
}

fn maude_terminal_miss_tag(tag: &str) -> &'static str {
    match tag {
        "Completed" => "terminalFailed",
        "Failed" => "terminalCompleted",
        "TimedOut" => "terminalCompleted",
        "Cancelled" => "terminalCompleted",
        _ => "terminalFailed",
    }
}

fn satisfying_terminal(predicate: &whipplescript_parser::DependencyPredicate) -> &'static str {
    match predicate {
        whipplescript_parser::DependencyPredicate::Succeeds => "completed",
        whipplescript_parser::DependencyPredicate::Fails => "failed",
        whipplescript_parser::DependencyPredicate::TimedOut => "timed_out",
        whipplescript_parser::DependencyPredicate::Cancelled => "cancelled",
        whipplescript_parser::DependencyPredicate::Completes => "completed",
    }
}

fn non_satisfying_terminal(
    predicate: &whipplescript_parser::DependencyPredicate,
) -> Option<&'static str> {
    match predicate {
        whipplescript_parser::DependencyPredicate::Succeeds => Some("failed"),
        whipplescript_parser::DependencyPredicate::Fails => Some("completed"),
        whipplescript_parser::DependencyPredicate::TimedOut => Some("completed"),
        whipplescript_parser::DependencyPredicate::Cancelled => Some("completed"),
        whipplescript_parser::DependencyPredicate::Completes => None,
    }
}

fn report_compile_failure(path: &str, error: CompileFailure) -> ExitCode {
    match error {
        CompileFailure::Io(error) => {
            eprintln!("{path}: failed to read: {error}");
        }
        CompileFailure::Diagnostics {
            source,
            segments,
            diagnostics,
        } => {
            for diagnostic in diagnostics {
                eprint!(
                    "{}",
                    render_bundle_diagnostic(path, &source, &segments, &diagnostic, "error")
                );
            }
        }
    }
    ExitCode::FAILURE
}

fn report_store_error(context: &str, error: StoreError) -> ExitCode {
    eprintln!("{context}: {}", store_error(error));
    ExitCode::FAILURE
}

fn store_error(error: StoreError) -> String {
    match error {
        StoreError::Io(error) => format!("store I/O error: {error}"),
        StoreError::Sqlite(error) => {
            format!("internal store error ({error}); this is a whip bug, please report it")
        }
        StoreError::Json(error) => format!(
            "internal store error (malformed stored JSON: {error}); this is a whip bug, please report it"
        ),
        StoreError::Conflict(message) => message,
        StoreError::PolicyBlocked { reason, .. } => reason,
        StoreError::CapacityBlocked { reason, .. } => reason,
    }
}

fn emit_json(value: Value) -> ExitCode {
    match serde_json::to_string_pretty(&value) {
        Ok(rendered) => {
            println!("{rendered}");
            ExitCode::SUCCESS
        }
        Err(error) => {
            eprintln!("failed to render JSON: {error}");
            ExitCode::FAILURE
        }
    }
}

