fn redact_cli_metadata(value: &str) -> String {
    value
        .split_whitespace()
        .map(|token| {
            if token_has_secret_pattern(token) {
                "[REDACTED]".to_owned()
            } else if let Some((key, _)) = token.split_once('=') {
                if key_is_sensitive(key) {
                    format!("{key}=[REDACTED]")
                } else {
                    token.to_owned()
                }
            } else {
                token.to_owned()
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}

fn key_is_sensitive(key: &str) -> bool {
    let key = key.to_ascii_lowercase();
    [
        "authorization",
        "api_key",
        "apikey",
        "credential",
        "password",
        "secret",
        "token",
    ]
    .iter()
    .any(|needle| key.contains(needle))
}

fn token_has_secret_pattern(token: &str) -> bool {
    let token = token.trim_matches(|ch: char| {
        matches!(ch, '"' | '\'' | ',' | ';' | ':' | ')' | '(' | '[' | ']')
    });
    token.contains("github_pat_")
        || token
            .find("sk-")
            .is_some_and(|start| token[start..].len() >= 20)
        || token
            .find("ghp_")
            .is_some_and(|start| token[start..].len() >= 20)
        || token
            .find("AKIA")
            .is_some_and(|start| token[start..].len() >= 20)
}

